                                            </div>

                                            <div className={styles.actions}>
                                                <Link href={`/contact?subject=Order Help: ${order.id}`} className={styles.contactBtn} title="Contact Support">
                                                    <Mail size={16} />
                                                </Link>
                                                <Link href={`/tracking?id=${order.id}`} className={styles.trackBtn}>
                                                    Details <ChevronRight size={14} />
                                                </Link>
                                                <button className={styles.deleteOrderBtn} onClick={() => setDeletingId(order.id)} title="Delete Order">
                                                    <Trash2 size={18} />
                                                </button>
                                            </div>

                                            {deletingId === order.id && (
                                                <div style={{
                                                    gridColumn: '1 / -1',
                                                    background: 'rgba(255,0,85,0.08)',
                                                    border: '1px solid rgba(255,0,85,0.2)',
                                                    padding: '12px 16px',
                                                    borderRadius: '10px',
                                                    display: 'flex',
                                                    alignItems: 'center',
                                                    justifyContent: 'space-between',
                                                    marginTop: '8px',
                                                    animation: 'fadeIn 0.2s ease'
                                                }}>
                                                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#ff0055', fontSize: '0.85rem', fontWeight: 600 }}>
                                                        <AlertTriangle size={16} /> Remove order history?
                                                    </div>
                                                    <div style={{ display: 'flex', gap: '8px' }}>
                                                        <button onClick={() => setDeletingId(null)} style={{ background: 'rgba(255,255,255,0.1)', border: 'none', color: 'white', padding: '4px 12px', borderRadius: '6px', fontSize: '0.75rem', cursor: 'pointer' }}>Cancel</button>
                                                        <button onClick={() => handleDeleteOrder(order.id)} style={{ background: '#ff0055', border: 'none', color: 'white', padding: '4px 12px', borderRadius: '6px', fontSize: '0.75rem', fontWeight: 700, cursor: 'pointer' }}>Delete</button>
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    ))}
                            </div>
                        </div>
                    </div>
                )
            }


        </div >
    )
}

'use client'
import { useState, useEffect, useMemo } from 'react'
import { useRouter, useParams } from 'next/navigation'
import { createClient } from '@/utils/supabase/client'
import { formatCurrency } from '@/utils/pricingEngine'
import { ArrowLeft, Upload, QrCode, CheckCircle, Loader2 } from 'lucide-react'
import styles from '../Payment.module.css'
import { useToastStore } from '@/store/toastStore'
import Image from 'next/image'
import { submitPaymentProof } from '../actions'
import BackButton from '@/components/BackButton'
import Loader from '@/components/Loader'

export default function PaymentPage() {
    const { id } = useParams()
    const router = useRouter()
    const supabase = createClient()
    const [order, setOrder] = useState<any>(null)
    const [loading, setLoading] = useState(true)
    const [isSubmitting, setIsSubmitting] = useState(false)
    const [screenshot, setScreenshot] = useState<File | null>(null)
    const [preview, setPreview] = useState<string | null>(null)
    const [qrError, setQrError] = useState(false)
    const addToast = useToastStore.getState().addToast

    const qrUrl = useMemo(() => {
        // Cache-busting with a version number that only changes when we explicitly want it
        return `${supabase.storage.from('prints').getPublicUrl('payments/payment-qr.png').data.publicUrl}?v=1`
    }, [supabase])

    useEffect(() => {
        const fetchOrder = async () => {
            try {
                const { data: { user }, error: authError } = await supabase.auth.getUser()
                if (authError || !user) {
                    router.push('/login')
                    return
                }

                const { data, error } = await supabase
                    .from('orders')
                    .select('*')
                    .eq('id', id)
                    .single()

                if (error) throw error

                if (data) {
                    setOrder(data)
                } else {
                    throw new Error('Order not found')
                }
            } catch (err: any) {
                addToast(err.message || 'Failed to load order', 'error')
                router.push('/orders')
            } finally {
                setLoading(false)
            }
        }
        fetchOrder()
    }, [id, router, supabase, addToast])

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (file) {
            setScreenshot(file)
            const reader = new FileReader()
            reader.onloadend = () => {
                setPreview(reader.result as string)
            }
            reader.readAsDataURL(file)
        }
    }

    const handleSubmit = async () => {
        if (!screenshot) {
            addToast('Please upload a screenshot first', 'error')
            return
        }
        setIsSubmitting(true)

        try {
            // 1. Upload screenshot to storage
            const fileExt = screenshot.name.split('.').pop()
            const fileName = `${order.id}-payment-proof.${fileExt}`
            const filePath = `payments/${fileName}`

            const { error: uploadError } = await supabase.storage
                .from('prints')
                .upload(filePath, screenshot, { upsert: true })

            if (uploadError) throw uploadError

            // 2. Update order status via Server Action for reliability and cache revalidation
            const result = await submitPaymentProof(order.id as string)

            if (result.error) throw new Error(result.error)

            addToast('Payment proof submitted successfully!', 'success')

            router.refresh()

            // Give the DB a split second to breathe and ensure revalidation is picked up
            setTimeout(() => {
                router.push('/orders')
            }, 800)
        } catch (error: any) {
            addToast(error.message || 'Failed to submit payment proof', 'error')
        } finally {
            setIsSubmitting(false)
        }
    }

    if (loading) return <Loader text="Securing order details..." />

    if (!order) return null

    return (
        <div className={styles.container}>
            <div className={styles.pageHeader}>
                <div className={styles.headerLeft}>
                    <BackButton fallback="/orders" />
                </div>
                <div className={styles.headerContent}>
                    <h1 className="title-gradient">Payment required</h1>
                    <p className={styles.subtitle}>Scan and upload proof to confirm your print order</p>
                </div>
                <div className={styles.headerRight} />
            </div>

            <div className={`${styles.paymentCard} glass`}>
                <div className={styles.header}>
                    <p className={styles.instructions}>Scan the QR code below using any UPI app (GPay, PhonePe, Paytm) to pay for your order.</p>
                </div>

                <div className={styles.amount}>
                    {formatCurrency(order.total_amount)}
                    <span style={{ fontSize: '1.2rem', opacity: 0.5, marginLeft: '12px', verticalAlign: 'middle', fontWeight: 500 }}>
                        + shipping (Discuss with Admin)
                    </span>
                </div>

                <div className={styles.qrSection}>
                    <div className={styles.qrPlaceholder}>
                        {qrError ? (
                            <div style={{ color: '#333', textAlign: 'center', padding: '20px' }}>
                                QR Code currently unavailable.<br />Please contact support.
                            </div>
                        ) : (
                            <img
                                src={qrUrl}
                                alt="Payment QR Code"
                                style={{ width: '200px', height: '200px', objectFit: 'contain' }}
                                onError={() => setQrError(true)}
                            />
                        )}
                    </div>
                    <span style={{ fontSize: '0.8rem', marginTop: '12px', display: 'block' }}>UPI ID: printhub@okaxis</span>
                </div>

                <div className={styles.instructions}>
                    <p>1. Scan the QR code and pay <strong>{formatCurrency(order.total_amount)}</strong> + Shipping</p>
                    <p>2. Take a screenshot of the successful payment</p>
                    <p>3. Upload the screenshot below to confirm your order</p>
                </div>

                <div className={styles.uploadSection}>
                    <Upload className={styles.uploadIcon} size={32} />
                    <p>{screenshot ? screenshot.name : 'Click or drag to upload payment screenshot'}</p>
                    <input
                        type="file"
                        accept="image/*"
                        className={styles.fileInput}
                        onChange={handleFileChange}
                    />
                    {preview && (
                        <img src={preview} alt="Screenshot Preview" className={styles.preview} />
                    )}
                </div>

                <button
                    className={styles.submitBtn}
                    onClick={handleSubmit}
                    disabled={!screenshot || isSubmitting}
                >
                    {isSubmitting ? (
                        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                            <Loader2 className="spin" size={20} /> Submitting...
                        </div>
                    ) : (
                        'Submit Payment Proof'
                    )}
                </button>
            </div>
        </div>
    )
}

'use server'

import { createClient } from '@/utils/supabase/server'
import { revalidatePath } from 'next/cache'

export async function submitPaymentProof(orderId: string) {
    console.log('Server Action: Submitting payment proof for order:', orderId)

    try {
        const supabase = await createClient()

        const { error } = await supabase
            .from('orders')
            .update({ status: 'pending_confirmation' })
            .eq('id', orderId)

        if (error) {
            console.error('Database update error:', error)
            return { error: error.message }
        }

        console.log('Order status updated successfully to pending_confirmation')

        return { success: true }
    } catch (err: any) {
        console.error('Server Action Crash:', err)
        return { error: 'Internal Server Error: ' + err.message }
    }
}

'use client'
import { useRouter } from 'next/navigation'
import { useEffect, useState } from 'react'
import styles from './Settings.module.css'
import { User, MapPin, Plus, Trash2, Settings as SettingsIcon, Bell, Moon, Shield, Zap, DollarSign, Activity } from 'lucide-react'
import BackButton from '@/components/BackButton'
import { createClient } from '@/utils/supabase/client'
import { User as SupabaseUser } from '@supabase/supabase-js'
import { useToastStore } from '@/store/toastStore'
import { useAdminStore } from '@/store/adminStore'
import Loader from '@/components/Loader'

interface Address {
    id: string
    full_name: string
    address_line1: string
    city: string
    zip_code: string
    phone: string
}

export default function SettingsPage() {
    const router = useRouter()
    const supabase = createClient()
    const addToast = useToastStore((state) => state.addToast)
    const {
        electricityRate,
        miscellaneousFee,
        updateGlobalSettings
    } = useAdminStore()

    const [user, setUser] = useState<SupabaseUser | null>(null)
    const [loading, setLoading] = useState(true)

    // Admin Specific State
    const [isAdmin, setIsAdmin] = useState(false)
    const [localElecRate, setLocalElecRate] = useState(electricityRate)
    const [localMiscFee, setLocalMiscFee] = useState(miscellaneousFee)
    const [maintenanceMode, setMaintenanceMode] = useState(false)

    const [activeTab, setActiveTab] = useState('profile')

    // Profile info
    const [phone, setPhone] = useState('')
    const [fullName, setFullName] = useState('')

    // Addresses from Supabase
    const [addresses, setAddresses] = useState<Address[]>([])
    const [showAddAddress, setShowAddAddress] = useState(false)
    const [editingId, setEditingId] = useState<string | null>(null)
    const [newAddress, setNewAddress] = useState({
        full_name: '',
        address_line1: '',
        city: '',
        zip_code: '',
        phone: ''
    })

    useEffect(() => {
        loadUserData()
        // Sync local admin state with store on mount
        setLocalElecRate(electricityRate)
        setLocalMiscFee(miscellaneousFee)
    }, [])

    const loadUserData = async () => {
        const { data: { user } } = await supabase.auth.getUser()
        if (!user) {
            router.push('/login')
            return
        }

        setUser(user)
        setIsAdmin(user.email === 'admin@printhub.com')
        setFullName(user.user_metadata?.full_name || '')

        if (user.email === 'admin@printhub.com') {
            // Default admin tab to 'configuration'
            setActiveTab('configuration')
        }

        // Load user_details (for name and phone)
        const { data: details } = await supabase
            .from('user_details')
            .select('*')
            .eq('user_id', user.id)
            .single()

        if (details) {
            setFullName(details.full_name || user.user_metadata?.full_name || '')
            setPhone(details.phone || '')
        } else {
            // Fallback to metadata if no DB record yet
            setFullName(user.user_metadata?.full_name || '')
        }

        // Load addresses (Only for non-admin)
        if (user.email !== 'admin@printhub.com') {
            const { data: addrs } = await supabase
                .from('addresses')
                .select('*')
                .eq('user_id', user.id)

            if (addrs) {
                setAddresses(addrs)
            }
        }

        setLoading(false)
    }

    const saveAdminSettings = () => {
        updateGlobalSettings({
            electricityRate: Number(localElecRate),
            miscellaneousFee: Number(localMiscFee)
        })
        addToast('Global settings updated!', 'success')
    }

    if (loading) {
        return <Loader text="Loading profile..." />
    }

    if (!user) return null


    const saveProfile = async () => {
        if (!user) return

        try {
            // Update auth metadata
            const { error: authError } = await supabase.auth.updateUser({
                data: { full_name: fullName }
            })
            if (authError) throw authError

            // Update user_details table
            const { error: detailError } = await supabase
                .from('user_details')
                .upsert({
                    user_id: user.id,
                    full_name: fullName,
                    phone: phone,
                    updated_at: new Date().toISOString()
                })

            if (detailError) throw detailError

            // Re-fetch user to get updated metadata locally
            const { data: { user: updatedUser } } = await supabase.auth.getUser()
            setUser(updatedUser)
            addToast('Profile saved!', 'success')
        } catch (error) {
            addToast('Failed to save profile', 'error')
        }
    }

    const handleAddAddress = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!user) return

        try {
            const addressPayload = {
                user_id: user.id,
                full_name: newAddress.full_name,
                address_line1: newAddress.address_line1,
                city: newAddress.city,
                zip_code: newAddress.zip_code,
                phone: newAddress.phone
            }

            if (editingId) {
                // Update existing
                const { data, error } = await supabase
                    .from('addresses')
                    .update(addressPayload)
                    .eq('id', editingId)
                    .select()

                if (error) throw error
                if (data) {
                    setAddresses(addresses.map(a => a.id === editingId ? data[0] : a))
                    addToast('Address updated successfully!', 'success')
                }
            } else {
                // Insert new
                const { data, error } = await supabase
                    .from('addresses')
                    .insert(addressPayload)
                    .select()

                if (error) throw error
                if (data) {
                    setAddresses([...addresses, data[0]])
                    addToast('Address added successfully!', 'success')
                }
            }

            setNewAddress({ full_name: '', address_line1: '', city: '', zip_code: '', phone: '' })
            setShowAddAddress(false)
            setEditingId(null)
        } catch (error) {
            addToast('Failed to save address', 'error')
        }
    }

    const openAddressForm = (addr?: Address) => {
        if (addr) {
            setEditingId(addr.id)
            setNewAddress({
                full_name: addr.full_name,
                address_line1: addr.address_line1,
                city: addr.city,
                zip_code: addr.zip_code,
                phone: addr.phone || ''
            })
        } else {
            setEditingId(null)
            setNewAddress({
                full_name: user?.user_metadata?.full_name || '',
                address_line1: '',
                city: '',
                zip_code: '',
                phone: phone || ''
            })
        }
        setShowAddAddress(true)
    }

    const closeAddressForm = () => {
        setShowAddAddress(false)
        setEditingId(null)
        setNewAddress({ full_name: '', address_line1: '', city: '', zip_code: '', phone: '' })
    }

    const handleDeleteAddress = async (id: string) => {
        try {
            const { error, count } = await supabase
                .from('addresses')
                .delete({ count: 'exact' })
                .eq('id', id)

            if (error) throw error

            // Update local state
            setAddresses(addresses.filter(addr => addr.id !== id))
            addToast('Address deleted successfully!', 'success')
        } catch (error: any) {
            addToast(`Failed to delete: ${error.message}`, 'error')
        }
    }


    return (
        <div className={styles.container}>
            <BackButton />
            <div className={styles.header}>
                <h1 className="title-gradient">{isAdmin ? 'Admin Settings' : 'Account Settings'}</h1>
            </div>

            <div className={styles.grid}>
                {/* Sidebar */}
                <div className={styles.sidebar}>
                    <div className={styles.userInfo}>
                        <div className={styles.avatar}>
                            {user.user_metadata?.avatar_url ? (
                                <img src={user.user_metadata.avatar_url} alt={user.user_metadata.full_name || 'User'} />
                            ) : (
                                <User size={40} />
                            )}
                        </div>
                        <div className={styles.userDetails}>
                            <h3>{user.user_metadata?.full_name || 'User'}</h3>
                            <p>{user.email}</p>
                            {isAdmin && <span className={styles.badge}>ADMIN</span>}
                        </div>
                    </div>

                    <nav className={styles.nav}>
                        {isAdmin && (
                            <button
                                className={`${styles.navItem} ${activeTab === 'configuration' ? styles.active : ''}`}
                                onClick={() => setActiveTab('configuration')}
                            >
                                <SettingsIcon size={20} />
                                Global Config
                            </button>
                        )}

                        <button
                            className={`${styles.navItem} ${activeTab === 'profile' ? styles.active : ''}`}
                            onClick={() => setActiveTab('profile')}
                        >
                            <User size={20} />
                            Edit Profile
                        </button>

                        {!isAdmin && (
                            <button
                                className={`${styles.navItem} ${activeTab === 'addresses' ? styles.active : ''}`}
                                onClick={() => setActiveTab('addresses')}
                            >
                                <MapPin size={20} />
                                Addresses
                            </button>
                        )}


                    </nav>
                </div>

                {/* Content Area */}
                <div className={styles.content}>
                    {activeTab === 'configuration' && isAdmin && (
                        <div className={styles.section}>
                            <h2>Global Platform Settings</h2>
                            <p className={styles.subtitle}>These settings affect all new order calculations immediately.</p>

                            <form className={styles.form} onSubmit={(e) => e.preventDefault()}>
                                <div className={styles.formGroup}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                                        <Zap size={18} color="var(--primary-color)" />
                                        <label style={{ margin: 0 }}>Electricity Rate (INR/Hour)</label>
                                    </div>
                                    <input
                                        type="number"
                                        value={localElecRate}
                                        onChange={(e) => setLocalElecRate(parseFloat(e.target.value))}
                                        className={styles.input}
                                    />
                                    <p className={styles.hint}>Used to calculate print cost based on estimated print hours.</p>
                                </div>

                                <div className={styles.formGroup}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                                        <DollarSign size={18} color="var(--primary-color)" />
                                        <label style={{ margin: 0 }}>Miscellaneous Fee (INR)</label>
                                    </div>
                                    <input
                                        type="number"
                                        value={localMiscFee}
                                        onChange={(e) => setLocalMiscFee(parseFloat(e.target.value))}
                                        className={styles.input}
                                    />
                                    <p className={styles.hint}>Flat fee added to every line item for handling/packaging.</p>
                                </div>

                                <div className={styles.divider}></div>

                                <div className={styles.formGroup} style={{ flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between' }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                        <Activity size={24} color={maintenanceMode ? '#ff4d4d' : '#888'} />
                                        <div>
                                            <label style={{ margin: 0, fontSize: '1rem', color: 'white' }}>Maintenance Mode</label>
                                            <p className={styles.hint} style={{ margin: 0 }}>Disable new uploads and orders</p>
                                        </div>
                                    </div>
                                    <label className={styles.switch}>
                                        <input
                                            type="checkbox"
                                            checked={maintenanceMode}
                                            onChange={(e) => setMaintenanceMode(e.target.checked)}
                                        />
                                        <span className={styles.slider}></span>
                                    </label>
                                </div>

                                <button className={styles.saveBtn} onClick={saveAdminSettings} style={{ marginTop: '24px' }}>
                                    Update Global Settings
                                </button>
                            </form>
                        </div>
                    )}

                    {activeTab === 'profile' && (
                        <div className={styles.section}>
                            <h2>Edit Profile</h2>
                            <form className={styles.form} onSubmit={(e) => e.preventDefault()}>
                                <div className={styles.formGroup}>
                                    <label>Full Name</label>
                                    <input
                                        type="text"
                                        value={fullName}
                                        onChange={(e) => setFullName(e.target.value)}
                                        className={styles.input}
                                    />
                                </div>
                                <div className={styles.formGroup}>
                                    <label>Email Address</label>
                                    <input type="email" defaultValue={user.email || ''} disabled className={styles.input} />
                                </div>
                                <div className={styles.formGroup}>
                                    <label>Phone Number</label>
                                    <input
                                        type="tel"
                                        placeholder="+xx xxxxxxxxxx"
                                        className={styles.input}
                                        value={phone}
                                        onChange={(e) => setPhone(e.target.value)}
                                    />
                                </div>
                                <button className={styles.saveBtn} onClick={saveProfile} type="button">Save Changes</button>
                            </form>
                        </div>
                    )}

                    {activeTab === 'addresses' && !isAdmin && (
                        <div className={styles.section}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                                <h2>Saved Addresses</h2>
                                {!showAddAddress && (
                                    <button
                                        className={styles.secondaryBtn}
                                        onClick={() => openAddressForm()}
                                    >
                                        <Plus size={18} /> Add New
                                    </button>
                                )}
                            </div>

                            {showAddAddress && (
                                <form onSubmit={handleAddAddress} className={styles.addressForm}>
                                    <h3 style={{ marginTop: 0, marginBottom: '20px', color: 'white' }}>
                                        {editingId ? 'Edit Address' : 'Add New Address'}
                                    </h3>
                                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
                                        <div className={styles.formGroup}>
                                            <label>Full Name (Recipient)</label>
                                            <input
                                                placeholder="Recipient's Name"
                                                className={styles.input}
                                                value={newAddress.full_name}
                                                onChange={e => setNewAddress({ ...newAddress, full_name: e.target.value })}
                                                required
                                            />
                                        </div>
                                        <div className={styles.formGroup}>
                                            <label>Mobile Number</label>
                                            <input
                                                placeholder="Recipient's Phone"
                                                className={styles.input}
                                                value={newAddress.phone}
                                                onChange={e => setNewAddress({ ...newAddress, phone: e.target.value })}
                                                required
                                            />
                                        </div>
                                    </div>
                                    <div className={styles.formGroup}>
                                        <label>Street Address</label>
                                        <input
                                            placeholder="House No, Area, Landmark..."
                                            className={styles.input}
                                            value={newAddress.address_line1}
                                            onChange={e => setNewAddress({ ...newAddress, address_line1: e.target.value })}
                                            required
                                        />
                                    </div>
                                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                                        <div className={styles.formGroup}>
                                            <label>City</label>
                                            <input
                                                placeholder="City"
                                                className={styles.input}
                                                value={newAddress.city}
                                                onChange={e => setNewAddress({ ...newAddress, city: e.target.value })}
                                                required
                                            />
                                        </div>
                                        <div className={styles.formGroup}>
                                            <label>ZIP Code</label>
                                            <input
                                                placeholder="ZIP Code"
                                                className={styles.input}
                                                value={newAddress.zip_code}
                                                onChange={e => setNewAddress({ ...newAddress, zip_code: e.target.value })}
                                                required
                                            />
                                        </div>
                                    </div>
                                    <div style={{ display: 'flex', gap: '10px', marginTop: '20px' }}>
                                        <button type="submit" className={styles.saveBtn}>
                                            {editingId ? 'Update Address' : 'Save Address'}
                                        </button>
                                        <button
                                            type="button"
                                            className={styles.cancelBtn}
                                            onClick={closeAddressForm}
                                        >
                                            Cancel
                                        </button>
                                    </div>
                                </form>
                            )}

                            {!showAddAddress && addresses.length > 0 && (
                                <div className={styles.addressList}>
                                    {addresses.map(addr => (
                                        <div key={addr.id} className={styles.addressCard}>
                                            <div className={styles.addressIcon}>
                                                <MapPin size={24} />
                                            </div>
                                            <div className={styles.addressDetails}>
                                                <h4>{addr.full_name}</h4>
                                                <p>{addr.address_line1}, {addr.city}, {addr.zip_code}</p>
                                                {addr.phone && <p style={{ fontSize: '0.8rem', color: 'var(--primary-color)', marginTop: '4px' }}>📞 {addr.phone}</p>}
                                            </div>
                                            <div className={styles.addressItemActions}>
                                                <button
                                                    className={styles.editBtn}
                                                    onClick={() => openAddressForm(addr)}
                                                    title="Edit Address"
                                                >
                                                    <SettingsIcon size={18} />
                                                </button>
                                                <button
                                                    className={styles.deleteBtn}
                                                    onClick={() => handleDeleteAddress(addr.id)}
                                                    title="Delete Address"
                                                >
                                                    <Trash2 size={18} />
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}

                            {addresses.length === 0 && !showAddAddress && (
                                <div className={styles.emptyState}>
                                    <MapPin size={48} />
                                    <p>No addresses saved yet</p>
                                </div>
                            )}
                        </div>
                    )}

                </div>
            </div>
        </div>
    )
}

'use client'
export const dynamic = 'force-dynamic'
import { useSearchParams, useRouter } from 'next/navigation'
import { useEffect, useState, Suspense } from 'react'
import Link from 'next/link'
import styles from './Tracking.module.css'
import { Search, Package, CheckCircle, Clock, Truck, Printer, AlertTriangle, CreditCard, XCircle, RotateCcw, Image, Upload } from 'lucide-react'
import BackButton from '@/components/BackButton'
import { createClient } from '@/utils/supabase/client'
import { cancelUserOrder, submitReturnRequest } from '@/app/admin/actions'
import { useToastStore } from '@/store/toastStore'
import Loader from '@/components/Loader'

const STATUS_FLOW = [
    { key: 'received', label: 'Order Received', icon: Package },
    { key: 'ordered', label: 'Payment Pending', icon: CreditCard },
    { key: 'pending_confirmation', label: 'Pending Confirmation', icon: Search },
    { key: 'payment_confirmed', label: 'Processing', icon: Clock },
    { key: 'printing', label: 'Printing', icon: Printer },
    { key: 'completed', label: 'Completed', icon: Package },
    { key: 'shipped', label: 'Shipped', icon: Truck },
    { key: 'delivered', label: 'Delivered', icon: CheckCircle },
    { key: 'return_requested', label: 'Return Requested', icon: RotateCcw },
    { key: 'returned', label: 'Returned', icon: RotateCcw },
    { key: 'refunded', label: 'Refunded', icon: CreditCard },
]

function TrackingContent() {
    const searchParams = useSearchParams()
    const urlOrderId = searchParams.get('id')
    const supabase = createClient()
    const router = useRouter()

    const [order, setOrder] = useState<any>(null)
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)
    const [cancelling, setCancelling] = useState(false)
    const [showCancelConfirm, setShowCancelConfirm] = useState(false)
    const [showReturnModal, setShowReturnModal] = useState(false)
    const [returnReason, setReturnReason] = useState('')
    const [returnEvidence, setReturnEvidence] = useState<File[]>([])
    const [submittingReturn, setSubmittingReturn] = useState(false)
    const addToast = useToastStore((s) => s.addToast)

    useEffect(() => {
        let channel: any = null

        const getData = async () => {
            if (!urlOrderId) return
            setLoading(true)

            try {
                // Auth check
                const { data: { user } } = await supabase.auth.getUser()
                if (!user) {
                    router.push('/login?callbackUrl=/tracking?id=' + urlOrderId)
                    return
                }

                // Initial fetch
                const fetchOrder = async () => {
                    const { data, error: fetchError } = await supabase
                        .from('orders')
                        .select('*')
                        .eq('id', urlOrderId)
                        .single()

                    if (fetchError) throw fetchError
                    setOrder(data)
                    setLoading(false)
                }

                await fetchOrder()

                // Real-time listener
                channel = supabase.channel(`tracking-${urlOrderId}`)
                    .on('postgres_changes',
                        { event: 'UPDATE', schema: 'public', table: 'orders', filter: `id=eq.${urlOrderId}` },
                        () => fetchOrder()
                    )
                    .subscribe()

            } catch (err: any) {
                console.error('Tracking page error:', err)
                setError(err.message || 'Failed to load tracking data')
                setLoading(false)
            }
        }

        getData()

        return () => {
            if (channel) supabase.removeChannel(channel)
        }
    }, [urlOrderId, router, supabase])

    const handleCancel = async () => {
        if (!order) return
        setCancelling(true)
        try {
            const res = await cancelUserOrder(order.id)
            if (res.error) throw new Error(res.error)
            setOrder({ ...order, status: 'cancelled' })
            addToast('Order cancelled successfully', 'success')
            setShowCancelConfirm(false)
        } catch (err: any) {
            addToast(err?.message || 'Failed to cancel order', 'error')
        } finally {
            setCancelling(false)
        }
    }

    const handleReturn = async () => {
        if (!order || !returnReason.trim()) return
        setSubmittingReturn(true)
        try {
            let uploadedUrls: string[] = []

            // 1. Upload evidence if any
            if (returnEvidence.length > 0) {
                const uploads = returnEvidence.map(async (file) => {
                    const fileExt = file.name.split('.').pop()
                    const fileName = `${order.id}-${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`
                    const filePath = `returns/${fileName}`

                    const { error: uploadError } = await supabase.storage
                        .from('prints')
                        .upload(filePath, file)

                    if (uploadError) throw uploadError

                    const { data: { publicUrl } } = supabase.storage
                        .from('prints')
                        .getPublicUrl(filePath)

                    return publicUrl
                })

                uploadedUrls = await Promise.all(uploads)
            }

            const res = await submitReturnRequest(order.id, returnReason, uploadedUrls)
            if (res.error) throw new Error(res.error)

            setOrder({ ...order, status: 'return_requested', return_reason: returnReason, return_evidence_urls: uploadedUrls })
            addToast('Return request submitted successfully', 'success')
            setShowReturnModal(false)
        } catch (err: any) {
            console.error('Return error:', err)
            addToast(err?.message || 'Failed to submit return request', 'error')
        } finally {
            setSubmittingReturn(false)
        }
    }

    if (loading) return <Loader text="Fetching status..." />

    if (!urlOrderId) {
        return (
            <div className={styles.container}>
                <div className={styles.content} style={{ textAlign: 'center', padding: '100px 20px' }}>
                    <AlertTriangle size={48} style={{ color: '#ffae00', marginBottom: '20px' }} />
                    <h2>No Order Selected</h2>
                    <p style={{ opacity: 0.6, marginBottom: '32px' }}>Please select an order from your history to track.</p>
                    <button onClick={() => router.push('/orders')} className="btn">View My Orders</button>
                </div>
            </div>
        )
    }

    // Calculate current step index based on status
    let currentStepIdx = -1
    if (order) {
        if (order.status === 'ordered') currentStepIdx = 1
        else if (order.status === 'pending_confirmation') currentStepIdx = 2
        else if (order.status === 'payment_confirmed' || order.status === 'processing') currentStepIdx = 3
        else if (order.status === 'printing') currentStepIdx = 4
        else if (order.status === 'completed') currentStepIdx = 5
        else if (order.status === 'shipped') currentStepIdx = 6
        else if (order.status === 'delivered') currentStepIdx = 7
        else if (order.status === 'return_requested') currentStepIdx = 8
        else if (order.status === 'return_refused') currentStepIdx = 8 // Stop at return step but highlight error
        else if (order.status === 'returned') currentStepIdx = 9
        else if (order.status === 'refunded') currentStepIdx = 10
        else currentStepIdx = 0 // Initial Received state
    }

    const cancellableStatuses = ['ordered', 'pending_confirmation', 'payment_confirmed']
    const canCancel = order && cancellableStatuses.includes(order.status)

    return (
        <div className={styles.container}>
            <div className={styles.content}>
                <BackButton fallback="/orders" />
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '32px' }}>
                    <h1 className="title-gradient" style={{ margin: 0, fontSize: '1.6rem', fontFamily: 'monospace' }}>
                        #{order ? order.id.slice(0, 12).toUpperCase() : '...'}
                    </h1>

                    {order && order.status !== 'cancelled' && (
                        <button
                            onClick={() => setShowCancelConfirm(true)}
                            disabled={!canCancel || cancelling}
                            style={{
                                padding: '10px 20px',
                                borderRadius: '12px',
                                border: '1px solid rgba(255,0,85,0.2)',
                                background: canCancel ? 'rgba(255,0,85,0.05)' : 'rgba(255,255,255,0.02)',
                                color: canCancel ? '#ff0055' : 'rgba(255,255,255,0.3)',
                                cursor: canCancel ? 'pointer' : 'not-allowed',
                                fontWeight: 700,
                                fontSize: '0.9rem',
                                transition: 'all 0.2s'
                            }}
                        >
                            {cancelling ? 'Cancelling...' : canCancel ? 'Cancel Order' : 'Non-Cancellable'}
                        </button>
                    )}

                    {order && order.status === 'delivered' && (
                        <button
                            onClick={() => setShowReturnModal(true)}
                            className="btn btn-outline"
                            style={{
                                padding: '10px 20px',
                                borderRadius: '12px',
                                border: '1px solid #ffae00',
                                color: '#ffae00',
                                background: 'transparent',
                                fontWeight: 700,
                                fontSize: '0.9rem'
                            }}
                        >
                            <RotateCcw size={16} style={{ marginRight: '8px' }} /> Return/Refund
                        </button>
                    )}
                </div>

                {/* Inline cancel confirmation */}
                {showCancelConfirm && (
                    <div style={{
                        background: 'rgba(255,0,85,0.04)',
                        border: '1px solid rgba(255,0,85,0.2)',
                        borderRadius: '16px',
                        padding: '20px 24px',
                        marginBottom: '24px',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '16px'
                    }}>
                        <XCircle size={28} color="#ff0055" style={{ flexShrink: 0 }} />
                        <div style={{ flex: 1 }}>
                            <strong style={{ color: '#ff0055' }}>Cancel this order?</strong>
                            <p style={{ margin: '4px 0 0', fontSize: '0.85rem', opacity: 0.55 }}>This action cannot be undone. Your order will be permanently cancelled.</p>
                        </div>
                        <div style={{ display: 'flex', gap: '10px', flexShrink: 0 }}>
                            <button
                                onClick={() => setShowCancelConfirm(false)}
                                style={{ padding: '8px 18px', borderRadius: '10px', background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)', color: 'white', fontWeight: 600, cursor: 'pointer', fontSize: '0.88rem' }}
                            >Keep Order</button>
                            <button
                                onClick={handleCancel}
                                disabled={cancelling}
                                style={{ padding: '8px 18px', borderRadius: '10px', background: '#ff0055', border: 'none', color: 'white', fontWeight: 700, cursor: 'pointer', fontSize: '0.88rem', opacity: cancelling ? 0.6 : 1 }}
                            >{cancelling ? 'Cancelling...' : 'Yes, Cancel'}</button>
                        </div>
                    </div>
                )}

                {error ? (
                    <div className={styles.statusCard} style={{ textAlign: 'center', padding: '60px 20px' }}>
                        <AlertTriangle size={48} color="#ff4d4d" style={{ marginBottom: '16px' }} />
                        <h3 style={{ color: '#ff4d4d' }}>Error Locating Order</h3>
                        <p style={{ opacity: 0.6 }}>{error}</p>
                    </div>
                ) : order && (
                    <div className={styles.statusCard}>
                        {/* Summary */}
                        <div style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '1px solid rgba(255,255,255,0.05)', paddingBottom: '20px', marginBottom: '32px' }}>
                            <div>
                                <div style={{ fontSize: '0.7rem', opacity: 0.5, textTransform: 'uppercase', marginBottom: '4px' }}>Tracking Number</div>
                                <div style={{ fontWeight: 800, fontFamily: 'monospace', color: order.tracking_number ? '#39ff14' : 'rgba(255,255,255,0.4)' }}>{order.tracking_number || '--'}</div>
                            </div>
                            <div style={{ textAlign: 'right' }}>
                                <div style={{ fontSize: '0.7rem', opacity: 0.5, textTransform: 'uppercase', marginBottom: '4px' }}>Placed On</div>
                                <div style={{ opacity: 0.8 }}>{new Date(order.created_at).toLocaleDateString()}</div>
                            </div>
                        </div>

                        {/* Tracking ID injected from Admin */}
                        {order.tracking_number && (
                            <div style={{
                                background: 'linear-gradient(90deg, rgba(57, 255, 20, 0.05) 0%, rgba(0, 191, 255, 0.05) 100%)',
                                border: '1px solid rgba(57, 255, 20, 0.2)',
                                padding: '20px',
                                borderRadius: '16px',
                                display: 'flex',
                                justifyContent: 'space-between',
                                alignItems: 'center',
                                marginBottom: '40px'
                            }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                                    <div style={{ width: '48px', height: '48px', borderRadius: '12px', background: 'rgba(57, 255, 20, 0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                        <Truck size={24} color="#39ff14" />
                                    </div>
                                    <div>
                                        <div style={{ fontSize: '0.75rem', color: '#39ff14', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '1px' }}>Courier Tracking ID</div>
                                        <div style={{ fontWeight: 900, fontSize: '1.2rem', color: 'white', fontFamily: 'monospace', marginTop: '2px' }}>{order.tracking_number}</div>
                                    </div>
                                </div>
                                <div style={{ textAlign: 'right' }}>
                                    <div style={{ fontSize: '0.7rem', opacity: 0.4 }}>Status</div>
                                    <div style={{ color: '#39ff14', fontWeight: 800 }}>SHIPPED</div>
                                </div>
                            </div>
                        )}

                        {order.status === 'cancelled' ? (
                            <div style={{ textAlign: 'center', padding: '60px 0', border: '1px solid rgba(255,0,85,0.2)', borderRadius: '24px', background: 'rgba(255,0,85,0.02)' }}>
                                <AlertTriangle size={64} color="#ff0055" style={{ marginBottom: '20px' }} />
                                <h3 style={{ color: '#ff0055', fontSize: '1.8rem', marginBottom: '10px' }}>Order Cancelled</h3>
                                <p style={{ opacity: 0.6, maxWidth: '340px', margin: '0 auto' }}>This order has been terminated and will not be processed further by the print farm.</p>
                                <button onClick={() => router.push('/upload')} className="btn" style={{ marginTop: '32px' }}>Start New Print</button>
                            </div>
                        ) : (
                            /* Vertical Milestone Timeline */
                            <div className={styles.timeline}>
                                {STATUS_FLOW.filter(step => {
                                    const isReturnStep = ['return_requested', 'returned', 'refunded'].includes(step.key);
                                    if (!isReturnStep) return true;

                                    // Only show return steps if the order is already in a return-related state
                                    const hasReturnInitiated = ['return_requested', 'returned', 'refunded', 'return_refused'].includes(order.status);
                                    return hasReturnInitiated;
                                }).map((step) => {
                                    const stepIdxInFullFlow = STATUS_FLOW.findIndex(s => s.key === step.key)

                                    // A step is completed if the order has passed it in the full flow, 
                                    // or if the order is delivered (completing all non-return steps)
                                    // Special cases for return status completions:
                                    const isCompleted = stepIdxInFullFlow < currentStepIdx
                                        || (order.status === 'delivered' && stepIdxInFullFlow <= 7)
                                        || (order.status === 'returned' && step.key === 'return_requested')
                                        || (order.status === 'refunded' && (step.key === 'return_requested' || step.key === 'returned'))

                                    // Current step is the one that exactly matches the status, unless it's return_refused which stays at return_requested
                                    const isActuallyCurrent = (order.status === step.key) || (order.status === 'return_refused' && step.key === 'return_requested')

                                    // Only mark as current if NOT completed (to avoid double highlight)
                                    const isCurrent = isActuallyCurrent && !isCompleted

                                    let description = isCompleted ? 'Step Completed' : isCurrent ? 'Current Phase' : 'Upcoming Milestone'

                                    // Custom descriptions for payment flow
                                    // Custom descriptions for payment flow
                                    if (step.key === 'received') {
                                        description = 'Order successfully placed'
                                    } else if (step.key === 'ordered') {
                                        description = isCompleted ? 'Payment proof submitted' : isCurrent ? 'Awaiting your payment' : description
                                    } else if (step.key === 'pending_confirmation') {
                                        description = isCompleted ? 'Order verified' : isCurrent ? 'Admin is verifying your proof' : description
                                    } else if (step.key === 'payment_confirmed') {
                                        description = isCompleted ? 'Order confirmed' : isCurrent ? 'Preparing for print' : description
                                    } else if (step.key === 'printing') {
                                        description = isCompleted ? 'Printing finished' : isCurrent ? 'Printing your items' : description
                                    }

                                    return (
                                        <div key={step.key} className={`${styles.timelineItem} ${isCompleted ? styles.completed : ''} ${isCurrent ? styles.current : ''}`}>
                                            <div className={styles.timelineIcon}>
                                                {isCompleted ? <CheckCircle size={16} /> : <step.icon size={16} />}
                                            </div>
                                            <div className={styles.timelineContent}>
                                                <h3>{step.label}</h3>
                                                <p>{description}</p>
                                            </div>
                                        </div>
                                    )
                                })}
                            </div>
                        )}

                        {order && (order.status === 'return_requested' || order.status === 'returned' || order.status === 'return_refused') && (
                            <div style={{
                                marginTop: '32px',
                                padding: '24px',
                                background: order.status === 'return_refused' ? 'rgba(255, 0, 85, 0.05)' :
                                    order.status === 'returned' ? 'rgba(57, 255, 20, 0.05)' :
                                        'rgba(255, 174, 0, 0.05)',
                                border: `1px solid ${order.status === 'return_refused' ? 'rgba(255, 0, 85, 0.2)' :
                                    order.status === 'returned' ? 'rgba(57, 255, 20, 0.2)' :
                                        'rgba(255, 174, 0, 0.2)'}`,
                                borderRadius: '16px',
                                textAlign: 'center'
                            }}>
                                <RotateCcw size={32} color={order.status === 'return_refused' ? '#ff0055' : order.status === 'returned' ? '#39ff14' : '#ffae00'} style={{ marginBottom: '16px' }} />
                                <h3 style={{ color: order.status === 'return_refused' ? '#ff0055' : order.status === 'returned' ? '#39ff14' : '#ffae00', marginBottom: '8px' }}>
                                    {order.status === 'return_requested' ? 'Return Request Pending' :
                                        order.status === 'returned' ? 'Return Request Accepted' :
                                            'Return Request Refused'}
                                </h3>
                                <p style={{ fontSize: '0.9rem', opacity: 0.6 }}>
                                    {order.status === 'return_requested' ? 'Our team is reviewing your return request.' :
                                        order.status === 'returned' ? 'Your return request has been approved. Our team will contact you for next steps.' :
                                            'Your return request has been declined.'}
                                </p>

                                {order.admin_return_note && (
                                    <div style={{
                                        marginTop: '16px',
                                        padding: '12px',
                                        background: 'rgba(255,255,255,0.02)',
                                        borderRadius: '8px',
                                        fontSize: '0.85rem',
                                        border: '1px solid rgba(255,255,255,0.05)'
                                    }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '4px', justifyContent: 'center' }}>
                                            <AlertTriangle size={14} color="#ffae00" />
                                            <strong style={{ opacity: 0.8 }}>Admin Message:</strong>
                                        </div>
                                        <p style={{ margin: 0, opacity: 0.9, fontStyle: 'italic' }}>"{order.admin_return_note}"</p>
                                    </div>
                                )}
                            </div>
                        )}

                        <div style={{ marginTop: '40px', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '16px', paddingTop: '20px', borderTop: '1px solid rgba(255,255,255,0.05)' }}>
                            <Link
                                href={`/contact?subject=Order Help: ${order.id}`}
                                style={{
                                    textDecoration: 'none',
                                    padding: '12px 24px',
                                    borderRadius: '12px',
                                    background: 'rgba(255,255,255,0.05)',
                                    border: '1px solid rgba(255,255,255,0.1)',
                                    color: 'white',
                                    fontWeight: 600,
                                    fontSize: '0.9rem',
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '8px',
                                    transition: 'all 0.2s'
                                }}
                                onMouseEnter={e => e.currentTarget.style.background = 'rgba(255,255,255,0.1)'}
                                onMouseLeave={e => e.currentTarget.style.background = 'rgba(255,255,255,0.05)'}
                            >
                                <Package size={18} />
                                Need Help? Contact Support
                            </Link>
                            <p style={{ fontSize: '0.8rem', opacity: 0.3 }}>Synchronized with PrintHub Manufacturing System</p>
                        </div>
                    </div>
                )}
            </div>

            {/* Return Modal */}
            {showReturnModal && (
                <div className={styles.modalOverlay}>
                    <div className="glass" style={{
                        maxWidth: '500px',
                        width: '90%',
                        padding: '32px',
                        borderRadius: '24px',
                        boxShadow: '0 20px 50px rgba(0,0,0,0.5)'
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '24px' }}>
                            <div style={{
                                width: '48px',
                                height: '48px',
                                borderRadius: '14px',
                                background: 'rgba(255, 174, 0, 0.1)',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center'
                            }}>
                                <RotateCcw size={24} color="#ffae00" />
                            </div>
                            <div>
                                <h2 style={{ margin: 0 }}>Return Request</h2>
                                <p style={{ margin: 0, opacity: 0.5, fontSize: '0.85rem' }}>Order #{order.id.slice(0, 8).toUpperCase()}</p>
                            </div>
                        </div>

                        <p style={{ fontSize: '0.95rem', lineHeight: 1.6, marginBottom: '24px' }}>
                            Please provide a reason for your return or refund request. Our team will review your request and get back to you within 24-48 hours.
                        </p>

                        <div style={{ marginBottom: '24px' }}>
                            <label style={{ display: 'block', fontSize: '0.8rem', fontWeight: 600, color: '#ffae00', marginBottom: '8px', textTransform: 'uppercase' }}>Reason for Return</label>
                            <textarea
                                value={returnReason}
