            .from('orders')
            .select('total_amount, shipping_cost, status')

        if (error) throw error

        const completedOrders = data?.filter(o => o.status !== 'cancelled') || []
        const totalRevenue = completedOrders.reduce((sum, o) => sum + (o.total_amount || 0), 0)

