'use client'
import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/utils/supabase/client'
import { User } from '@supabase/supabase-js'
import { useAdminStore } from '@/store/adminStore'
import { FilamentKey } from '@/utils/pricingEngine'
import styles from '../Admin.module.css'
import { Plus, Trash2, X, Edit2, Save, AlertTriangle, ChevronDown } from 'lucide-react'
import { useToastStore } from '@/store/toastStore'
import Loader from '@/components/Loader'
import CustomSelect from '@/components/CustomSelect'

export default function AdminMaterialsPage() {
    const addToast = useToastStore((state) => state.addToast)
    const router = useRouter()
    const supabase = createClient()
    const [user, setUser] = useState<User | null>(null)
    const [loading, setLoading] = useState(true)
    const [isProcessing, setIsProcessing] = useState(false)

    const {
        filaments, updateFilament, addFilament, renameFilament, removeFilament,
        updateGlobalSettings, electricityRate, miscellaneousFee, supportMaterialPrice, updateColorPricing,
        addColorWithPricing, updateFilamentColors, updateColorHex,
        materialTypes, addMaterialType, removeMaterialType,
        supportTypes, addSupportType, removeSupportType,
        hasHydrated, fetchSettings
    } = useAdminStore()

    // Add Material State
    const [brandName, setBrandName] = useState('')
    const [materialType, setMaterialType] = useState('PLA')
    const [newMaterialType, setNewMaterialType] = useState('')
    const [newTypeDensity, setNewTypeDensity] = useState(1.24)
    const [newTypeProperties, setNewTypeProperties] = useState({
        strength: 5,
        flexibility: 5,
        heatRes: 5,
        durability: 5
    })
    const [editingKey, setEditingKey] = useState<FilamentKey | null>(null)

    // Add Color State
    const [addingColorTo, setAddingColorTo] = useState<FilamentKey | null>(null)
    const [newColorHex, setNewColorHex] = useState('#ffffff')
    const [newColorPrice, setNewColorPrice] = useState(0)

    // Confirmation states
    const [deletingMaterialKey, setDeletingMaterialKey] = useState<FilamentKey | null>(null)
    const [deletingType, setDeletingType] = useState<string | null>(null)
    const [deletingSupportType, setDeletingSupportType] = useState<string | null>(null)
    const [newSupportType, setNewSupportType] = useState('')

    useEffect(() => {
        const checkUser = async () => {
            try {
                const { data: { user }, error } = await supabase.auth.getUser()
                if (error) throw error
                setUser(user)
                setLoading(false)

                const ADMIN_EMAILS_ENV = process.env.NEXT_PUBLIC_ADMIN_EMAILS || 'admin@printhub.com,newadmin@printhub.com'
                const ADMINS = ADMIN_EMAILS_ENV.split(',').map(e => e.trim().toLowerCase())
                const userEmail = user?.email?.toLowerCase() || ''
                if (!user || !ADMINS.includes(userEmail)) {
                    router.push('/')
                }
            } catch (err) {
                console.error('Auth check failed:', err)
                setLoading(false)
                router.push('/')
            }
        }
        checkUser().then(() => {
            fetchSettings()
        })
    }, [router, fetchSettings])

    const handleSaveFilament = async () => {
        if (!brandName || !materialType || isProcessing) return
        setIsProcessing(true)

        try {
            if (editingKey) {
                // Update existing
                const cleanBrand = brandName.replace(/[^a-zA-Z0-9]/g, '').toUpperCase()
                const cleanType = materialType.replace(/[^a-zA-Z0-9]/g, '').toUpperCase()
                const newKey = `${cleanBrand}_${cleanType}` as FilamentKey

                if (newKey !== editingKey) {
                    // Key changed, rename it
                    if (filaments[newKey]) {
                        addToast('Material with this name already exists!', 'error')
                        setIsProcessing(false)
                        return
                    }
                    await renameFilament(editingKey, newKey)
                    await updateFilament(newKey, { brand: brandName, type: materialType })
                } else {
                    await updateFilament(editingKey, { brand: brandName, type: materialType })
                }
                setEditingKey(null)
            } else {
                // Auto-generate key: BRAND_TYPE (uppercase, underscores)
                const cleanBrand = brandName.replace(/[^a-zA-Z0-9]/g, '').toUpperCase()
                const cleanType = materialType.replace(/[^a-zA-Z0-9]/g, '').toUpperCase()
                const key = `${cleanBrand}_${cleanType}` as FilamentKey

                // Check if key exists
                if (filaments[key]) {
                    addToast('Material with this generated key already exists!', 'error')
                    setIsProcessing(false)
                    return
                }

                await addFilament({
                    key,
                    pricePerGram: 0,
                    availableColors: [],
                    density: 1.24, // Fallback, fetched from Material Types dynamically
                    properties: { strength: 5, flexibility: 5, heatRes: 5, durability: 5 },
                    colorPricing: {},
                    brand: brandName,
                    type: materialType
                })
            }

            setBrandName('')
            setMaterialType(materialTypes[0]?.name || 'PLA')
            addToast('Material saved successfully!', 'success')
        } catch (err) {
            console.error('Failed to save material:', err)
            addToast('Error saving material. Please try again.', 'error')
        } finally {
            setIsProcessing(false)
        }
    }

    const startEditing = (key: FilamentKey) => {
        setEditingKey(key)
        const filament = filaments[key]
        setBrandName(filament.brand || '')
        setMaterialType(filament.type || 'PLA')
    }

    const cancelEditing = () => {
        setEditingKey(null)
        setBrandName('')
        setMaterialType(materialTypes[0]?.name || 'PLA')
    }

    const startAddColor = (key: FilamentKey) => {
        setAddingColorTo(key)
        setNewColorHex('#ffffff')
        setNewColorPrice(filaments[key].pricePerGram > 0 ? filaments[key].pricePerGram : 0)
    }

    const confirmAddColor = async (key: FilamentKey) => {
        setIsProcessing(true)
        try {
            await addColorWithPricing(key, newColorHex, newColorPrice)
            setAddingColorTo(null)
            addToast('Color added successfully!', 'success')
        } catch (err) {
            addToast('Failed to add color.', 'error')
        } finally {
            setIsProcessing(false)
        }
    }

    const cancelAddColor = () => {
        setAddingColorTo(null)
    }

    const handleRemoveColor = async (key: FilamentKey, color: string) => {
        const currentColors = filaments[key].availableColors || []
        await updateFilamentColors(key, currentColors.filter(c => c !== color))
    }

    if (loading || !user || !hasHydrated) {
        return <Loader text={!hasHydrated ? '🔄 Syncing Admin Data...' : '🔐 Verifying Access...'} />
    }

    return (
        <div className="container" style={{ maxWidth: '100%', padding: 0 }}>
            <h1 className="title-gradient" style={{ marginBottom: '32px' }}>Materials & Pricing</h1>

            <div className={styles.grid}>
                {/* Global Settings */}
                <section className={`${styles.section} glass`} style={{ gridColumn: '1 / -1' }}>
                    <h2>Pricing</h2>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', maxWidth: '800px' }}>
                        <div>
                            <label style={{ display: 'block', marginBottom: '8px', fontSize: '0.9rem', color: 'rgba(255,255,255,0.7)' }}>Electricity Rate (₹/hr)</label>
                            <input
                                type="number"
                                value={electricityRate}
                                onChange={async (e) => {
                                    setIsProcessing(true)
                                    await updateGlobalSettings({ electricityRate: parseFloat(e.target.value) || 0 })
                                    setIsProcessing(false)
                                }}
                                className={styles.numInput}
                                style={{ width: '100%' }}
                            />
                        </div>
                        <div>
                            <label style={{ display: 'block', marginBottom: '8px', fontSize: '0.9rem', color: 'rgba(255,255,255,0.7)' }}>One-time Setup Fee (₹/print)</label>
                            <input
                                type="number"
                                value={miscellaneousFee}
                                onChange={async (e) => {
                                    setIsProcessing(true)
                                    await updateGlobalSettings({ miscellaneousFee: parseFloat(e.target.value) || 0 })
                                    setIsProcessing(false)
                                }}
                                className={styles.numInput}
                                style={{ width: '100%' }}
                            />
                        </div>
                        <div>
                            <label style={{ display: 'block', marginBottom: '8px', fontSize: '0.9rem', color: 'rgba(255,255,255,0.7)' }}>Support Price (₹/g)</label>
                            <input
                                type="number"
                                step="any"
                                value={supportMaterialPrice}
                                onChange={async (e) => {
                                    setIsProcessing(true)
                                    await updateGlobalSettings({ supportMaterialPrice: parseFloat(e.target.value) || 0 })
                                    setIsProcessing(false)
                                }}
                                className={styles.numInput}
                                style={{ width: '100%' }}
                            />
                        </div>
                    </div>
                </section>

                {/* Filament Management */}
                <section className={`${styles.section} glass`} style={{ gridColumn: '1 / -1' }}>
                    <h2>Material Management</h2>

                    <div className={styles.addPrinterForm} style={{ gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', alignItems: 'end' }}>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <label style={{ fontSize: '0.8rem', opacity: 0.7, fontWeight: 600 }}>Brand</label>
                                <span style={{ fontSize: '0.65rem', opacity: 0.5 }}>Manufacturer</span>
                            </div>
                            <input
                                type="text"
                                placeholder="e.g. Bambu Lab"
                                value={brandName}
                                onChange={(e) => setBrandName(e.target.value)}
                                className={styles.input}
                                style={{ width: '100%', border: editingKey ? '1px solid #39ff14' : '' }}
                            />
                        </div>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <label style={{ fontSize: '0.8rem', opacity: 0.7, fontWeight: 600 }}>Material</label>
                                <span style={{ fontSize: '0.65rem', opacity: 0.5 }}>Polymers</span>
                            </div>
                            <CustomSelect
                                value={materialType}
                                options={(materialTypes || []).map(type => ({ value: type.name, label: type.name }))}
                                onChange={(val) => setMaterialType(val)}
                            />
                        </div>

                        <div style={{ display: 'flex', gap: '10px' }}>
                            <button onClick={handleSaveFilament} className="btn" disabled={!brandName || !materialType} style={{ flex: 1, height: '48px', opacity: (!brandName || !materialType) ? 0.5 : 1 }}>
                                {editingKey ? <Save size={18} /> : <Plus size={18} />} {editingKey ? 'Save Changes' : 'Add Material'}
                            </button>
                            {editingKey && (
                                <button onClick={cancelEditing} className="btn secondary" style={{ height: '48px', background: 'rgba(255,255,255,0.1)' }}>
                                    <X size={18} />
                                </button>
                            )}
                        </div>
                    </div>



                    <div className={styles.tableContainer}>
                        <table className={styles.table}>
                            <thead>
                                <tr>
                                    <th>Brand</th>
                                    <th>Type</th>
                                    <th>Density & Properties</th>
                                    <th>Colors & Pricing</th>
                                    <th>Action</th>
                                </tr>
                            </thead>
                            <tbody>
                                {(Object.keys(filaments) as FilamentKey[]).map((key) => (
                                    <tr key={key} style={{ outline: editingKey === key ? '1px solid #39ff14' : '', background: editingKey === key ? 'rgba(57, 255, 20, 0.02)' : '' }}>
                                        <td style={{ verticalAlign: 'top', paddingTop: '20px' }}>
                                            <div style={{ fontWeight: '700', color: 'white' }}>
                                                {filaments[key].brand || '—'}
                                            </div>
                                        </td>
                                        <td style={{ verticalAlign: 'top', paddingTop: '20px' }}>
                                            <div style={{ fontWeight: '800', color: 'white', fontFamily: 'monospace' }}>
                                                {filaments[key].type || key}
                                            </div>
                                        </td>
                                        <td style={{ verticalAlign: 'top', paddingTop: '20px' }}>
                                            <div style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.6)' }}>
                                                Density: <span style={{ color: '#39ff14' }}>{filaments[key].density || 1.24}</span>
                                            </div>
                                            {filaments[key].properties && (
                                                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '4px', marginTop: '8px', fontSize: '0.65rem' }}>
                                                    <span title="Strength">S: {filaments[key].properties!.strength}</span>
                                                    <span title="Flexibility">F: {filaments[key].properties!.flexibility}</span>
                                                    <span title="Heat Resistance">H: {filaments[key].properties!.heatRes}</span>
                                                    <span title="Durability">D: {filaments[key].properties!.durability}</span>
                                                </div>
                                            )}
                                        </td>
                                        <td>
                                            <div className={styles.colorGrid}>
                                                {(() => {
                                                    const isEditingRow = editingKey === key
                                                    return (
                                                        <>
                                                            {(filaments[key].availableColors || []).map((color) => (
                                                                <div key={color} style={{
                                                                    display: 'flex',
                                                                    alignItems: 'center',
                                                                    gap: '10px',
                                                                    background: isEditingRow ? 'rgba(57, 255, 20, 0.05)' : 'rgba(255,255,255,0.05)',
                                                                    padding: '8px 12px',
                                                                    borderRadius: '12px',
                                                                    border: isEditingRow ? '1px solid rgba(57, 255, 20, 0.3)' : '1px solid rgba(255,255,255,0.1)',
                                                                    transition: 'all 0.2s'
                                                                }}>
                                                                    {isEditingRow ? (
                                                                        <input
                                                                            type="color"
                                                                            value={color}
                                                                            onChange={(e) => updateColorHex(key, color, e.target.value)}
                                                                            style={{ width: '28px', height: '28px', padding: 0, border: 'none', background: 'none', cursor: 'pointer', borderRadius: '8px' }}
                                                                            title="Edit Color Hex"
                                                                        />
                                                                    ) : (
                                                                        <div style={{ background: color, width: '28px', height: '28px', borderRadius: '8px', border: '1px solid rgba(255,255,255,0.2)', flexShrink: 0 }} />
                                                                    )}

                                                                    <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                                                                        <span style={{ fontSize: '0.8rem', opacity: 0.5 }}>₹</span>
                                                                        <input
                                                                            type="number"
                                                                            value={filaments[key].colorPricing?.[color] || ''}
                                                                            onChange={(e) => updateColorPricing(key, color, parseFloat(e.target.value) || 0)}
                                                                            className={styles.numInput}
                                                                            disabled={!isEditingRow}
                                                                            style={{
                                                                                width: '60px',
                                                                                padding: '4px 8px',
                                                                                fontSize: '0.9rem',
                                                                                border: 'none',
                                                                                background: 'rgba(0,0,0,0.3)',
                                                                                cursor: isEditingRow ? 'text' : 'not-allowed',
                                                                                opacity: isEditingRow ? 1 : 0.6
                                                                            }}
                                                                        />
                                                                        <span style={{ fontSize: '0.7rem', opacity: 0.3 }}>/g</span>
                                                                    </div>

                                                                    <button
                                                                        onClick={() => handleRemoveColor(key, color)}
                                                                        disabled={!isEditingRow}
                                                                        style={{
                                                                            background: 'rgba(255, 0, 85, 0.1)',
                                                                            border: 'none',
                                                                            color: '#ff0055',
                                                                            cursor: isEditingRow ? 'pointer' : 'not-allowed',
                                                                            padding: '6px',
                                                                            borderRadius: '8px',
                                                                            display: 'flex',
                                                                            transition: 'all 0.2s',
                                                                            opacity: isEditingRow ? 1 : 0.3
                                                                        }}
                                                                        onMouseEnter={(e) => { if (isEditingRow) e.currentTarget.style.background = 'rgba(255,0,85,0.2)' }}
                                                                        onMouseLeave={(e) => { if (isEditingRow) e.currentTarget.style.background = 'rgba(255,0,85,0.1)' }}
                                                                        title="Remove Color"
                                                                    >
                                                                        <Trash2 size={14} />
                                                                    </button>
                                                                </div>
                                                            ))}

                                                            {addingColorTo === key ? (
                                                                <div style={{ display: 'flex', alignItems: 'center', gap: '8px', background: 'rgba(57, 255, 20, 0.05)', padding: '6px 12px', borderRadius: '12px', border: '1px solid rgba(57, 255, 20, 0.3)' }}>
                                                                    <input
                                                                        type="color"
                                                                        value={newColorHex}
                                                                        onChange={(e) => setNewColorHex(e.target.value)}
                                                                        style={{ width: '28px', height: '28px', padding: 0, border: 'none', background: 'none', cursor: 'pointer' }}
                                                                    />
                                                                    <input
                                                                        type="number"
                                                                        placeholder="₹/g"
                                                                        value={newColorPrice || ''}
                                                                        onChange={(e) => setNewColorPrice(parseFloat(e.target.value))}
                                                                        className={styles.numInput}
                                                                        style={{ width: '60px', padding: '4px 8px', fontSize: '0.9rem', border: 'none', background: 'rgba(0,0,0,0.3)' }}
                                                                    />
                                                                    <div style={{ display: 'flex', gap: '4px' }}>
                                                                        <button onClick={() => confirmAddColor(key)} style={{ color: '#39ff14', background: 'rgba(57,255,20,0.1)', border: 'none', borderRadius: '6px', cursor: 'pointer', padding: '6px', display: 'flex' }}><Plus size={14} /></button>
                                                                        <button onClick={cancelAddColor} style={{ color: '#ff0055', background: 'rgba(255,0,85,0.1)', border: 'none', borderRadius: '6px', cursor: 'pointer', padding: '6px', display: 'flex' }}><X size={14} /></button>
                                                                    </div>
                                                                </div>
                                                            ) : (
                                                                <button
                                                                    onClick={() => startAddColor(key)}
                                                                    className={styles.addColorBtn}
                                                                    title="Add Color"
                                                                    disabled={!isEditingRow}
                                                                    style={{
                                                                        opacity: isEditingRow ? 1 : 0.3,
                                                                        cursor: isEditingRow ? 'pointer' : 'not-allowed'
                                                                    }}
                                                                >
                                                                    <Plus size={18} />
                                                                </button>
                                                            )}
                                                        </>
                                                    )
                                                })()}
                                            </div>
                                        </td>
                                        <td style={{ verticalAlign: 'top', paddingTop: '20px', position: 'relative' }}>
                                            <div style={{ display: 'flex', gap: '12px' }}>
                                                <button onClick={() => startEditing(key)} className={styles.editBtn} title="Edit Name/Config">
                                                    <Edit2 size={18} />
                                                </button>
                                                <button onClick={() => setDeletingMaterialKey(key)} className={styles.deleteBtn} title="Delete Full Material">
                                                    <Trash2 size={18} />
                                                </button>
                                            </div>

                                            {deletingMaterialKey === key && (
                                                <div style={{
                                                    position: 'absolute', inset: 0, zIndex: 10,
                                                    background: 'rgba(255,0,85,0.95)', backdropFilter: 'blur(5px)',
                                                    display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '12px',
                                                    animation: 'fadeIn 0.2s ease', color: 'white'
                                                }}>
                                                    <div style={{ fontWeight: 800, fontSize: '0.9rem', display: 'flex', alignItems: 'center', gap: '8px' }}>
                                                        <AlertTriangle size={18} /> Delete material?
                                                    </div>
                                                    <button onClick={() => setDeletingMaterialKey(null)} style={{ background: 'rgba(255,255,255,0.2)', border: 'none', color: 'white', padding: '6px 12px', borderRadius: '8px', cursor: 'pointer', fontWeight: 600 }}>Cancel</button>
                                                    <button onClick={() => { removeFilament(key); setDeletingMaterialKey(null); addToast('Material removed', 'info') }} style={{ background: 'white', border: 'none', color: '#ff0055', padding: '6px 12px', borderRadius: '8px', cursor: 'pointer', fontWeight: 800 }}>Delete</button>
                                                </div>
                                            )}
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </section>

                {/* Material Types Configuration */}
                <section className={`${styles.section} glass`} style={{ gridColumn: '1 / -1' }}>
                    <h2>Configure Material Types</h2>
                    <p style={{ fontSize: '0.8rem', opacity: 0.6, marginBottom: '16px' }}>Add or remove material types that appear in the dropdown (e.g. PLA, PLA+, PETG).</p>

                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px', marginBottom: '20px' }}>
                        {(materialTypes || []).map(type => (
                            <div key={type.name} style={{ position: 'relative' }}>
                                <div style={{
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '8px',
                                    background: 'rgba(255,255,255,0.05)',
                                    padding: '6px 12px',
                                    borderRadius: '20px',
                                    border: '1px solid rgba(255,255,255,0.1)'
                                }}>
                                    <span style={{ fontSize: '0.9rem' }}>{type.name}</span>
                                    <button
                                        onClick={() => setDeletingType(type.name)}
                                        style={{ background: 'none', border: 'none', color: '#ff0055', cursor: 'pointer', display: 'flex', padding: '2px' }}
                                    >
                                        <X size={14} />
                                    </button>
                                </div>
                                {deletingType === type.name && (
                                    <div style={{
                                        position: 'absolute',
                                        left: '0',
                                        top: '0',
                                        height: '100%',
                                        width: 'max-content',
                                        minWidth: '100%',
                                        zIndex: 20,
                                        background: '#ff0055',
                                        borderRadius: '20px',
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'center',
                                        gap: '8px',
                                        animation: 'fadeIn 0.2s ease, scaleIn 0.2s ease',
                                        color: 'white',
                                        padding: '0 12px',
                                        boxShadow: '0 4px 12px rgba(255, 0, 85, 0.4)'
                                    }}>
                                        <span style={{ fontSize: '0.75rem', fontWeight: 800, whiteSpace: 'nowrap' }}>Remove {type.name}?</span>
                                        <button onClick={() => setDeletingType(null)} style={{ background: 'none', border: 'none', color: 'white', cursor: 'pointer', padding: '2px', display: 'flex' }}><X size={14} /></button>
                                        <button onClick={async () => {
                                            setIsProcessing(true)
                                            await removeMaterialType(type.name)
                                            setDeletingType(null)
                                            setIsProcessing(false)
                                            addToast(`${type.name} removed`, 'info')
                                        }} style={{ background: 'white', border: 'none', color: '#ff0055', borderRadius: '4px', padding: '2px 8px', fontSize: '0.7rem', fontWeight: 900, cursor: 'pointer' }}>Yes</button>
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px', maxWidth: '600px', background: 'rgba(255,255,255,0.02)', padding: '20px', borderRadius: '12px' }}>
                        <div>
                            <label style={{ fontSize: '0.8rem', opacity: 0.8 }}>Material Type Name</label>
                            <input
                                type="text"
                                placeholder="New Material Type (e.g. TPU-CF)"
                                value={newMaterialType}
                                onChange={(e) => setNewMaterialType(e.target.value)}
                                className={styles.input}
                                style={{ width: '100%', marginTop: '8px' }}
                            />
                        </div>
                        <div>
                            <label style={{ fontSize: '0.8rem', opacity: 0.8 }}>Density (g/cm³)</label>
                            <input
                                type="number"
                                step="any"
                                value={newTypeDensity}
                                onChange={(e) => setNewTypeDensity(parseFloat(e.target.value) || 0)}
                                className={styles.input}
                                style={{ width: '100%', marginTop: '8px' }}
                            />
                        </div>

                        <div>
                            <h3 style={{ fontSize: '0.8rem', opacity: 0.8, marginBottom: '12px' }}>Physical Properties (1-10)</h3>
                            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '16px' }}>
                                {(['strength', 'flexibility', 'heatRes', 'durability'] as (keyof typeof newTypeProperties)[]).map((prop) => (
                                    <div key={prop} style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                                        <label style={{ fontSize: '0.75rem', opacity: 0.6, textTransform: 'capitalize' }}>
                                            {prop === 'heatRes' ? 'Heat Resistance' : prop}: <span style={{ color: '#39ff14' }}>{newTypeProperties[prop]}</span>
                                        </label>
                                        <input
                                            type="range"
                                            min="1"
                                            max="10"
                                            value={newTypeProperties[prop]}
                                            onChange={(e) => setNewTypeProperties({ ...newTypeProperties, [prop]: parseInt(e.target.value) })}
                                            style={{ accentColor: '#39ff14' }}
                                        />
                                    </div>
                                ))}
                            </div>
                        </div>

                        <button
                            onClick={async () => {
                                if (newMaterialType && !isProcessing) {
                                    setIsProcessing(true)
                                    await addMaterialType({
                                        name: newMaterialType,
                                        density: newTypeDensity,
                                        properties: newTypeProperties
                                    })
                                    setNewMaterialType('')
                                    setNewTypeDensity(1.24)
                                    setNewTypeProperties({ strength: 5, flexibility: 5, heatRes: 5, durability: 5 })
                                    setIsProcessing(false)
                                    addToast(`${newMaterialType} added`, 'success')
                                }
                            }}
                            className="btn"
                            disabled={!newMaterialType || isProcessing}
                            style={{ alignSelf: 'flex-start' }}
                        >
                            {isProcessing ? 'Adding...' : 'Add Type With Properties'}
                        </button>
                    </div>
                </section>

                {/* Support Types Configuration */}
                <section className={`${styles.section} glass`} style={{ gridColumn: '1 / -1' }}>
                    <h2>Configure Support Types</h2>
                    <p style={{ fontSize: '0.8rem', opacity: 0.6, marginBottom: '16px' }}>Add or remove support types (e.g. Standard, Tree, Dissolvable).</p>

                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px', marginBottom: '20px' }}>
                        {(supportTypes || []).map(type => (
                            <div key={type} style={{ position: 'relative' }}>
                                <div style={{
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '8px',
                                    background: 'rgba(255,255,255,0.05)',
                                    padding: '6px 12px',
                                    borderRadius: '20px',
                                    border: '1px solid rgba(255,255,255,0.1)'
                                }}>
                                    <span style={{ fontSize: '0.9rem' }}>{type}</span>
                                    <button
                                        onClick={() => setDeletingSupportType(type)}
                                        style={{ background: 'none', border: 'none', color: '#ff0055', cursor: 'pointer', display: 'flex', padding: '2px' }}
                                    >
                                        <X size={14} />
                                    </button>
                                </div>
                                {deletingSupportType === type && (
                                    <div style={{
                                        position: 'absolute',
                                        left: '0',
                                        top: '0',
                                        height: '100%',
                                        width: 'max-content',
                                        minWidth: '100%',
                                        zIndex: 20,
                                        background: '#ff0055',
                                        borderRadius: '20px',
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'center',
                                        gap: '8px',
                                        animation: 'fadeIn 0.2s ease, scaleIn 0.2s ease',
                                        color: 'white',
                                        padding: '0 12px',
                                        boxShadow: '0 4px 12px rgba(255, 0, 85, 0.4)'
                                    }}>
                                        <span style={{ fontSize: '0.75rem', fontWeight: 800, whiteSpace: 'nowrap' }}>Remove {type}?</span>
                                        <button onClick={() => setDeletingSupportType(null)} style={{ background: 'none', border: 'none', color: 'white', cursor: 'pointer', padding: '2px', display: 'flex' }}><X size={14} /></button>
                                        <button onClick={async () => {
                                            setIsProcessing(true)
                                            await removeSupportType(type)
                                            setDeletingSupportType(null)
                                            setIsProcessing(false)
                                            addToast(`${type} removed`, 'info')
                                        }} style={{ background: 'white', border: 'none', color: '#ff0055', borderRadius: '4px', padding: '2px 8px', fontSize: '0.7rem', fontWeight: 900, cursor: 'pointer' }}>Yes</button>
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>

                    <div style={{ display: 'flex', gap: '10px', maxWidth: '400px' }}>
                        <input
                            type="text"
                            placeholder="New Support Type (e.g. Organic)"
                            value={newSupportType}
                            onChange={(e) => setNewSupportType(e.target.value)}
                            className={styles.input}
                            style={{ flex: 1 }}
                        />
                        <button
                            onClick={async () => {
                                if (newSupportType && !isProcessing) {
                                    setIsProcessing(true)
                                    await addSupportType(newSupportType)
                                    setNewSupportType('')
                                    setIsProcessing(false)
                                    addToast(`${newSupportType} added`, 'success')
                                }
                            }}
                            className="btn"
                            disabled={!newSupportType || isProcessing}
                        >
                            {isProcessing ? 'Adding...' : 'Add Type'}
                        </button>
                    </div>
                </section>
            </div>
        </div>
    )
}

'use client'
import { useState, useEffect, useRef } from 'react'
import { useParams, useRouter } from 'next/navigation'
import { createClient } from '@/utils/supabase/client'
import { formatCurrency } from '@/utils/pricingEngine'
import dynamic from 'next/dynamic'
import { Truck, Package, FileText, Eye, Download, ChevronLeft, ChevronDown, Check, Box, Save, X, RefreshCw, Upload, RotateCcw, AlertTriangle } from 'lucide-react'
import { useToastStore } from '@/store/toastStore'
import { getAdminOrderById, updateOrderAdmin, getSignedModelUrl, adminHandleReturnRequest } from '../../actions'
import BackButton from '@/components/BackButton'
import Loader from '@/components/Loader'

const STLViewer = dynamic(() => import('@/components/STLViewer'), { ssr: false, loading: () => <Loader text="Preparing 3D model..." fullPage={false} /> })

const ADMIN_EMAILS_ENV = process.env.NEXT_PUBLIC_ADMIN_EMAILS || 'admin@printhub.com,newadmin@printhub.com'
const ADMINS = ADMIN_EMAILS_ENV.split(',').map(e => e.trim().toLowerCase())

const STATUS_OPTIONS = [
    { value: 'ordered', label: 'Ordered', emoji: '🆕' },
    { value: 'pending_confirmation', label: 'Pending Confirmation', emoji: '🔍' },
    { value: 'payment_confirmed', label: 'Order Confirmed', emoji: '💰' },
    { value: 'processing', label: 'Processing', emoji: '🕐' },
    { value: 'printing', label: 'Printing', emoji: '🖨️' },
    { value: 'completed', label: 'Completed', emoji: '✅' },
    { value: 'shipped', label: 'Shipped', emoji: '📦' },
    { value: 'delivered', label: 'Delivered', emoji: '🏠' },
    { value: 'return_requested', label: 'Return Requested', emoji: '🔄' },
    { value: 'returned', label: 'Returned', emoji: '↩️' },
    { value: 'return_refused', label: 'Return Refused', emoji: '🚫' },
    { value: 'refunded', label: 'Refunded', emoji: '💸' },
    { value: 'cancelled', label: 'Cancelled', emoji: '❌' },
]

const SC: Record<string, { bg: string; border: string; text: string }> = {
    ordered: { bg: 'rgba(0,112,243,0.12)', border: 'rgba(0,112,243,0.35)', text: '#0070f3' },
    pending_confirmation: { bg: 'rgba(255,174,0,0.12)', border: 'rgba(255,174,0,0.35)', text: '#ffae00' },
    payment_confirmed: { bg: 'rgba(57,255,20,0.12)', border: 'rgba(57,255,20,0.35)', text: '#39ff14' },
    processing: { bg: 'rgba(255,174,0,0.12)', border: 'rgba(255,174,0,0.35)', text: '#ffae00' },
    printing: { bg: 'rgba(57,255,20,0.12)', border: 'rgba(57,255,20,0.35)', text: '#39ff14' },
    completed: { bg: 'rgba(0,255,136,0.12)', border: 'rgba(0,255,136,0.35)', text: '#00ff88' },
    shipped: { bg: 'rgba(0,191,255,0.12)', border: 'rgba(0,191,255,0.35)', text: '#00bfff' },
    delivered: { bg: 'rgba(167,139,250,0.12)', border: 'rgba(167,139,250,0.35)', text: '#a78bfa' },
    return_requested: { bg: 'rgba(255,174,0,0.12)', border: 'rgba(255,174,0,0.35)', text: '#ffae00' },
    returned: { bg: 'rgba(57,255,20,0.12)', border: 'rgba(57,255,20,0.35)', text: '#39ff14' },
    return_refused: { bg: 'rgba(255,0,85,0.12)', border: 'rgba(255,0,85,0.35)', text: '#ff0055' },
    refunded: { bg: 'rgba(255,174,0,0.12)', border: 'rgba(255,174,0,0.35)', text: '#ffae00' },
    cancelled: { bg: 'rgba(255,0,85,0.12)', border: 'rgba(255,0,85,0.35)', text: '#ff0055' },
}

function StatusDropdown({ value, onChange }: { value: string; onChange: (v: string) => void }) {
    const [open, setOpen] = useState(false)
    const ref = useRef<HTMLDivElement>(null)
    const current = STATUS_OPTIONS.find(s => s.value === value) || STATUS_OPTIONS[0]
    const sc = SC[value] || SC.processing

    useEffect(() => {
        function onOut(e: MouseEvent) { if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false) }
        document.addEventListener('mousedown', onOut)
        return () => document.removeEventListener('mousedown', onOut)
    }, [])

    return (
        <div ref={ref} style={{ position: 'relative', userSelect: 'none' }}>
            <button
                onClick={() => setOpen(o => !o)}
                style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '10px 16px', borderRadius: '12px', cursor: 'pointer', border: `1px solid ${sc.border}`, background: sc.bg, color: sc.text, fontWeight: 700, fontSize: '0.9rem', width: '100%' }}
            >
                <span>{current.emoji}</span>
                <span style={{ flex: 1, textAlign: 'left' }}>{current.label}</span>
                <ChevronDown size={14} style={{ transform: open ? 'rotate(180deg)' : 'none', transition: 'transform 0.2s', opacity: 0.7 }} />
            </button>
            {open && (
                <div style={{ position: 'absolute', top: 'calc(100% + 8px)', left: 0, right: 0, zIndex: 100, background: '#161b22', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '12px', padding: '6px', boxShadow: '0 16px 48px rgba(0,0,0,0.5)', animation: 'fadeIn 0.1s ease' }}>
                    {STATUS_OPTIONS.map(opt => {
                        const s = SC[opt.value]
                        const isActive = opt.value === value
                        return (
                            <button key={opt.value}
                                onClick={() => { onChange(opt.value); setOpen(false) }}
                                style={{ width: '100%', display: 'flex', alignItems: 'center', gap: '10px', padding: '10px 12px', borderRadius: '8px', border: 'none', cursor: 'pointer', background: isActive ? s.bg : 'transparent', color: isActive ? s.text : 'rgba(255,255,255,0.7)', fontWeight: isActive ? 700 : 400, fontSize: '0.88rem' }}
                                onMouseEnter={e => { if (!isActive) e.currentTarget.style.background = 'rgba(255,255,255,0.05)' }}
                                onMouseLeave={e => { if (!isActive) e.currentTarget.style.background = 'transparent' }}
                            >
                                <span>{opt.emoji}</span>
                                <span style={{ flex: 1, textAlign: 'left' }}>{opt.label}</span>
                                {isActive && <Check size={14} />}
                            </button>
                        )
                    })}
                </div>
            )}
        </div>
    )
}

export default function OrderDetailPage() {
    const { id } = useParams()
    const router = useRouter()
    const supabase = createClient()
    const addToast = useToastStore((state) => state.addToast)

    const [order, setOrder] = useState<any>(null)
    const [loading, setLoading] = useState(true)
    const [updating, setUpdating] = useState(false)
    const [activeFile, setActiveFile] = useState<any>(null) // For 3D preview
    const [track, setTrack] = useState('')
    const [isEditingTrack, setIsEditingTrack] = useState(false)
    const [paymentProofUrl, setPaymentProofUrl] = useState<string | null>(null)
    const [adminReturnNote, setAdminReturnNote] = useState('')
    const [handlingReturn, setHandlingReturn] = useState(false)

    // Viewer settings
    const [showCrossSection, setShowCrossSection] = useState(false)
    const [crossSectionHeight, setCrossSectionHeight] = useState(50)
    const [crossSectionAxis, setCrossSectionAxis] = useState<'x' | 'y' | 'z'>('y')
    const [autoRotate, setAutoRotate] = useState(true)
    const [showWireframe, setShowWireframe] = useState(false)

    useEffect(() => {
        const checkAdmin = async () => {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user || !ADMINS.includes(user.email?.toLowerCase() || '')) {
                router.push('/')
                return
            }
            fetchOrder()
        }
        checkAdmin()
    }, [id])

    const fetchOrder = async () => {
        setLoading(true)
        const { data, error } = await getAdminOrderById(id as string)
        setLoading(false)
        if (error) {
            addToast('Failed to load order', 'error')
            router.push('/admin/orders')
        } else {
            setOrder(data)
            setTrack(data.tracking_number || '')
            setAdminReturnNote(data.admin_return_note || '')
            if (data.order_items?.length > 0) {
                setActiveFile(data.order_items[0])
            }
            // Find payment proof if exists
            fetchPaymentProof(data.id)

            // Resolve signed URLs for all items if they are paths
            if (data.order_items) {
                const enrichedItems = await Promise.all(data.order_items.map(async (item: any) => {
                    if (item.file_url && !item.file_url.startsWith('http') && !item.file_url.startsWith('blob:')) {
                        const res = await getSignedModelUrl(item.file_url)
                        if (res.data) {
                            return { ...item, original_path: item.file_url, file_url: res.data }
                        }
                    }
                    return item
                }))
                setOrder({ ...data, order_items: enrichedItems })
                if (enrichedItems.length > 0) setActiveFile(enrichedItems[0])
            }
        }
    }

    const fetchPaymentProof = async (orderId: string) => {
        try {
            const { data: files, error } = await supabase.storage.from('prints').list('payments')
            if (error) {
                console.error('Error listing payments:', error)
                return
            }
            if (files) {
                const proofFile = files.find(f => f.name.startsWith(orderId))
                if (proofFile) {
                    const { data: { publicUrl } } = supabase.storage.from('prints').getPublicUrl(`payments/${proofFile.name}`)
                    setPaymentProofUrl(publicUrl)
                }
            }
        } catch (err) {
            console.error('Unexpected error fetching payment proof:', err)
        }
    }

    const updateStatus = async (newStatus: string) => {
        setOrder((prev: any) => ({ ...prev, status: newStatus }))
        const { error } = await updateOrderAdmin(id as string, { status: newStatus })
        if (error) {
            addToast('Status update failed', 'error')
            fetchOrder() // Revert
        } else {
            addToast(`Order marked as ${newStatus}`, 'success')
        }
    }

    const handleReturnAction = async (decision: 'accept' | 'refuse') => {
        setHandlingReturn(true)
        try {
            const res = await adminHandleReturnRequest(id as string, decision, adminReturnNote)
            if (res.error) throw new Error(res.error)

            addToast(`Return request ${decision === 'accept' ? 'accepted' : 'refused'}`, 'success')
            fetchOrder()
        } catch (err: any) {
            addToast(err.message || 'Action failed', 'error')
        } finally {
            setHandlingReturn(false)
        }
    }

    const saveTracking = async () => {
        setUpdating(true)
        const { error } = await updateOrderAdmin(id as string, { tracking_number: track })
        setUpdating(false)
        if (!error) {
            addToast('Tracking ID updated', 'success')
            setIsEditingTrack(false)
            setOrder((prev: any) => ({ ...prev, tracking_number: track }))
        } else {
            addToast('Update failed', 'error')
        }
    }

    const handleDownloadSTL = async (e: React.MouseEvent, url: string, fileName: string) => {
        e.stopPropagation()
        try {
            const response = await fetch(url)
            if (!response.ok) throw new Error('Download failed')

            const blob = await response.blob()
            const blobUrl = URL.createObjectURL(blob)

            const a = document.createElement('a')
            a.href = blobUrl
            a.download = fileName
            document.body.appendChild(a)
            a.click()
            document.body.removeChild(a)
            URL.revokeObjectURL(blobUrl)

            addToast('Download started', 'success')
        } catch (error) {
            console.error('Download error:', error)
            addToast('Failed to download file', 'error')
        }
    }

    if (loading) return <Loader text="Fetching order details..." />
    if (!order) return <Loader text="Order not found." />

    const addr = typeof order.shipping_address === 'string' ? JSON.parse(order.shipping_address) : order.shipping_address
    const items = order.order_items || []
    const sc = SC[order.status] || SC.processing

    return (
        <div style={{ color: 'white', maxWidth: '1400px', margin: '0 auto', padding: '20px' }}>

            {/* Header Section */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px', marginBottom: '32px' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
                    <BackButton href="/admin/orders" />
                    <h1 className="title-gradient" style={{ margin: 0, fontSize: '1.8rem', lineHeight: '1' }}>Order Details</h1>
                </div>
                <p style={{ margin: '0 0 0 60px', color: 'rgba(255,255,255,0.5)', fontSize: '0.95rem' }}>
                    Manage print specifications, customer fulfillment, and delivery logistics.
                </p>
            </div>

            <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(350px, 1fr))',
                gap: '24px',
                alignItems: 'start'
            }}>

                {/* Main Visual & Control Cluster */}
                <div style={{ gridColumn: 'span 2', display: 'flex', flexDirection: 'column', gap: '24px' }}>

                    {/* 3D Viewer Section */}
                    <div style={{
                        aspectRatio: '16/10', background: '#0d1117', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.1)',
                        overflow: 'hidden', position: 'relative', boxShadow: '0 20px 50px rgba(0,0,0,0.5)'
                    }}>
                        {activeFile?.file_url ? (
                            <>
                                <div style={{ position: 'absolute', top: 0, left: 0, right: 0, padding: '12px', display: 'flex', gap: '8px', zIndex: 10, background: 'linear-gradient(to bottom, rgba(0,0,0,0.8), transparent)' }}>
                                    <button
                                        onClick={() => setShowCrossSection(!showCrossSection)}
                                        style={{ background: showCrossSection ? 'rgba(57,255,20,0.2)' : 'rgba(255,255,255,0.1)', border: showCrossSection ? '1px solid #39ff14' : '1px solid rgba(255,255,255,0.2)', color: showCrossSection ? '#39ff14' : 'white', padding: '4px 10px', borderRadius: '6px', fontSize: '0.75rem', cursor: 'pointer', zIndex: 10 }}
                                    >
                                        Cross Section
                                    </button>
                                    <button
                                        onClick={() => setAutoRotate(!autoRotate)}
                                        style={{ background: autoRotate ? 'rgba(57,255,20,0.2)' : 'rgba(255,255,255,0.1)', border: autoRotate ? '1px solid #39ff14' : '1px solid rgba(255,255,255,0.2)', color: autoRotate ? '#39ff14' : 'white', padding: '4px 10px', borderRadius: '6px', fontSize: '0.75rem', cursor: 'pointer', zIndex: 10 }}
                                    >
                                        Rotate
                                    </button>
                                    <button
                                        onClick={() => setShowWireframe(!showWireframe)}
                                        style={{ background: showWireframe ? 'rgba(57,255,20,0.2)' : 'rgba(255,255,255,0.1)', border: showWireframe ? '1px solid #39ff14' : '1px solid rgba(255,255,255,0.2)', color: showWireframe ? '#39ff14' : 'white', padding: '4px 10px', borderRadius: '6px', fontSize: '0.75rem', cursor: 'pointer', zIndex: 10 }}
                                    >
                                        Mesh
                                    </button>
                                </div>
                                {showCrossSection && (
                                    <div style={{ position: 'absolute', top: '45px', left: '12px', right: '12px', zIndex: 10, background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(8px)', padding: '10px', borderRadius: '8px', border: '1px solid rgba(255,255,255,0.1)' }}>
                                        <div style={{ display: 'flex', gap: '8px', marginBottom: '8px' }}>
                                            {(['x', 'y', 'z'] as const).map(axis => (
                                                <button
                                                    key={axis}
                                                    onClick={() => setCrossSectionAxis(axis)}
                                                    style={{ flex: 1, background: crossSectionAxis === axis ? 'rgba(57,255,20,0.2)' : 'rgba(255,255,255,0.1)', border: crossSectionAxis === axis ? '1px solid #39ff14' : '1px solid rgba(255,255,255,0.2)', color: crossSectionAxis === axis ? '#39ff14' : 'white', padding: '4px 0', borderRadius: '4px', fontSize: '0.7rem', textTransform: 'uppercase', cursor: 'pointer' }}
                                                >
                                                    {axis}-Axis
                                                </button>
                                            ))}
                                        </div>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                                            <input
                                                type="range"
                                                min="0"
                                                max="100"
                                                value={crossSectionHeight}
                                                onChange={(e) => setCrossSectionHeight(parseInt(e.target.value))}
                                                style={{ flex: 1, cursor: 'pointer' }}
                                            />
                                            <span style={{ fontSize: '0.75rem', fontWeight: 600 }}>{crossSectionHeight}%</span>
                                        </div>
                                    </div>
                                )}
                                <STLViewer
                                    url={activeFile.file_url}
                                    color={activeFile.color || '#39ff14'}
                                    autoRotate={autoRotate}
                                    height={500}
                                    showCrossSection={showCrossSection}
                                    crossSectionHeight={crossSectionHeight}
                                    crossSectionAxis={crossSectionAxis}
                                    wireframe={showWireframe}
                                />
                                <div style={{ position: 'absolute', bottom: '20px', left: '20px', background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(10px)', padding: '10px 16px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.1)', pointerEvents: 'none' }}>
                                    <div style={{ fontSize: '0.7rem', opacity: 0.5, textTransform: 'uppercase', marginBottom: '2px' }}>Viewing File</div>
                                    <div style={{ fontWeight: 700, fontSize: '0.9rem' }}>{activeFile.file_name}</div>
                                </div>
                            </>
                        ) : (
                            <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'rgba(255,255,255,0.2)' }}>
                                <Box size={48} />
                            </div>
                        )}
                    </div>

                    {/* Configuration Details Section */}
                    <div style={{ background: 'rgba(255,255,255,0.02)', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.05)', padding: '32px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '24px' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                <FileText size={24} color="#39ff14" />
                                <h3 style={{ margin: 0, fontSize: '1.4rem' }}>Print Configuration Details</h3>
                            </div>
                            <span style={{ padding: '4px 12px', background: 'rgba(57,255,20,0.1)', color: '#39ff14', borderRadius: '20px', fontSize: '0.8rem', fontWeight: 700 }}>
                                {items.length} {items.length === 1 ? 'FILE' : 'FILES'}
                            </span>
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr', gap: '20px' }}>
                            {items.map((item: any, idx: number) => {
                                const isActive = activeFile?.id === item.id

                                const supportType = item.support_type || 'none'
                                const supportMaterial = item.support_material || ''
                                const brimR = typeof item.brim === 'boolean' ? item.brim : false
                                const brandR = item.brand || 'Standard'
                                const infillPatternR = item.infill_pattern || 'Grid'
                                const amsColorsR = item.ams_colors || [item.color]
                                const amsBrandsR = item.ams_brands || []

                                return (
                                    <div
                                        key={idx}
                                        onClick={() => setActiveFile(item)}
                                        style={{
                                            display: 'grid',
                                            gridTemplateColumns: 'auto 1fr auto',
                                            gap: '24px',
                                            padding: '24px',
                                            background: isActive ? 'rgba(57,255,20,0.04)' : 'rgba(255,255,255,0.02)',
                                            borderRadius: '20px',
                                            border: isActive ? '1px solid #39ff14' : '1px solid rgba(255,255,255,0.05)',
                                            transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                                            cursor: 'pointer',
                                            position: 'relative',
                                            overflow: 'hidden'
                                        }}
                                    >
                                        {isActive && <div style={{ position: 'absolute', top: 0, left: 0, width: '4px', height: '100%', background: '#39ff14' }} />}

                                        {/* Icon/Color */}
                                        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '12px' }}>
                                            <div style={{
                                                width: '56px', height: '56px', borderRadius: '16px',
                                                background: 'rgba(0,0,0,0.3)', border: '1px solid rgba(255,255,255,0.1)',
                                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                                boxShadow: isActive ? '0 0 20px rgba(57,255,20,0.1)' : 'none'
                                            }}>
                                                <Box size={28} color={isActive ? '#39ff14' : 'rgba(255,255,255,0.3)'} />
                                            </div>
                                            <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap' }}>
                                                {amsColorsR.map((c: string, i: number) => (
                                                    <div key={i} style={{
                                                        width: '20px', height: '20px', borderRadius: '50%',
                                                        background: c, border: '2px solid white',
                                                        boxShadow: '0 2px 5px rgba(0,0,0,0.3)'
                                                    }} title={`Slot ${i + 1}: ${c}`} />
                                                ))}
                                            </div>
                                        </div>

                                        {/* Main Info */}
                                        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                                            <div style={{ fontWeight: 800, fontSize: '1.2rem', color: isActive ? '#39ff14' : 'white' }}>{item.file_name}</div>

                                            <div style={{
                                                display: 'grid',
                                                gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))',
                                                gap: '12px'
                                            }}>
                                                <div style={{ background: 'rgba(255,255,255,0.03)', padding: '12px 14px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
                                                    <div style={{ fontSize: '0.65rem', opacity: 0.4, textTransform: 'uppercase', marginBottom: '2px' }}>Material</div>
                                                    <div style={{ fontWeight: 700, fontSize: '0.9rem' }}>{item.material}</div>
                                                </div>
                                                <div style={{ background: 'rgba(255,255,255,0.03)', padding: '12px 14px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
                                                    <div style={{ fontSize: '0.65rem', opacity: 0.4, textTransform: 'uppercase', marginBottom: '2px' }}>Brand(s)</div>
                                                    <div style={{ fontWeight: 700, fontSize: '0.9rem', color: '#39ff14' }}>
                                                        {amsBrandsR.length > 0 ? Array.from(new Set(amsBrandsR)).join(', ') : brandR}
                                                    </div>
                                                </div>
                                                <div style={{ background: 'rgba(255,255,255,0.03)', padding: '12px 14px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
                                                    <div style={{ fontSize: '0.65rem', opacity: 0.4, textTransform: 'uppercase', marginBottom: '2px' }}>Resolution</div>
                                                    <div style={{ fontWeight: 700, fontSize: '0.9rem' }}>{item.layer_height}mm</div>
                                                </div>
                                                <div style={{ background: 'rgba(255,255,255,0.03)', padding: '12px 14px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
                                                    <div style={{ fontSize: '0.65rem', opacity: 0.4, textTransform: 'uppercase', marginBottom: '2px' }}>Infill density</div>
                                                    <div style={{ fontWeight: 700, fontSize: '0.9rem' }}>{item.infill}%</div>
                                                </div>
                                                <div style={{ background: 'rgba(255,255,255,0.03)', padding: '12px 14px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
                                                    <div style={{ fontSize: '0.65rem', opacity: 0.4, textTransform: 'uppercase', marginBottom: '2px' }}>Infill Pattern</div>
                                                    <div style={{ fontWeight: 700, fontSize: '0.9rem' }}>{infillPatternR}</div>
                                                </div>
                                                <div style={{ background: 'rgba(255,255,255,0.03)', padding: '12px 14px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
                                                    <div style={{ fontSize: '0.65rem', opacity: 0.4, textTransform: 'uppercase', marginBottom: '2px' }}>Support Type</div>
                                                    <div style={{ fontWeight: 700, fontSize: '0.9rem', textTransform: 'capitalize' }}>{supportType === 'none' ? 'None' : supportType}</div>
                                                </div>
                                                <div style={{ background: 'rgba(255,255,255,0.03)', padding: '12px 14px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
                                                    <div style={{ fontSize: '0.65rem', opacity: 0.4, textTransform: 'uppercase', marginBottom: '2px' }}>Brim Required</div>
                                                    <div style={{ fontWeight: 700, fontSize: '0.9rem', color: brimR ? '#a78bfa' : 'white' }}>
                                                        {brimR ? `Yes` : 'No'}
                                                    </div>
                                                </div>
                                                <div style={{ background: 'rgba(255,255,255,0.03)', padding: '12px 14px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
                                                    <div style={{ fontSize: '0.65rem', opacity: 0.4, textTransform: 'uppercase', marginBottom: '2px' }}>Quantity</div>
                                                    <div style={{ fontWeight: 700, fontSize: '0.9rem' }}>×{item.quantity || 1}</div>
                                                </div>
                                            </div>

                                            <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
                                            </div>
                                        </div>

                                        {/* Actions */}
                                        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', justifyContent: 'center', gap: '12px' }}>
                                            <div style={{ textAlign: 'right' }}>
                                                <div style={{ fontSize: '0.7rem', opacity: 0.4, textTransform: 'uppercase' }}>Item Total</div>
                                                <div style={{ fontWeight: 800, fontSize: '1.4rem', color: '#39ff14' }}>{formatCurrency(item.price * (item.quantity || 1))}</div>
                                            </div>
                                            <button
                                                onClick={(e) => handleDownloadSTL(e, item.file_url, item.file_name)}
                                                style={{
                                                    background: '#39ff14', color: 'black', border: 'none', borderRadius: '10px',
                                                    padding: '8px 16px', fontWeight: 700, fontSize: '0.85rem',
                                                    cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px',
                                                    transition: 'all 0.2s'
                                                }}
                                                onMouseEnter={e => e.currentTarget.style.transform = 'translateY(-2px)'}
                                                onMouseLeave={e => e.currentTarget.style.transform = 'translateY(0)'}
                                            >
                                                <Download size={16} /> Download STL
                                            </button>
                                        </div>
                                    </div>
                                )
                            })}
                        </div>
                    </div>
                </div>

                {/* Right Column Grouping: Summary, Customer, Payments, Returns */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>

                    {/* Status & Summary */}
                    <div style={{ background: 'rgba(255,255,255,0.02)', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.05)', padding: '24px' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '20px' }}>
                            <div>
                                <div style={{ fontSize: '0.75rem', opacity: 0.4, textTransform: 'uppercase', letterSpacing: '1px', fontWeight: 800, marginBottom: '4px' }}>ORDER ID</div>
                                <h2 style={{ margin: 0, fontSize: '1.4rem', fontFamily: 'monospace' }}>#{order.id.slice(0, 12).toUpperCase()}</h2>
                                <div style={{ fontSize: '0.85rem', opacity: 0.5, marginTop: '4px' }}>Date: {new Date(order.created_at).toLocaleString()}</div>
                            </div>
                        </div>

                        <div style={{ marginBottom: '24px' }}>
                            <div style={{ fontSize: '0.75rem', opacity: 0.4, textTransform: 'uppercase', fontWeight: 800, marginBottom: '10px' }}>PROGRESS STATUS</div>
                            <StatusDropdown value={order.status} onChange={updateStatus} />
                        </div>

                        <div style={{ borderTop: '1px solid rgba(255,255,255,0.06)', paddingTop: '20px' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                                <span style={{ opacity: 0.5 }}>Subtotal</span>
                                <span>{formatCurrency(order.total_amount - (order.shipping_cost || 0))}</span>
                            </div>
                            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '12px' }}>
                                <span style={{ opacity: 0.5 }}>Shipping ({order.delivery_method})</span>
                                <span>{formatCurrency(order.shipping_cost || 0)}</span>
                            </div>
                            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '1.4rem' }}>
                                <span style={{ fontWeight: 800 }}>Total</span>
                                <span style={{ fontWeight: 800, color: '#39ff14' }}>{formatCurrency(order.total_amount)}</span>
                            </div>
                        </div>
                    </div>

