            </button>
            {open && (
                <div style={{ position: 'absolute', top: 'calc(100% + 8px)', right: 0, zIndex: 300, background: '#0d1117', border: '1px solid rgba(255,255,255,0.12)', borderRadius: '12px', padding: '8px', minWidth: '200px', boxShadow: '0 16px 48px rgba(0,0,0,0.7)', animation: 'fadeIn 0.12s ease', display: 'flex', flexDirection: 'column', gap: '4px' }}>
                    {options.map(opt => {
                        const s = SC[opt.value] || SC.processing
                        const isActive = value.includes(opt.value)
                        return (
                            <button key={opt.value}
                                onClick={() => handleToggle(opt.value)}
                                style={{ width: '100%', display: 'flex', alignItems: 'center', gap: '10px', padding: '8px 12px', borderRadius: '8px', border: 'none', cursor: 'pointer', background: isActive ? s.bg : 'transparent', color: isActive ? s.text : 'rgba(255,255,255,0.75)', fontWeight: isActive ? 700 : 400, fontSize: '0.85rem', textAlign: 'left' }}
                                onMouseEnter={e => { if (!isActive) e.currentTarget.style.background = 'rgba(255,255,255,0.06)' }}
                                onMouseLeave={e => { if (!isActive) e.currentTarget.style.background = 'transparent' }}
                            >
                                <div style={{ width: '16px', height: '16px', borderRadius: '4px', border: `1px solid ${isActive ? s.border : 'rgba(255,255,255,0.2)'}`, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, background: isActive ? s.bg : 'transparent' }}>
                                    {isActive && <Check size={12} />}
                                </div>
                                <span>{opt.emoji}</span>
                                <span style={{ flex: 1 }}>{opt.label}</span>
                            </button>
                        )
                    })}
                </div>
            )}
        </div>
    )
}

// ──── Date Range Dropdown ────
function DateRangeFilter({ startDate, endDate, onStartChange, onEndChange }: { startDate: string, endDate: string, onStartChange: (v: string) => void, onEndChange: (v: string) => void }) {
    const [open, setOpen] = useState(false)
    const ref = useRef<HTMLDivElement>(null)

    useEffect(() => {
        function onOut(e: MouseEvent) { if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false) }
        document.addEventListener('mousedown', onOut)
        return () => document.removeEventListener('mousedown', onOut)
    }, [])

    const hasFilter = startDate || endDate

    return (
        <div ref={ref} style={{ position: 'relative', userSelect: 'none', flexShrink: 0 }}>
            <button
                onClick={() => setOpen(o => !o)}
                style={{ display: 'flex', alignItems: 'center', gap: '7px', padding: '8px 14px', borderRadius: '10px', cursor: 'pointer', border: '1px solid rgba(255,255,255,0.1)', background: 'rgba(255,255,255,0.05)', color: 'white', fontWeight: 600, fontSize: '0.85rem', whiteSpace: 'nowrap' }}
            >
                <Calendar size={14} style={{ opacity: 0.7 }} />
                <span>{hasFilter ? 'Date Filtered' : 'Filter Date'}</span>
                <ChevronDown size={14} style={{ transform: open ? 'rotate(180deg)' : 'none', transition: 'transform 0.2s', opacity: 0.7 }} />
            </button>
            {open && (
                <div style={{ position: 'absolute', top: 'calc(100% + 8px)', right: 0, zIndex: 300, background: '#0d1117', border: '1px solid rgba(255,255,255,0.12)', borderRadius: '12px', padding: '16px', minWidth: '220px', boxShadow: '0 16px 48px rgba(0,0,0,0.7)', animation: 'fadeIn 0.12s ease', display: 'flex', flexDirection: 'column', gap: '12px' }}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                        <label style={{ fontSize: '0.75rem', opacity: 0.6, fontWeight: 700, textTransform: 'uppercase' }}>From</label>
                        <input type="date" value={startDate} onChange={e => onStartChange(e.target.value)} style={{ padding: '8px 10px', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white', outline: 'none', fontFamily: 'inherit', colorScheme: 'dark' }} />
                    </div>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                        <label style={{ fontSize: '0.75rem', opacity: 0.6, fontWeight: 700, textTransform: 'uppercase' }}>To</label>
                        <input type="date" value={endDate} onChange={e => onEndChange(e.target.value)} style={{ padding: '8px 10px', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white', outline: 'none', fontFamily: 'inherit', colorScheme: 'dark' }} />
                    </div>
                    {hasFilter && (
                        <button
                            onClick={() => { onStartChange(''); onEndChange(''); setOpen(false); }}
                            style={{ padding: '8px', borderRadius: '8px', background: 'rgba(255,0,85,0.1)', color: '#ff0055', border: '1px solid rgba(255,0,85,0.2)', fontSize: '0.8rem', cursor: 'pointer', fontWeight: 700, marginTop: '4px' }}
                        >
                            Clear Date Filter
                        </button>
                    )}
                </div>
            )}
        </div>
    )
}

// ──── Main Page ────
export default function AdminOrdersPage() {
    const router = useRouter()
    const supabase = createClient()
    const addToast = useToastStore((state) => state.addToast)
    const [user, setUser] = useState<User | null>(null)
    const [orders, setOrders] = useState<any[]>([])
    const [loading, setLoading] = useState(true)
    const [fetching, setFetching] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const [activeSearch, setActiveSearch] = useState('')
    const [historySearch, setHistorySearch] = useState('')
    const [activeStatusFilters, setActiveStatusFilters] = useState<string[]>([])
    const [historyStatusFilters, setHistoryStatusFilters] = useState<string[]>([])
    const [activeStartDate, setActiveStartDate] = useState('')
    const [activeEndDate, setActiveEndDate] = useState('')
    const [historyStartDate, setHistoryStartDate] = useState('')
    const [historyEndDate, setHistoryEndDate] = useState('')
    const [deletingId, setDeletingId] = useState<string | null>(null)

    useEffect(() => {
        const checkUser = async () => {
            const { data: { user } } = await supabase.auth.getUser()
            setUser(prev => prev?.id === user?.id ? prev : user)
            setLoading(false)
            if (!user || !ADMINS.includes(user.email?.toLowerCase() || '')) router.push('/')
        }
        checkUser()
    }, [router])

    useEffect(() => {
        if (ADMINS.includes(user?.email?.toLowerCase() || '')) {
            fetchOrders()
            const ch = supabase.channel('admin-orders-rt')
                .on('postgres_changes', { event: '*', schema: 'public', table: 'orders' }, fetchOrders)
                .subscribe()
            return () => { supabase.removeChannel(ch) }
        }
    }, [user])

    const fetchOrders = async () => {
        setFetching(true)
        setError(null)
        const { data, error } = await getAdminOrders() as any
        setFetching(false)
        if (error) { setError(error); addToast('Failed to load orders', 'error') }
        else if (data) setOrders(data)
    }

    const handleDeleteOrder = async (orderId: string, e: React.MouseEvent) => {
        e.stopPropagation()
        const orderToDelete = orders.find(o => o.id === orderId)

        try {
            // 1. Delete associated files from Storage
            if (orderToDelete && orderToDelete.order_items) {
                const filesToDelete: string[] = []
                orderToDelete.order_items.forEach((item: any) => {
                    if (item.file_url) {
                        if (item.file_url.startsWith('http')) {
                            try {
                                const url = new URL(item.file_url)
                                const pathParts = url.pathname.split('/')
                                const fileName = decodeURIComponent(pathParts[pathParts.length - 1])
                                if (fileName) filesToDelete.push(fileName)
                            } catch (e) { }
                        } else {
                            filesToDelete.push(item.file_url)
                        }
                    }
                })

                if (filesToDelete.length > 0) {
                    await supabase.storage
                        .from('prints')
                        .remove(filesToDelete)
                }
            }

            // 2. Delete from Database
            const { error } = await supabase
                .from('orders')
                .delete()
                .eq('id', orderId)

            if (error) throw error

            setOrders(orders.filter(order => order.id !== orderId))
            addToast('Order successfully purged.', 'success')
            setDeletingId(null)
        } catch (error) {
            addToast('Failed to purge order.', 'error')
        }
    }

    if (loading || !user) return <Loader text="Verifying permissions..." />
    if (fetching && orders.length === 0) return <Loader text="Loading orders..." />

    const filterOrders = (list: any[], query: string, statuses: string[], startDate: string, endDate: string) => {
        let filtered = list;
        if (statuses.length > 0) {
            filtered = filtered.filter(o => statuses.includes(o.status));
        }

        if (startDate || endDate) {
            filtered = filtered.filter(o => {
                const orderDate = new Date(o.created_at)
                orderDate.setHours(0, 0, 0, 0)

                if (startDate) {
                    const start = new Date(startDate)
                    start.setHours(0, 0, 0, 0)
                    if (orderDate < start) return false
                }

                if (endDate) {
                    const end = new Date(endDate)
                    end.setHours(0, 0, 0, 0)
                    if (orderDate > end) return false
                }

                return true
            })
        }

        if (!query) return filtered;
        const q = query.toLowerCase()
        return filtered.filter(o => {
            const addr = parseAddress(o.shipping_address)
            const details = o.user_details as any
            const customerName = details?.full_name?.toLowerCase() || addr?.full_name?.toLowerCase() || ''
            const orderId = o.id.toLowerCase()
            return customerName.includes(q) || orderId.includes(q)
        })
    }

    const activeOrders = filterOrders(orders.filter(o => !HISTORY_STATUSES.includes(o.status)), activeSearch, activeStatusFilters, activeStartDate, activeEndDate)
    const historyOrders = filterOrders(orders.filter(o => HISTORY_STATUSES.includes(o.status)), historySearch, historyStatusFilters, historyStartDate, historyEndDate)

    return (
        <div className="container" style={{ maxWidth: '100%', padding: 0 }}>

            {/* Header */}
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '32px' }}>
                <h1 className="title-gradient" style={{ margin: 0 }}>Order Management</h1>
                <button onClick={fetchOrders} disabled={fetching}
                    style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '10px 20px', borderRadius: '10px', border: '1px solid rgba(255,255,255,0.1)', background: 'rgba(255,255,255,0.05)', color: 'white', cursor: 'pointer', fontSize: '0.9rem' }}
                >
                    <RefreshCw size={15} style={{ animation: fetching ? 'spin 0.8s linear infinite' : 'none' }} />
                    {fetching ? 'Refreshing…' : 'Refresh'}
                </button>
            </div>

            {error && (
                <div style={{ padding: '16px', background: 'rgba(255,0,85,0.1)', border: '1px solid #ff0055', borderRadius: '12px', marginBottom: '24px', color: '#ff0055' }}>
                    <strong>Error:</strong> {error}
                    <button onClick={fetchOrders} style={{ marginLeft: '12px', background: '#ff0055', color: 'white', border: 'none', padding: '4px 12px', borderRadius: '6px', cursor: 'pointer' }}>Retry</button>
                </div>
            )}

            {/* ──── ACTIVE QUEUE ──── */}
            <section className={styles.section} style={{ marginBottom: '40px', position: 'relative', zIndex: 20 }}>
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '24px', flexWrap: 'wrap', gap: '16px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                            <Package color="#39ff14" size={24} />
                            <h2 style={{ margin: 0, fontSize: '1.4rem' }}>Active Queue</h2>
                        </div>
                        <span style={{ padding: '4px 14px', borderRadius: '20px', background: 'rgba(57,255,20,0.1)', border: '1px solid rgba(57,255,20,0.2)', color: '#39ff14', fontSize: '0.85rem', fontWeight: 700 }}>
                            {activeOrders.length} order{activeOrders.length !== 1 ? 's' : ''}
                        </span>
                    </div>

                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1, justifyContent: 'flex-end', minWidth: '300px' }}>
                        <div style={{ position: 'relative', flex: 1, maxWidth: '300px' }}>
                            <Search size={15} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', opacity: 0.4 }} />
                            <input
                                type="text"
                                placeholder="Search ID or Customer..."
                                value={activeSearch}
                                onChange={(e) => setActiveSearch(e.target.value)}
                                style={{ width: '100%', padding: '9px 12px 9px 36px', borderRadius: '10px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white', fontSize: '0.85rem' }}
                            />
                        </div>

                        <DateRangeFilter
                            startDate={activeStartDate}
                            endDate={activeEndDate}
                            onStartChange={setActiveStartDate}
                            onEndChange={setActiveEndDate}
                        />

                        <MultiStatusFilter
                            value={activeStatusFilters}
                            onChange={setActiveStatusFilters}
                            options={STATUS_OPTIONS.filter(o => !HISTORY_STATUSES.includes(o.value))}
                        />
                    </div>
                </div>

                {activeOrders.length === 0 ? (
                    <div style={{ textAlign: 'center', padding: '60px 20px', opacity: 0.4 }}>
                        <Package size={48} style={{ marginBottom: '16px' }} />
                        <p style={{ margin: 0 }}>Queue is clear — no active orders</p>
                    </div>
                ) : (
                    <div style={{
                        display: 'flex', flexDirection: 'column', gap: '12px',
                    }}>
                        {activeOrders.map(order => {
                            const addr = parseAddress(order.shipping_address)
                            const items: any[] = order.order_items || []
                            const sc = SC[order.status] || SC.processing

                            return (
                                <div
                                    key={order.id}
                                    onClick={() => router.push(`/admin/orders/${order.id}`)}
                                    style={{
                                        cursor: 'pointer', display: 'flex', alignItems: 'center', padding: '16px 20px', gap: '16px',
                                        background: 'rgba(255,255,255,0.02)', border: `1px solid ${sc.border}`, borderRadius: '18px',
                                        transition: 'all 0.2s', position: 'relative', overflow: 'hidden'
                                    }}
                                    onMouseEnter={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.04)'; e.currentTarget.style.transform = 'translateY(-2px)' }}
                                    onMouseLeave={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.02)'; e.currentTarget.style.transform = 'none' }}
                                >
                                    <div style={{ width: '42px', height: '42px', borderRadius: '14px', flexShrink: 0, background: `linear-gradient(135deg,${sc.text}33,${sc.text}11)`, border: `1px solid ${sc.border}`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.1rem', fontWeight: 800, color: sc.text }}>
                                        {currentStatusEmoji(order.status)}
                                    </div>
                                    <div style={{ flex: 1, minWidth: 0 }}>
                                        <div style={{ fontWeight: 700, fontSize: '1rem', color: 'white', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                                            {order.user_details?.full_name || addr?.full_name || 'Unknown Customer'}
                                        </div>
                                        <div style={{ fontSize: '0.78rem', opacity: 0.45, marginTop: '2px' }}>
                                            <span style={{ fontFamily: 'monospace', fontWeight: 600 }}>#{order.id.slice(0, 8).toUpperCase()}</span> · {items.length} file{items.length !== 1 ? 's' : ''} · {new Date(order.created_at).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' })}
                                        </div>
                                    </div>
                                    <div style={{ textAlign: 'right', flexShrink: 0 }}>
                                        <div style={{ fontWeight: 800, fontSize: '1.1rem', color: 'white' }}>{formatCurrency(order.total_amount)}</div>
                                        <span style={{ fontSize: '0.7rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.5px', color: sc.text }}>{order.status}</span>
                                    </div>
                                    <div style={{ opacity: 0.2 }}>
                                        <ChevronDown size={18} style={{ transform: 'rotate(-90deg)' }} />
                                    </div>
                                </div>
                            )
                        })}
                    </div>
                )}
            </section>

            {/* ──── ORDER HISTORY ──── */}
            <section className={styles.section} style={{ position: 'relative', zIndex: 10 }}>
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '24px', flexWrap: 'wrap', gap: '16px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                            <Archive color="rgba(255,255,255,0.5)" size={24} />
                            <h2 style={{ margin: 0, color: 'rgba(255,255,255,0.7)', fontSize: '1.4rem' }}>Order History</h2>
                        </div>
                        <span style={{ padding: '4px 14px', borderRadius: '20px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.5)', fontSize: '0.85rem', fontWeight: 700 }}>
                            {historyOrders.length} order{historyOrders.length !== 1 ? 's' : ''}
                        </span>
                    </div>

                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flex: 1, justifyContent: 'flex-end', minWidth: '300px' }}>
                        <div style={{ position: 'relative', flex: 1, maxWidth: '300px' }}>
                            <Search size={15} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', opacity: 0.3 }} />
                            <input
                                type="text"
                                placeholder="Search ID or Customer..."
                                value={historySearch}
                                onChange={(e) => setHistorySearch(e.target.value)}
                                style={{ width: '100%', padding: '9px 12px 9px 36px', borderRadius: '10px', background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.08)', color: 'rgba(255,255,255,0.7)', fontSize: '0.85rem' }}
                            />
                        </div>

                        <DateRangeFilter
                            startDate={historyStartDate}
                            endDate={historyEndDate}
                            onStartChange={setHistoryStartDate}
                            onEndChange={setHistoryEndDate}
                        />

                        <MultiStatusFilter
                            value={historyStatusFilters}
                            onChange={setHistoryStatusFilters}
                            options={STATUS_OPTIONS.filter(o => HISTORY_STATUSES.includes(o.value))}
                        />
                    </div>
                </div>
                <div className={styles.tableContainer}>
                    <table className={styles.table} style={{ opacity: 0.85 }}>
                        <thead>
                            <tr>
                                <th>Order ID</th><th>Date</th><th>Customer</th><th>Files</th><th>Total</th><th>Status</th><th>Tracking</th><th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {historyOrders.length === 0 ? (
                                <tr><td colSpan={8} style={{ textAlign: 'center', padding: '32px', opacity: 0.4 }}>No completed orders yet</td></tr>
                            ) : historyOrders.map(order => {
                                const addr = parseAddress(order.shipping_address)
                                const items: any[] = order.order_items || []
                                const sc = SC[order.status] || SC.delivered
                                return (
                                    <Fragment key={order.id}>
                                        <tr onClick={() => router.push(`/admin/orders/${order.id}`)} style={{ cursor: 'pointer' }}>
                                            <td style={{ fontFamily: 'monospace', fontSize: '0.84rem' }} title={order.id}>#{order.id.slice(0, 8).toUpperCase()}</td>
                                            <td style={{ opacity: 0.65, whiteSpace: 'nowrap' }}>{new Date(order.created_at).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: '2-digit' })}</td>
                                            <td style={{ fontWeight: 600 }}>{order.user_details?.full_name || addr?.full_name || '—'}</td>
                                            <td>
                                                <div style={{ display: 'flex', flexDirection: 'column', gap: '3px' }}>
                                                    {items.map((item: any, i: number) => <span key={i} style={{ fontSize: '0.81rem', opacity: 0.78 }}>×{item.quantity} {item.file_name}</span>)}
                                                    {items.length === 0 && <span style={{ opacity: 0.38 }}>—</span>}
                                                </div>
                                            </td>
                                            <td style={{ fontWeight: 700 }}>{formatCurrency(order.total_amount)}</td>
                                            <td>
                                                <span style={{ padding: '4px 10px', borderRadius: '6px', fontSize: '0.77rem', fontWeight: 700, background: sc.bg, color: sc.text, border: `1px solid ${sc.border}`, whiteSpace: 'nowrap' }}>
                                                    {order.status.charAt(0).toUpperCase() + order.status.slice(1)}
                                                </span>
                                            </td>
                                            <td style={{ opacity: 0.55, fontSize: '0.84rem' }}>{order.tracking_number || '—'}</td>
                                            <td>
                                                <button
                                                    onClick={(e) => { e.stopPropagation(); setDeletingId(order.id) }}
                                                    style={{ background: 'transparent', border: 'none', color: '#ff0055', cursor: 'pointer', opacity: 0.7, padding: '4px' }}
                                                    title="Delete Order"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </td>
                                        </tr>
                                        {deletingId === order.id && (
                                            <tr style={{ background: 'rgba(255,0,85,0.08)' }}>
                                                <td colSpan={8} style={{ padding: '12px 16px', borderBottom: '1px solid rgba(255,0,85,0.2)' }}>
                                                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                                                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#ff0055', fontSize: '0.85rem', fontWeight: 600 }}>
                                                            <AlertTriangle size={16} /> Permanently delete order #{order.id.slice(0, 8).toUpperCase()}?
                                                        </div>
                                                        <div style={{ display: 'flex', gap: '8px' }}>
                                                            <button
                                                                onClick={(e) => { e.stopPropagation(); setDeletingId(null) }}
                                                                style={{ background: 'rgba(255,255,255,0.1)', border: 'none', color: 'white', padding: '4px 12px', borderRadius: '6px', fontSize: '0.75rem', cursor: 'pointer' }}
                                                            >
                                                                Cancel
                                                            </button>
                                                            <button
                                                                onClick={(e) => handleDeleteOrder(order.id, e)}
                                                                style={{ background: '#ff0055', border: 'none', color: 'white', padding: '4px 12px', borderRadius: '6px', fontSize: '0.75rem', fontWeight: 700, cursor: 'pointer' }}
                                                            >
                                                                Delete
                                                            </button>
                                                        </div>
                                                    </div>
                                                </td>
                                            </tr>
                                        )}
                                    </Fragment>
                                )
                            })}
                        </tbody>
                    </table>
                </div>
            </section >

            <style>{`
                @keyframes spin    { to { transform: rotate(360deg); } }
                @keyframes fadeIn  { from { opacity:0; transform:translateY(-4px); } to { opacity:1; transform:translateY(0); } }
            `}</style>
        </div >
    )
}

function currentStatusEmoji(status: string) {
    return STATUS_OPTIONS.find(s => s.value === status)?.emoji || '🕐'
}

'use client'
import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/utils/supabase/client'
import { User } from '@supabase/supabase-js'
import { formatCurrency } from '@/utils/pricingEngine'
import styles from './Admin.module.css'
import { getAdminStats, getAdminFinancials, getSiteConfig, updateSiteConfig, getAdminTestimonials, updateTestimonialAdmin, deleteTestimonialAdmin, submitUserTestimonial } from './actions'
import { RefreshCw, Upload, CreditCard, Phone, Save, FileText, HelpCircle, Truck, RotateCcw, Shield, MessageSquare, Plus, Trash2, Edit3, Check, Megaphone, Star } from 'lucide-react'
import { useToastStore } from '@/store/toastStore'
import { useAdminStore } from '@/store/adminStore'
import Link from 'next/link'
import Loader from '@/components/Loader'

const ADMIN_EMAILS_ENV = process.env.NEXT_PUBLIC_ADMIN_EMAILS || 'admin@printhub.com,newadmin@printhub.com'
const ADMINS = ADMIN_EMAILS_ENV.split(',').map(email => email.trim().toLowerCase())

export default function AdminDashboard() {
    const router = useRouter()
    const supabase = createClient()
    const [user, setUser] = useState<User | null>(null)
    const [orders, setOrders] = useState<any[]>([])
    const [financials, setFinancials] = useState<{ totalRevenue: number; estimatedProfit: number } | null>(null)
    const [loading, setLoading] = useState(true)
    const [refreshing, setRefreshing] = useState(false)
    const [qrUpdating, setQrUpdating] = useState(false)
    const [qrError, setQrError] = useState(false)
    const [migrationNeeded, setMigrationNeeded] = useState(false)
    const [qrVersion, setQrVersion] = useState(Date.now())
    const addToast = useToastStore((state) => state.addToast)

    const [savingContacts, setSavingContacts] = useState(false)
    const [contactInfo, setContactInfo] = useState({
        instagram: '',
        whatsapp: '',
        email: 'atombotikx@gmail.com',
        phone: '+91 96778 55385',
        address: '21, Chekkan Thottam,\nRailway Lane 3rd Street,\nGanapathy, Coimbatore\nTamil Nadu - 641006',
        google_maps: ''
    })

    const [policies, setPolicies] = useState({
        faq: '',
        shipping: '',
        returns: '',
        terms: ''
    })
    const [savingPolicies, setSavingPolicies] = useState(false)

    // Testimonials state
    interface Testimonial { id?: string; name: string; role: string; quote: string; initials: string; rating: number; is_approved?: boolean; admin_reply?: string }
    const DEFAULT_TESTIMONIALS: Testimonial[] = []
    const [testimonials, setTestimonials] = useState<Testimonial[]>([])
    const [savingTestimonials, setSavingTestimonials] = useState(false)
    const [editingTestimonial, setEditingTestimonial] = useState<number | null>(null)
    const [newTestimonial, setNewTestimonial] = useState<Testimonial>({ name: '', role: '', quote: '', initials: '', rating: 5 })
    const [showAddTestimonial, setShowAddTestimonial] = useState(false)
    const [tmFilter, setTmFilter] = useState<'all' | 1 | 2 | 3 | 4 | 5>('all')
    const [replyingTo, setReplyingTo] = useState<string | null>(null)
    const [replyText, setReplyText] = useState('')

    // Admin Store
    const {
        materialTypes,
        supportTypes,
        addMaterialType,
        removeMaterialType,
        addSupportType,
        removeSupportType
    } = useAdminStore()

    // Work Hours state
    interface WorkHourRow { day: string; hours: string }
    const DEFAULT_HOURS: WorkHourRow[] = [
        { day: 'Monday – Friday', hours: '9:00 AM – 8:00 PM' },
        { day: 'Saturday', hours: '10:00 AM – 6:00 PM' },
        { day: 'Sunday', hours: 'Closed' },
    ]
    const [workHours, setWorkHours] = useState<WorkHourRow[]>(DEFAULT_HOURS)
    const [savingHours, setSavingHours] = useState(false)

    // Announcement Banner state
    const [bannerConfig, setBannerConfig] = useState({ message: '', active: false, type: 'info' })
    const [savingBanner, setSavingBanner] = useState(false)

    useEffect(() => {
        const checkUser = async () => {
            try {
                const { data: { user }, error } = await supabase.auth.getUser()

                const userEmail = user?.email?.toLowerCase() || ''
                if (error || !user || !ADMINS.includes(userEmail) || user.app_metadata?.provider !== 'email') {
                    console.warn('[Admin] Unauthorized access attempt:', userEmail)
                    router.push('/')
                    return
                }

                setUser(prev => prev?.id === user.id ? prev : user)
                setLoading(false)
            } catch (err) {
                console.error('[Admin] Auth Error:', err)
                router.push('/')
            }
        }
        checkUser()
    }, [router])

    const handleQrUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (!file) return

        if (file.size > 5 * 1024 * 1024) {
            addToast('File too large (Max 5MB)', 'error')
            return
        }

        setQrUpdating(true)
        try {
            const filePath = `payments/payment-qr.png`

            // Helper for timeout
            const withTimeout = (promise: Promise<any>, ms: number) => {
                return Promise.race([
                    promise,
                    new Promise((_, reject) => setTimeout(() => reject(new Error('Request timed out. Please check your connection.')), ms))
                ])
            }

            console.log('Starting upload sequence...')

            // Re-verify auth before upload
            const { data: { session } } = await withTimeout(supabase.auth.getSession(), 5000)
            if (!session) {
                addToast('Session expired. Please login again.', 'error')
                router.push('/')
                return
            }

            // 1. Delete existing (optional, but avoids upsert flakes)
            try {
                await withTimeout(supabase.storage.from('prints').remove([filePath]), 5000)
            } catch (e: any) {
                // Silently bypass old QR deletion errors
            }

            // 2. Upload
            console.log(`Uploading new QR to: ${filePath}, size: ${file.size} bytes`)
            const { data, error: uploadError } = await withTimeout(
                supabase.storage.from('prints').upload(filePath, file, {
                    cacheControl: '0',
                    upsert: true
                }),
                15000 // 15s timeout for upload
            )

            if (uploadError) {
                console.error('Supabase Storage Error:', uploadError)
                throw new Error(uploadError.message)
            }

            console.log('Upload successful')
            setQrVersion(Date.now())
            setQrError(false)
            addToast('Global Payment QR updated successfully', 'success')
        } catch (err: any) {
            addToast(err.message || 'Upload failed. Check your internet or console.', 'error')
        } finally {
            setQrUpdating(false)
            // Reset input so same file can be selected again
            e.target.value = ''
        }
    }

    const fetchData = async () => {
        if (!user || !ADMINS.includes(user.email?.toLowerCase() || '')) return
        setRefreshing(true)
        try {
            const [statsRes, finRes, configRes, policyRes] = await Promise.all([
                getAdminStats(),
                getAdminFinancials(),
                getSiteConfig('contact_info'),
                getSiteConfig('site_policies')
            ])
            if (statsRes.data) setOrders(statsRes.data)
            if (finRes.data) setFinancials(finRes.data as any)

            if (configRes.error?.includes('site_config') || configRes.error?.includes('schema cache')) {
                setMigrationNeeded(true)
            } else if (configRes.data) {
                setContactInfo(prev => ({ ...prev, ...configRes.data }))
                setMigrationNeeded(false)
            }

            if (policyRes.data) {
                setPolicies(prev => ({ ...prev, ...policyRes.data }))
            }

            const testimonialsRes = await getAdminTestimonials()
            if (testimonialsRes.data) {
                setTestimonials(testimonialsRes.data)
            }

            const hoursRes = await getSiteConfig('work_hours')
            if (hoursRes.data && Array.isArray(hoursRes.data)) {
                setWorkHours(hoursRes.data)
            }

            const bannerRes = await getSiteConfig('announcement_banner')
            if (bannerRes.data) {
                setBannerConfig(bannerRes.data)
            }

            setMigrationNeeded(false)
        } catch (err: any) {
            setRefreshing(false)
        }
    }

    const handleSaveContacts = async () => {
        setSavingContacts(true)
        const { success, error } = await updateSiteConfig('contact_info', contactInfo)

        if (success) {
            addToast('Contact information updated successfully!', 'success')
        } else {
            addToast(error || 'Failed to update contact information', 'error')
        }
        setSavingContacts(false)
    }

    const handleSavePolicies = async () => {
        setSavingPolicies(true)
        const result = await updateSiteConfig('site_policies', policies)
        if (result.success) {
            addToast('Site policies updated successfully', 'success')
        } else {
            addToast(result.error || 'Failed to update policies', 'error')
        }
        setSavingPolicies(false)
    }

    const handleSaveBanner = async () => {
        setSavingBanner(true)
        const result = await updateSiteConfig('announcement_banner', bannerConfig)
        if (result.success) {
            addToast('Announcement banner updated successfully', 'success')
        } else {
            addToast(result.error || 'Failed to update banner', 'error')
        }
        setSavingBanner(false)
    }

    const handleSaveWorkHours = async (updated: any[]) => {
        setSavingHours(true)
        const { success, error } = await updateSiteConfig('work_hours', updated)
        if (success) {
            addToast('Business hours saved!', 'success')
            setWorkHours(updated)
        } else {
            addToast(error || 'Failed to save hours', 'error')
        }
        setSavingHours(false)
    }

    const getInitials = (name: string) => name.split(' ').map((n: string) => n[0]).join('').toUpperCase().slice(0, 2)

    const handleAddTestimonial = async () => {
        if (!newTestimonial.name.trim() || !newTestimonial.quote.trim()) {
            addToast('Name and quote are required', 'error')
            return
        }
        setSavingTestimonials(true)
        const { success, data, error } = await submitUserTestimonial({
            name: newTestimonial.name.trim(),
            role: newTestimonial.role.trim() || 'Customer',
            quote: newTestimonial.quote.trim(),
            rating: newTestimonial.rating,
            initials: getInitials(newTestimonial.name.trim())
        })

        if (success && data && data[0]) {
            // Automatically approve admin-added reviews
            await updateTestimonialAdmin(data[0].id, { is_approved: true })
            setTestimonials(prev => [{ ...data[0], is_approved: true }, ...prev])
            setNewTestimonial({ name: '', role: '', quote: '', initials: '', rating: 5 })
            setShowAddTestimonial(false)
            addToast('Review added!', 'success')
        } else {
            addToast(error || 'Failed to add review', 'error')
        }
        setSavingTestimonials(false)
    }

    const handleApproveTestimonial = async (id: string, approve: boolean) => {
        const { success } = await updateTestimonialAdmin(id, { is_approved: approve })
        if (success) {
            setTestimonials(prev => prev.map(t => t.id === id ? { ...t, is_approved: approve } : t))
            addToast(approve ? 'Testimonial approved!' : 'Testimonial hidden!', 'success')
        }
    }

    const handleUpdateTestimonial = async (id: string, updates: any) => {
        const { success } = await updateTestimonialAdmin(id, updates)
        if (success) {
            setTestimonials(prev => prev.map(t => t.id === id ? { ...t, ...updates } : t))
            addToast('Testimonial updated!', 'success')
            setEditingTestimonial(null)
        }
    }

    const handleDeleteTestimonial = async (id: string) => {
        if (!confirm('Delete this testimonial?')) return
        const { success } = await deleteTestimonialAdmin(id)
        if (success) {
            setTestimonials(prev => prev.filter(t => t.id !== id))
            addToast('Testimonial deleted!', 'success')
        }
    }

    const handleSaveReply = async (id: string, reply: string) => {
        if (!reply.trim()) return
        const { success } = await updateTestimonialAdmin(id, { admin_reply: reply.trim() })
        if (success) {
            setTestimonials(prev => prev.map(t => t.id === id ? { ...t, admin_reply: reply.trim() } : t))
            setReplyingTo(null)
            setReplyText('')
            addToast('Reply saved!', 'success')
        }
    }

    useEffect(() => {
        if (user) {
            fetchData()

            // Subscribe to real-time order changes
            const channel = supabase.channel('admin-dashboard-sync')
                .on('postgres_changes', { event: '*', schema: 'public', table: 'orders' }, () => {
                    fetchData()
                })
                .subscribe()

            return () => {
                supabase.removeChannel(channel)
            }
        }
    }, [user])

    if (loading || !user) return <Loader text="Verifying permissions..." />
    if (refreshing && orders.length === 0) return <Loader text="Loading dashboard..." />

    const today = new Date().toDateString()

    return (
        <div className="container" style={{ maxWidth: '1200px', padding: '40px 20px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' }}>
                <div>
                    <h1 className="title-gradient" style={{ margin: 0, fontSize: '2.5rem' }}>Admin Console</h1>
                    <p style={{ opacity: 0.5, marginTop: '8px' }}>Manage your print farm, payments, and site configuration.</p>
                </div>
                <div style={{ display: 'flex', gap: '12px' }}>
                    <button
                        onClick={fetchData}
                        className="btn"
                        disabled={refreshing}
                        style={{
                            padding: '10px 24px',
                            background: 'rgba(57,255,20,0.1)',
                            border: '1px solid rgba(57,255,20,0.3)',
                            color: '#39ff14',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '10px',
                            fontWeight: 700,
                            letterSpacing: '0.5px',
                            transition: 'all 0.3s',
                            boxShadow: '0 0 20px rgba(57,255,20,0.1)'
                        }}
                    >
                        <RefreshCw size={18} className={refreshing ? 'spin' : ''} />
                        {refreshing ? 'Syncing...' : 'Sync Stats'}
                    </button>
                </div>
            </div>

            <div className={styles.statsGrid}>
                {/* ... existing stats cards same as before but inside modernized grid if needed ... */}
                <div className={styles.statCard}>
                    <div className={styles.statLabel}>🆕 Received Today</div>
                    <div className={styles.statValue} style={{ color: '#0070f3' }}>
                        {orders.filter(o => new Date(o.created_at).toDateString() === today).length}
                    </div>
                </div>
                <div className={styles.statCard}>
                    <div className={styles.statLabel}>💰 Pending Payment</div>
                    <div className={styles.statValue} style={{ color: '#ffae00' }}>
                        {orders.filter(o => o.status === 'ordered').length}
                    </div>
                </div>
                <div className={styles.statCard}>
                    <div className={styles.statLabel}>🔍 Admin Confirmation</div>
                    <div className={styles.statValue} style={{ color: '#39ff14' }}>
                        {orders.filter(o => o.status === 'pending_confirmation').length}
                    </div>
                </div>
                <div className={styles.statCard}>
                    <div className={styles.statLabel}>🖨️ Printing</div>
                    <div className={styles.statValue} style={{ color: '#00ff88' }}>
                        {orders.filter(o => o.status === 'printing').length}
                    </div>
                </div>
                <div className={styles.statCard}>
                    <div className={styles.statLabel}>📦 In Shipping</div>
                    <div className={styles.statValue} style={{ color: '#00bfff' }}>
                        {orders.filter(o => o.status === 'shipped').length}
                    </div>
                </div>
                <div className={styles.statCard}>
                    <div className={styles.statLabel}>🔄 Return Requests</div>
                    <div className={styles.statValue} style={{ color: '#ffae00' }}>
                        {orders.filter(o => o.status === 'return_requested').length}
                    </div>
                </div>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '24px', marginTop: '24px' }}>
                <div style={{
                    padding: '28px 32px', borderRadius: '24px',
                    background: 'linear-gradient(135deg, rgba(0,191,255,0.08), rgba(0,0,0,0.2))',
                    border: '1px solid rgba(0,191,255,0.2)',
                    backdropFilter: 'blur(10px)'
                }}>
                    <div style={{ fontSize: '0.75rem', color: 'rgba(0,191,255,0.8)', textTransform: 'uppercase', letterSpacing: '1.5px', fontWeight: 800, marginBottom: '8px' }}>Revenue</div>
                    <div style={{ fontSize: '2.5rem', fontWeight: 900, color: 'white' }}>{financials ? formatCurrency(financials.totalRevenue) : '—'}</div>
                </div>
                <div style={{
                    padding: '28px 32px', borderRadius: '24px',
                    background: 'linear-gradient(135deg, rgba(57,255,20,0.08), rgba(0,0,0,0.2))',
                    border: '1px solid rgba(57,255,20,0.2)',
                    backdropFilter: 'blur(10px)'
                }}>
                    <div style={{ fontSize: '0.75rem', color: 'rgba(57,255,20,0.8)', textTransform: 'uppercase', letterSpacing: '1.5px', fontWeight: 800, marginBottom: '8px' }}>Estimated Profit</div>
                    <div style={{ fontSize: '2.5rem', fontWeight: 900, color: 'white' }}>{financials ? formatCurrency(financials.estimatedProfit) : '—'}</div>
                </div>
            </div>

            {/* ── Migration Warning ── */}
            {migrationNeeded && (
                <div style={{
                    padding: '20px', background: 'rgba(255, 174, 0, 0.1)',
                    border: '1px solid rgba(255, 174, 0, 0.3)', borderRadius: '16px',
                    marginBottom: '32px', display: 'flex', alignItems: 'center', gap: '16px'
                }}>
                    <div style={{ fontSize: '1.5rem' }}>⚠️</div>
                    <div>
                        <div style={{ fontWeight: 800, color: '#ffae00', fontSize: '1rem' }}>Database Migration Required</div>
                        <p style={{ margin: '4px 0 0', fontSize: '0.85rem', opacity: 0.8 }}>
                            The 'site_config' table is missing. Please run the SQL migration in <code>schema.sql</code> using your Supabase SQL Editor to enable site-wide settings.
                        </p>
                    </div>
                </div>
            )}

            {/* ── Settings Grid ── */}
            <div style={{ display: 'grid', gridTemplateColumns: 'minmax(300px, 1fr) 2fr', gap: '32px', marginTop: '40px' }}>

                {/* Payment QR Section */}
                <div className="glass" style={{ padding: '32px', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.05)' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '24px' }}>
                        <div style={{ background: 'rgba(57,255,20,0.1)', padding: '10px', borderRadius: '12px' }}>
                            <CreditCard size={20} color="#39ff14" />
                        </div>
                        <h3 style={{ margin: 0 }}>Payment QR</h3>
                    </div>

                    <div style={{
                        aspectRatio: '1', width: '100%', maxWidth: '200px', background: 'white', borderRadius: '16px', padding: '12px',
                        margin: '0 auto 24px', boxShadow: '0 20px 40px rgba(0,0,0,0.3)'
                    }}>
                        {qrError ? (
                            <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#666', fontSize: '0.8rem' }}>No QR Found</div>
                        ) : (
                            <img
                                src={`${supabase.storage.from('admin-assets').getPublicUrl('qrs/payment-qr.png').data.publicUrl}?v=${qrVersion}`}
                                alt="QR"
                                style={{ width: '100%', height: '100%', objectFit: 'contain' }}
                                onError={() => setQrError(true)}
                            />
                        )}
                    </div>

                    <label className="btn" style={{
                        width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px',
                        background: 'white', color: 'black', fontWeight: 700, padding: '14px', borderRadius: '12px', cursor: 'pointer'
                    }}>
                        {qrUpdating ? <RefreshCw size={18} className="spin" /> : <Upload size={18} />}
                        {qrUpdating ? 'Uploading...' : 'Replace QR'}
                        <input type="file" accept="image/*" onChange={handleQrUpload} style={{ display: 'none' }} />
                    </label>
                </div>

                {/* Contact Settings Section */}
                <div className="glass" style={{ padding: '32px', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.05)' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                            <div style={{ background: 'rgba(0,191,255,0.1)', padding: '10px', borderRadius: '12px' }}>
                                <Phone size={20} color="#00bfff" />
                            </div>
                            <h3 style={{ margin: 0 }}>Site Contact Info</h3>
                        </div>
                        <button
                            onClick={handleSaveContacts}
                            disabled={savingContacts}
                            className="btn"
                            style={{
                                background: '#39ff14', color: 'black', fontWeight: 700,
                                padding: '8px 20px', borderRadius: '10px', display: 'flex',
                                alignItems: 'center', gap: '8px', fontSize: '0.9rem'
                            }}
                        >
                            {savingContacts ? <RefreshCw size={14} className="spin" /> : <Save size={16} />}
                            {savingContacts ? 'Saving...' : 'Save Changes'}
                        </button>
                    </div>

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '24px' }}>
                        <div>
                            <div style={{ marginBottom: '16px' }}>
                                <label style={{ display: 'block', fontSize: '0.75rem', opacity: 0.5, marginBottom: '6px', fontWeight: 600 }}>INSTAGRAM</label>
                                <input
                                    type="text"
                                    value={contactInfo.instagram}
                                    onChange={(e) => setContactInfo({ ...contactInfo, instagram: e.target.value })}
                                    style={{ width: '100%', padding: '12px', background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', color: 'white' }}
                                />
                            </div>
                            <div style={{ marginBottom: '16px' }}>
                                <label style={{ display: 'block', fontSize: '0.75rem', opacity: 0.5, marginBottom: '6px', fontWeight: 600 }}>WHATSAPP</label>
                                <input
                                    type="text"
                                    value={contactInfo.whatsapp}
                                    onChange={(e) => setContactInfo({ ...contactInfo, whatsapp: e.target.value })}
                                    style={{ width: '100%', padding: '12px', background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', color: 'white' }}
                                />
                            </div>
                            <div>
                                <label style={{ display: 'block', fontSize: '0.75rem', opacity: 0.5, marginBottom: '6px', fontWeight: 600 }}>PHONE DISPLAY</label>
                                <input
                                    type="text"
                                    value={contactInfo.phone}
                                    onChange={(e) => setContactInfo({ ...contactInfo, phone: e.target.value })}
                                    style={{ width: '100%', padding: '12px', background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', color: 'white' }}
                                />
                            </div>
                        </div>
                        <div>
                            <div style={{ marginBottom: '16px' }}>
                                <label style={{ display: 'block', fontSize: '0.75rem', opacity: 0.5, marginBottom: '6px', fontWeight: 600 }}>SUPPORT EMAIL</label>
                                <input
                                    type="text"
                                    value={contactInfo.email}
                                    onChange={(e) => setContactInfo({ ...contactInfo, email: e.target.value })}
                                    style={{ width: '100%', padding: '12px', background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', color: 'white' }}
                                />
                            </div>
                            <div>
                                <label style={{ display: 'block', fontSize: '0.75rem', opacity: 0.5, marginBottom: '6px', fontWeight: 600 }}>ADDRESS</label>
                                <textarea
                                    value={contactInfo.address}
                                    onChange={(e) => setContactInfo({ ...contactInfo, address: e.target.value })}
                                    rows={4}
                                    style={{ width: '100%', padding: '12px', background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', color: 'white', resize: 'none' }}
                                />
                            </div>
                            <div style={{ marginTop: '16px' }}>
                                <label style={{ display: 'block', fontSize: '0.75rem', opacity: 0.5, marginBottom: '6px', fontWeight: 600 }}>GOOGLE MAPS LINK</label>
                                <input
                                    type="text"
                                    value={contactInfo.google_maps}
                                    onChange={(e) => setContactInfo({ ...contactInfo, google_maps: e.target.value })}
                                    placeholder="https://maps.google.com/..."
                                    style={{ width: '100%', padding: '12px', background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', color: 'white' }}
                                />
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Policies Editor Section */}
            <div className="glass" style={{ padding: '32px', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.05)', marginTop: '32px', gridColumn: 'span 2' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '32px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                        <div style={{ background: 'rgba(57,255,20,0.1)', padding: '10px', borderRadius: '12px' }}>
                            <FileText size={20} color="#39ff14" />
                        </div>
                        <h3 style={{ margin: 0 }}>Content & Policies Manager</h3>
                    </div>
                    <button
                        onClick={handleSavePolicies}
                        disabled={savingPolicies}
                        className="btn"
                        style={{
                            background: '#39ff14', color: 'black', fontWeight: 700,
                            padding: '10px 24px', borderRadius: '12px', display: 'flex',
                            alignItems: 'center', gap: '8px'
                        }}
                    >
                        {savingPolicies ? <RefreshCw size={18} className="spin" /> : <Save size={18} />}
                        {savingPolicies ? 'Saving...' : 'Publish Content'}
                    </button>
                </div>

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '32px' }}>
                    <div>
                        <div style={{ marginBottom: '24px' }}>
                            <label style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.8rem', opacity: 0.6, marginBottom: '10px', fontWeight: 700 }}>
                                <HelpCircle size={14} /> FAQ CONTENT (JSON Format)
                            </label>
                            <textarea
                                value={policies.faq}
                                onChange={(e) => setPolicies({ ...policies, faq: e.target.value })}
                                rows={8}
                                placeholder='[{"q": "Question?", "a": "Answer."}]'
                                style={{ width: '100%', padding: '16px', background: 'rgba(0,0,0,0.2)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '14px', color: 'white', fontFamily: 'monospace', fontSize: '0.85rem' }}
                            />
                        </div>
                        <div>
                            <label style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.8rem', opacity: 0.6, marginBottom: '10px', fontWeight: 700 }}>
                                <Truck size={14} /> SHIPPING POLICY
                            </label>
                            <textarea
                                value={policies.shipping}
                                onChange={(e) => setPolicies({ ...policies, shipping: e.target.value })}
                                rows={8}
                                style={{ width: '100%', padding: '16px', background: 'rgba(0,0,0,0.2)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '14px', color: 'white', fontSize: '0.9rem' }}
                            />
                        </div>
                    </div>
                    <div>
                        <div style={{ marginBottom: '24px' }}>
                            <label style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.8rem', opacity: 0.6, marginBottom: '10px', fontWeight: 700 }}>
                                <RotateCcw size={14} /> RETURNS & REFUNDS
                            </label>
                            <textarea
                                value={policies.returns}
                                onChange={(e) => setPolicies({ ...policies, returns: e.target.value })}
                                rows={8}
                                style={{ width: '100%', padding: '16px', background: 'rgba(0,0,0,0.2)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '14px', color: 'white', fontSize: '0.9rem' }}
                            />
                        </div>
                        <div>
                            <label style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.8rem', opacity: 0.6, marginBottom: '10px', fontWeight: 700 }}>
                                <Shield size={14} /> TERMS OF SERVICE
                            </label>
                            <textarea
                                value={policies.terms}
                                onChange={(e) => setPolicies({ ...policies, terms: e.target.value })}
                                rows={8}
                                style={{ width: '100%', padding: '16px', background: 'rgba(0,0,0,0.2)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '14px', color: 'white', fontSize: '0.9rem' }}
                            />
                        </div>
                    </div>
                </div>
            </div>

            {/* ── Announcement Banner ── */}
            <div className="glass" style={{ padding: '32px', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.05)', marginTop: '32px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                        <div style={{ background: 'rgba(57,255,20,0.1)', padding: '10px', borderRadius: '12px' }}>
                            <Megaphone size={20} color="#39ff14" />
                        </div>
                        <div>
                            <h3 style={{ margin: 0 }}>Announcement Banner</h3>
                            <p style={{ margin: '4px 0 0', fontSize: '0.8rem', opacity: 0.4 }}>Global notice shown at the top of the homepage</p>
                        </div>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                            <span style={{ fontSize: '0.85rem', fontWeight: 600, color: bannerConfig.active ? '#39ff14' : '#666' }}>
                                {bannerConfig.active ? 'ACTIVE' : 'INACTIVE'}
                            </span>
                            <label className={styles.switch}>
                                <input
                                    type="checkbox"
                                    checked={bannerConfig.active}
                                    onChange={(e) => setBannerConfig({ ...bannerConfig, active: e.target.checked })}
                                />
                                <span className={styles.slider}></span>
                            </label>
                        </div>
                        <button
                            onClick={handleSaveBanner}
                            disabled={savingBanner}
                            className="btn"
                            style={{
                                background: '#39ff14', color: 'black', fontWeight: 700,
                                padding: '10px 24px', borderRadius: '12px', display: 'flex',
                                alignItems: 'center', gap: '8px'
                            }}
                        >
                            {savingBanner ? <RefreshCw size={18} className="spin" /> : <Save size={18} />}
                            {savingBanner ? 'Saving...' : 'Update Banner'}
                        </button>
                    </div>
                </div>

                <div style={{ display: 'flex', gap: '12px', marginBottom: '20px' }}>
                    {(['info', 'offer', 'maintenance', 'unavailable'] as const).map((type) => (
                        <button
                            key={type}
                            onClick={() => setBannerConfig({ ...bannerConfig, type })}
                            style={{
                                padding: '8px 16px',
                                borderRadius: '10px',
                                border: '1px solid',
                                fontSize: '0.85rem',
                                fontWeight: 700,
                                cursor: 'pointer',
                                transition: 'all 0.2s',
                                background: bannerConfig.type === type ?
                                    (type === 'info' ? 'rgba(57,255,20,0.15)' :
                                        type === 'offer' ? 'rgba(0,191,255,0.15)' :
                                            type === 'maintenance' ? 'rgba(255,174,0,0.15)' :
                                                'rgba(255,71,87,0.15)') : 'rgba(255,255,255,0.03)',
                                borderColor: bannerConfig.type === type ?
                                    (type === 'info' ? '#39ff14' :
                                        type === 'offer' ? '#00bfff' :
                                            type === 'maintenance' ? '#ffae00' :
                                                '#ff4757') : 'rgba(255,255,255,0.1)',
                                color: bannerConfig.type === type ?
                                    (type === 'info' ? '#39ff14' :
                                        type === 'offer' ? '#00bfff' :
                                            type === 'maintenance' ? '#ffae00' :
                                                '#ff4757') : 'rgba(255,255,255,0.4)',
                            }}
                        >
                            {type.charAt(0).toUpperCase() + type.slice(1)}
                        </button>
                    ))}
                </div>

                <textarea
                    value={bannerConfig.message}
                    onChange={(e) => setBannerConfig({ ...bannerConfig, message: e.target.value })}
                    rows={2}
                    placeholder="Enter announcement message (e.g., 'Free shipping on orders over ₹1000!')"
                    style={{
                        width: '100%', padding: '16px', background: 'rgba(0,0,0,0.2)',
                        border: '1px solid rgba(255,255,255,0.1)', borderRadius: '14px',
                        color: 'white', fontSize: '0.95rem', resize: 'none'
                    }}
                />
            </div>

            {/* ── Testimonials Manager ── */}
            <div className="glass" style={{ padding: '32px', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.05)', marginTop: '32px' }}>
                {/* Header row */}
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                        <div style={{ background: 'rgba(57,255,20,0.1)', padding: '10px', borderRadius: '12px' }}>
                            <MessageSquare size={20} color="#39ff14" />
                        </div>
                        <div>
                            <h3 style={{ margin: 0 }}>Testimonials Manager</h3>
                            <p style={{ margin: '4px 0 0', fontSize: '0.8rem', opacity: 0.4 }}>Customer reviews shown on the homepage</p>
                        </div>
                    </div>
                    <button
                        onClick={() => setShowAddTestimonial(!showAddTestimonial)}
                        className="btn"
                        style={{ background: 'rgba(57,255,20,0.15)', color: '#39ff14', border: '1px solid rgba(57,255,20,0.3)', padding: '10px 20px', borderRadius: '12px', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 700 }}
                    >
                        <Plus size={18} /> Add Review
                    </button>
                </div>

                {/* Star filter chips */}
                <div style={{ display: 'flex', gap: '8px', marginBottom: '20px', flexWrap: 'wrap' }}>
                    {(['all', 5, 4, 3, 2, 1] as const).map(f => (
                        <button
                            key={f}
                            onClick={() => setTmFilter(f as any)}
                            style={{
                                padding: '6px 14px', borderRadius: '20px', border: '1px solid',
                                fontSize: '0.82rem', fontWeight: 700, cursor: 'pointer',
                                background: tmFilter === f ? 'rgba(57,255,20,0.15)' : 'rgba(255,255,255,0.04)',
                                borderColor: tmFilter === f ? 'rgba(57,255,20,0.4)' : 'rgba(255,255,255,0.1)',
                                color: tmFilter === f ? '#39ff14' : 'rgba(255,255,255,0.5)',
                                transition: 'all 0.2s'
                            }}
                        >
                            {f === 'all' ? 'All' : `${'★'.repeat(f as number)} ${f}★`}
                        </button>
                    ))}
                    <span style={{ marginLeft: 'auto', fontSize: '0.8rem', color: 'rgba(255,255,255,0.3)', alignSelf: 'center' }}>
                        {(tmFilter === 'all' ? testimonials : testimonials.filter(t => t.rating === tmFilter)).length} review{testimonials.length !== 1 ? 's' : ''}
                    </span>
                </div>

                {/* Add new testimonial form */}
                {showAddTestimonial && (
                    <div style={{ background: 'rgba(57,255,20,0.04)', border: '1px solid rgba(57,255,20,0.15)', borderRadius: '16px', padding: '24px', marginBottom: '20px' }}>
                        <h4 style={{ margin: '0 0 20px', color: '#39ff14' }}>New Testimonial</h4>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '16px' }}>
                            <div>
                                <label style={{ display: 'block', fontSize: '0.75rem', opacity: 0.5, marginBottom: '6px', fontWeight: 700 }}>NAME *</label>
                                <input value={newTestimonial.name} onChange={e => setNewTestimonial(t => ({ ...t, name: e.target.value }))} placeholder="Customer name" style={{ width: '100%', padding: '10px 14px', background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', color: 'white', boxSizing: 'border-box' as any }} />
                            </div>
                            <div>
                                <label style={{ display: 'block', fontSize: '0.75rem', opacity: 0.5, marginBottom: '6px', fontWeight: 700 }}>ROLE / PROFESSION</label>
                                <input value={newTestimonial.role} onChange={e => setNewTestimonial(t => ({ ...t, role: e.target.value }))} placeholder="e.g. Robotics Engineer" style={{ width: '100%', padding: '10px 14px', background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', color: 'white', boxSizing: 'border-box' as any }} />
                            </div>
                        </div>
                        <div style={{ marginBottom: '16px' }}>
                            <label style={{ display: 'block', fontSize: '0.75rem', opacity: 0.5, marginBottom: '6px', fontWeight: 700 }}>REVIEW TEXT *</label>
                            <textarea value={newTestimonial.quote} onChange={e => setNewTestimonial(t => ({ ...t, quote: e.target.value }))} rows={3} placeholder="Customer's review..." style={{ width: '100%', padding: '10px 14px', background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', color: 'white', resize: 'none', fontFamily: 'inherit', boxSizing: 'border-box' as any }} />
                        </div>
                        <div style={{ marginBottom: '20px' }}>
                            <label style={{ display: 'block', fontSize: '0.75rem', opacity: 0.5, marginBottom: '8px', fontWeight: 700 }}>RATING</label>
                            <div style={{ display: 'flex', gap: '8px' }}>
                                {[1, 2, 3, 4, 5].map(s => (
                                    <button key={s} type="button" onClick={() => setNewTestimonial(t => ({ ...t, rating: s }))} style={{ background: 'none', border: 'none', padding: 0, cursor: 'pointer', color: s <= newTestimonial.rating ? '#39ff14' : 'rgba(255,255,255,0.2)', fontSize: '1.6rem', lineHeight: 1 }}>★</button>
                                ))}
                            </div>
                        </div>
                        <div style={{ display: 'flex', gap: '12px' }}>
                            <button onClick={handleAddTestimonial} disabled={savingTestimonials} className="btn" style={{ background: '#39ff14', color: 'black', fontWeight: 700, padding: '10px 24px', borderRadius: '10px', display: 'flex', alignItems: 'center', gap: '8px' }}>
                                {savingTestimonials ? <RefreshCw size={16} className="spin" /> : <Check size={16} />} Save Review
                            </button>
                            <button onClick={() => setShowAddTestimonial(false)} className="btn" style={{ background: 'rgba(255,255,255,0.06)', color: 'white', padding: '10px 20px', borderRadius: '10px' }}>Cancel</button>
                        </div>
                    </div>
                )}

                {/* Scrollable list — ~3 cards visible */}
                <div style={{ maxHeight: '420px', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '12px', paddingRight: '4px' }}>
                    {(tmFilter === 'all' ? testimonials : testimonials.filter(t => t.rating === (tmFilter as number))).map((t, i) => {
                        const id = (t.id as string) || i.toString()
                        return (
                            <div key={id} style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)', borderRadius: '14px', padding: '16px 20px', opacity: t.is_approved ? 1 : 0.6 }}>
                                {/* Main review row */}
                                <div style={{ display: 'flex', gap: '14px', alignItems: 'flex-start' }}>
                                    <div style={{ width: '40px', height: '40px', borderRadius: '50%', background: 'linear-gradient(135deg,#39ff14,#00bfff)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700, color: 'black', fontSize: '0.85rem', flexShrink: 0 }}>
                                        {t.initials || getInitials(t.name)}
                                    </div>
                                    <div style={{ flex: 1, minWidth: 0 }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '3px', flexWrap: 'wrap' }}>
                                            <strong style={{ color: 'white', fontSize: '0.95rem' }}>{t.name}</strong>
                                            <span style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.35)' }}>{t.role}</span>
                                            <span style={{ color: '#39ff14', fontSize: '0.85rem', letterSpacing: '1px' }}>{'★'.repeat(t.rating ?? 5)}<span style={{ color: 'rgba(255,255,255,0.2)' }}>{'★'.repeat(5 - (t.rating ?? 5))}</span></span>
                                            {!t.is_approved && <span style={{ fontSize: '0.65rem', background: 'rgba(255,0,85,0.2)', color: '#ff0055', padding: '2px 6px', borderRadius: '4px', fontWeight: 700 }}>HIDDEN</span>}
                                        </div>
                                        <p style={{ margin: 0, fontSize: '0.88rem', color: 'rgba(255,255,255,0.55)', fontStyle: 'italic', lineHeight: 1.5 }}>"{t.quote}"</p>

                                        {/* Reply bubble */}
                                        {t.admin_reply && (
                                            <div style={{ marginTop: '10px', padding: '10px 14px', background: 'rgba(57,255,20,0.05)', border: '1px solid rgba(57,255,20,0.15)', borderRadius: '10px', borderLeft: '3px solid #39ff14' }}>
                                                <span style={{ fontSize: '0.7rem', fontWeight: 700, color: '#39ff14', textTransform: 'uppercase', letterSpacing: '0.06em' }}>Admin Reply</span>
                                                <p style={{ margin: '4px 0 0', fontSize: '0.85rem', color: 'rgba(255,255,255,0.7)' }}>{t.admin_reply}</p>
                                            </div>
                                        )}

                                        {/* Reply input */}
                                        {replyingTo === id && (
                                            <div style={{ marginTop: '10px', display: 'flex', gap: '8px' }}>
                                                <input
                                                    autoFocus
                                                    value={replyText}
                                                    onChange={e => setReplyText(e.target.value)}
                                                    placeholder="Type your reply..."
                                                    onKeyDown={e => { if (e.key === 'Enter') handleSaveReply(id, replyText) }}
                                                    style={{ flex: 1, padding: '8px 12px', background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.12)', borderRadius: '8px', color: 'white', fontFamily: 'inherit', fontSize: '0.88rem' }}
                                                />
                                                <button onClick={() => handleSaveReply(id, replyText)} disabled={savingTestimonials} style={{ padding: '8px 16px', background: '#39ff14', color: 'black', fontWeight: 700, borderRadius: '8px', border: 'none', cursor: 'pointer', fontSize: '0.85rem', display: 'flex', alignItems: 'center', gap: '6px' }}>
                                                    {savingTestimonials ? <RefreshCw size={13} className="spin" /> : null} Reply
                                                </button>
                                                <button onClick={() => { setReplyingTo(null); setReplyText('') }} style={{ padding: '8px 12px', background: 'rgba(255,255,255,0.06)', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontSize: '0.85rem' }}>✕</button>
                                            </div>
                                        )}
                                    </div>
                                    {/* Action buttons */}
                                    <div style={{ display: 'flex', gap: '6px', flexShrink: 0 }}>
                                        <button
                                            title={t.is_approved ? "Hide" : "Approve"}
                                            onClick={() => handleApproveTestimonial(id, !t.is_approved)}
                                            style={{ width: '34px', height: '34px', borderRadius: '8px', background: t.is_approved ? 'rgba(57,255,20,0.1)' : 'rgba(255,255,255,0.05)', border: `1px solid ${t.is_approved ? '#39ff14' : 'rgba(255,255,255,0.1)'}`, color: t.is_approved ? '#39ff14' : 'rgba(255,255,255,0.4)', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}
                                        >
                                            {t.is_approved ? <Check size={14} /> : <Plus size={14} />}
                                        </button>
                                        <button
                                            title="Reply"
                                            onClick={() => { setReplyingTo(replyingTo === id ? null : id); setReplyText(t.admin_reply || '') }}
                                            style={{ width: '34px', height: '34px', borderRadius: '8px', background: replyingTo === id ? 'rgba(57,255,20,0.15)' : 'rgba(255,255,255,0.05)', border: `1px solid ${replyingTo === id ? 'rgba(57,255,20,0.3)' : 'rgba(255,255,255,0.1)'}`, color: replyingTo === id ? '#39ff14' : 'rgba(255,255,255,0.4)', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', transition: 'all 0.2s' }}
                                        >
                                            <MessageSquare size={14} />
                                        </button>
                                        <button
                                            title="Delete"
                                            onClick={() => handleDeleteTestimonial(id)}
                                            style={{ width: '34px', height: '34px', borderRadius: '8px', background: 'rgba(255,0,85,0.08)', border: '1px solid rgba(255,0,85,0.2)', color: '#ff0055', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', transition: 'all 0.2s' }}
                                        >
                                            <Trash2 size={14} />
                                        </button>
                                    </div>
                                </div>
                            </div>
                        )
                    })}
                    {(tmFilter === 'all' ? testimonials : testimonials.filter(t => t.rating === (tmFilter as number))).length === 0 && (
                        <div style={{ textAlign: 'center', padding: '40px', opacity: 0.35 }}>
                            <MessageSquare size={36} style={{ marginBottom: '10px' }} />
                            <p style={{ margin: 0 }}>{tmFilter === 'all' ? 'No reviews yet.' : `No ${tmFilter}★ reviews.`}</p>
                        </div>
                    )}
                </div>
            </div>


            {/* ── Work Hours Manager ── */}
            <div className="glass" style={{ padding: '32px', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.05)', marginTop: '32px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                        <div style={{ background: 'rgba(57,255,20,0.1)', padding: '10px', borderRadius: '12px' }}>
                            <Check size={20} color="#39ff14" />
                        </div>
                        <div>
                            <h3 style={{ margin: 0 }}>Business Hours</h3>
                            <p style={{ margin: '4px 0 0', fontSize: '0.8rem', opacity: 0.4 }}>Displayed on the Contact Us page</p>
                        </div>
                    </div>
                    <div style={{ display: 'flex', gap: '10px' }}>
                        <button
                            onClick={() => setWorkHours(h => [...h, { day: '', hours: '' }])}
                            className="btn"
                            style={{ background: 'rgba(57,255,20,0.12)', color: '#39ff14', border: '1px solid rgba(57,255,20,0.25)', padding: '8px 18px', borderRadius: '10px', display: 'flex', alignItems: 'center', gap: '6px', fontWeight: 700 }}
                        >
                            <Plus size={16} /> Add Row
                        </button>
                        <button
                            onClick={() => handleSaveWorkHours(workHours)}
                            disabled={savingHours}
                            className="btn"
                            style={{ background: '#39ff14', color: 'black', fontWeight: 700, padding: '8px 22px', borderRadius: '10px', display: 'flex', alignItems: 'center', gap: '8px' }}
                        >
                            {savingHours ? <RefreshCw size={16} className="spin" /> : <Save size={16} />} Save Hours
                        </button>
                    </div>
                </div>

                <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                    {workHours.map((row, idx) => (
                        <div key={idx} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr auto', gap: '12px', alignItems: 'center' }}>
                            <input
                                value={row.day}
                                onChange={e => setWorkHours(h => h.map((r, i) => i === idx ? { ...r, day: e.target.value } : r))}
                                placeholder="Day(s), e.g. Monday – Friday"
                                style={{ padding: '10px 14px', background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', color: 'white', fontFamily: 'inherit' }}
                            />
                            <input
                                value={row.hours}
                                onChange={e => setWorkHours(h => h.map((r, i) => i === idx ? { ...r, hours: e.target.value } : r))}
                                placeholder="Hours or 'Closed'"
                                style={{ padding: '10px 14px', background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '10px', color: 'white', fontFamily: 'inherit' }}
                            />
                            <button
                                onClick={() => setWorkHours(h => h.filter((_, i) => i !== idx))}
                                style={{ width: '36px', height: '36px', borderRadius: '8px', background: 'rgba(255,0,85,0.1)', border: '1px solid rgba(255,0,85,0.2)', color: '#ff0055', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', flexShrink: 0 }}
                            >
                                <Trash2 size={15} />
                            </button>
                        </div>
                    ))}
                    {workHours.length === 0 && (
                        <p style={{ opacity: 0.4, textAlign: 'center', padding: '20px' }}>No rows yet. Click "Add Row".</p>
                    )}
                </div>
            </div>

            <style>{`
                .spin { animation: spin 1s linear infinite; }
                @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
                .glass { background: rgba(255, 255, 255, 0.03); backdrop-filter: blur(10px); }
            `}</style>
        </div >
    )
}

'use client'
import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/utils/supabase/client'
import { User } from '@supabase/supabase-js'
import { useAdminStore, Printer } from '@/store/adminStore'
import styles from '../Admin.module.css'
import { Plus, Trash2, Edit2, Save, X, AlertTriangle } from 'lucide-react'
import { useToastStore } from '@/store/toastStore'
import Loader from '@/components/Loader'

export default function AdminPrintersPage() {
    const addToast = useToastStore((state) => state.addToast)
    const router = useRouter()
    const supabase = createClient()
    const [user, setUser] = useState<User | null>(null)
    const [loading, setLoading] = useState(true)

    const { printers, updatePrinterStatus, addPrinter, updatePrinter, removePrinter, fetchSettings } = useAdminStore()
    const [newPrinterName, setNewPrinterName] = useState('')
    const [newPrinterType, setNewPrinterType] = useState('FDM')
    const [editingId, setEditingId] = useState<string | null>(null)
    const [deletingId, setDeletingId] = useState<string | null>(null)
    const [isProcessing, setIsProcessing] = useState(false)

    useEffect(() => {
        const checkUser = async () => {
            const { data: { user } } = await supabase.auth.getUser()
            setUser(user)
            setLoading(false)

            const ADMIN_EMAILS_ENV = process.env.NEXT_PUBLIC_ADMIN_EMAILS || 'admin@printhub.com,newadmin@printhub.com'
            const ADMINS = ADMIN_EMAILS_ENV.split(',').map(e => e.trim().toLowerCase())
            const userEmail = user?.email?.toLowerCase() || ''
            if (!user || !ADMINS.includes(userEmail)) {
                router.push('/')
            }
        }
        checkUser()
    }, [router])

    useEffect(() => {
        fetchSettings()
    }, [fetchSettings])

    const handleSavePrinter = async () => {
        if (!newPrinterName || isProcessing) return
        setIsProcessing(true)

        try {
            if (editingId) {
                await updatePrinter(editingId, {
                    name: newPrinterName,
                    type: newPrinterType
                })
                setEditingId(null)
                addToast('Printer updated', 'success')
            } else {
                await addPrinter({
                    id: crypto.randomUUID(),
                    name: newPrinterName,
                    type: newPrinterType,
                    status: 'available'
                })
                addToast('Printer added', 'success')
            }
            setNewPrinterName('')
        } catch (err) {
            addToast('Operation failed', 'error')
        } finally {
            setIsProcessing(false)
        }
    }

    const startEditing = (printer: Printer) => {
        setEditingId(printer.id)
        setNewPrinterName(printer.name)
        setNewPrinterType(printer.type)
    }

    const cancelEditing = () => {
        setEditingId(null)
        setNewPrinterName('')
        setNewPrinterType('FDM')
    }

    if (loading || !user) return <Loader text="Verifying access..." />

    return (
        <div className="container" style={{ maxWidth: '100%', padding: 0 }}>
            <h1 className="title-gradient" style={{ marginBottom: '32px' }}>Printer Farm</h1>

            <section className={`${styles.section} glass`}>
                <div className={styles.addPrinterForm}>
                    <input
                        type="text"
                        placeholder="Printer Name (e.g. Prusa MK4 #4)"
                        value={newPrinterName}
                        onChange={(e) => setNewPrinterName(e.target.value)}
                        className={styles.input}
                    />
                    <input
                        type="text"
                        placeholder="Model (e.g. MK4, X1C)"
                        value={newPrinterType}
                        onChange={(e) => setNewPrinterType(e.target.value)}
                        className={styles.input}
                        style={{ width: '150px' }}
                    />
                    <button onClick={handleSavePrinter} className="btn">
                        {editingId ? <Save size={18} /> : <Plus size={18} />}
                    </button>
                    {editingId && (
                        <button onClick={cancelEditing} className="btn secondary" style={{ background: 'rgba(255,255,255,0.1)' }}>
                            <X size={18} />
                        </button>
                    )}
                </div>

                <div className={styles.tableContainer}>
                    <table className={styles.table}>
                        <thead>
                            <tr>
                                <th>Printer</th>
                                <th>Model</th>
                                <th>Status</th>
                                <th>Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            {printers.map((printer) => (
                                <tr key={printer.id}>
                                    <td>{printer.name}</td>
                                    <td>{printer.type}</td>
                                    <td>
                                        <select
                                            disabled={isProcessing}
                                            value={printer.status}
                                            onChange={async (e) => {
                                                setIsProcessing(true)
                                                await updatePrinterStatus(printer.id, e.target.value as Printer['status'])
                                                setIsProcessing(false)
                                            }}
                                            className={`${styles.statusSelect} ${styles[printer.status]}`}
                                        >
                                            <option value="available">Available</option>
                                            <option value="busy">Busy</option>
                                            <option value="maintenance">Maintenance</option>
                                        </select>
                                    </td>
                                    <td style={{ position: 'relative' }}>
                                        <div style={{ display: 'flex', gap: '8px' }}>
                                            <button onClick={() => startEditing(printer)} className={styles.editBtn}>
                                                <Edit2 size={16} />
                                            </button>
                                            <button onClick={() => setDeletingId(printer.id)} className={styles.deleteBtn}>
                                                <Trash2 size={16} />
                                            </button>
                                        </div>

                                        {deletingId === printer.id && (
                                            <div style={{
                                                position: 'absolute', inset: 0, zIndex: 10,
                                                background: 'rgba(255,0,85,0.95)', backdropFilter: 'blur(5px)',
                                                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px',
                                                animation: 'fadeIn 0.2s ease', color: 'white', borderRadius: '8px'
                                            }}>
                                                <AlertTriangle size={14} />
                                                <button onClick={() => setDeletingId(null)} style={{ background: 'none', border: 'none', color: 'white', cursor: 'pointer', fontSize: '0.7rem' }}>Cancel</button>
                                                <button onClick={async () => {
                                                    setIsProcessing(true)
                                                    await removePrinter(printer.id)
                                                    setDeletingId(null)
                                                    setIsProcessing(false)
                                                    addToast('Printer removed', 'info')
                                                }} style={{ background: 'white', border: 'none', color: '#ff0055', borderRadius: '4px', padding: '2px 6px', fontSize: '0.7rem', fontWeight: 900, cursor: 'pointer' }}>Delete</button>
                                            </div>
                                        )}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </section>
        </div>
    )
}

'use client'
import { useState, useRef, useEffect, Suspense } from 'react'
import { useSearchParams } from 'next/navigation'
import styles from './AdminSTL.module.css'
import STLViewer from '@/components/STLViewer'
import { Upload, Box } from 'lucide-react'
import { useToastStore } from '@/store/toastStore'
import { createClient } from '@/utils/supabase/client'
import { useRouter } from 'next/navigation'
import { User } from '@supabase/supabase-js'
import Loader from '@/components/Loader'

function AdminSTLViewer() {
    const searchParams = useSearchParams()
    const urlParam = searchParams.get('url')
    const nameParam = searchParams.get('name')

    const [fileUrl, setFileUrl] = useState<string | null>(urlParam || null)
    const [fileName, setFileName] = useState<string>(nameParam || (urlParam ? urlParam.split('/').pop() || 'model.stl' : ''))
    const fileInputRef = useRef<HTMLInputElement>(null)
    const router = useRouter()
    const supabase = createClient()
    const [loading, setLoading] = useState(true)
    const [user, setUser] = useState<User | null>(null)

    useEffect(() => {
        const checkUser = async () => {
            const { data: { user } } = await supabase.auth.getUser()
            const ADMIN_EMAILS_ENV = process.env.NEXT_PUBLIC_ADMIN_EMAILS || 'admin@printhub.com,newadmin@printhub.com'
            const ADMINS = ADMIN_EMAILS_ENV.split(',').map(e => e.trim().toLowerCase())

            if (!user || !ADMINS.includes(user.email?.toLowerCase() || '')) {
                router.push('/')
                return
            }
            setUser(user)
            setLoading(false)
        }
        checkUser()
    }, [router])

    // If url param changes re-load
    useEffect(() => {
        if (urlParam) {
            setFileUrl(urlParam)
            setFileName(nameParam || urlParam.split('/').pop() || 'model.stl')
        }
    }, [urlParam, nameParam])

    // Viewer Controls
    const [color, setColor] = useState('#ffffff')
    const [wireframe, setWireframe] = useState(false)
    const [opacity, setOpacity] = useState(1)
    const [crossSection, setCrossSection] = useState(false)
    const [crossSectionHeight, setCrossSectionHeight] = useState(50)
    const [crossSectionAxis, setCrossSectionAxis] = useState<'x' | 'y' | 'z'>('y')
    const [autoRotate, setAutoRotate] = useState(true)
    const [showAxes, setShowAxes] = useState(false)

    if (loading) return <Loader text="Checking permissions..." />

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const selectedFile = e.target.files[0]
            if (selectedFile.name.toLowerCase().endsWith('.stl')) {
                const url = URL.createObjectURL(selectedFile)
                setFileUrl(url)
                setFileName(selectedFile.name)
            } else {
                useToastStore.getState().addToast('Please upload a .stl file', 'error')
            }
        }
    }

    return (
        <div className={styles.container}>
            <div className={styles.header}>
                <h1 className="title-gradient">Admin STL viewer</h1>
                <p className={styles.subtitle}>Quickly inspect STL files</p>
            </div>

            <div className={`${styles.contentGrid} ${fileUrl ? styles.withSidebar : ''}`}>
                <div className={styles.viewerWrapper}>
                    {!fileUrl ? (
                        <div
                            className={styles.uploadZone}
                            onClick={() => fileInputRef.current?.click()}
                        >
                            <input
                                type="file"
                                ref={fileInputRef}
                                onChange={handleFileChange}
                                accept=".stl"
                                hidden
                            />
                            <Upload size={48} className={styles.uploadIcon} />
                            <h3>Drop STL file here</h3>
                            <p>or click to browse</p>
                        </div>
                    ) : (
                        <div className={styles.viewerContent}>
                            <div className={styles.toolbar}>
                                <div className={styles.fileInfo}>
                                    <Box size={20} />
                                    <span>{fileName}</span>
                                </div>
                                <button
                                    onClick={() => { setFileUrl(null); setFileName(''); }}
                                    className={styles.changeBtn}
                                >
                                    Change file
                                </button>
                            </div>
                            <STLViewer
                                url={fileUrl}
                                height={600}
                                color={color}
                                wireframe={wireframe}
                                opacity={opacity}
                                showCrossSection={crossSection}
                                crossSectionHeight={crossSectionHeight}
                                crossSectionAxis={crossSectionAxis}
                                autoRotate={autoRotate}
                                showAxes={showAxes}
                                showLoader={true}
                            />
                        </div>
                    )}
                </div>

                {/* Controls Sidebar */}
                {fileUrl && (
                    <div className={styles.controlsSidebar}>
                        <h3>Viewer options</h3>

                        <div className={styles.controlGroup}>
                            <label>Model color</label>
                            <div className={styles.colorPickerWrapper}>
                                <input
                                    type="color"
                                    value={color}
                                    onChange={(e) => setColor(e.target.value)}
                                    className={styles.colorInput}
                                />
                                <span className={styles.colorValue}>{color.toUpperCase()}</span>
                            </div>
                        </div>

                        <div className={styles.controlGroup}>
                            <div className={styles.checkboxWrapper} onClick={() => setWireframe(!wireframe)}>
                                <input
                                    type="checkbox"
                                    id="wireframe"
                                    checked={wireframe}
                                    onChange={(e) => setWireframe(e.target.checked)}
                                    onClick={(e) => e.stopPropagation()}
                                />
                                <div className={styles.customCheckbox} />
                                <label htmlFor="wireframe">Mesh view (wireframe)</label>
                            </div>
                        </div>

                        <div className={styles.controlGroup}>
                            <label>Opacity ({Math.round(opacity * 100)}%)</label>
                            <input
                                type="range"
                                min="0.1"
                                max="1"
                                step="0.1"
                                value={opacity}
                                onChange={(e) => setOpacity(parseFloat(e.target.value))}
                                className={styles.rangeInput}
                            />
                        </div>

                        <div className={styles.divider} />

                        <div className={styles.controlGroup}>
                            <div className={styles.checkboxWrapper} onClick={() => setCrossSection(!crossSection)}>
                                <input
                                    type="checkbox"
                                    id="crossSection"
                                    checked={crossSection}
                                    onChange={(e) => setCrossSection(e.target.checked)}
                                    onClick={(e) => e.stopPropagation()}
                                />
                                <div className={styles.customCheckbox} />
                                <label htmlFor="crossSection">Enable cross-section</label>
                            </div>
                        </div>

                        <div className={styles.controlGroup}>
                            <div className={styles.checkboxWrapper} onClick={() => setAutoRotate(!autoRotate)}>
                                <input
                                    type="checkbox"
                                    id="autoRotate"
                                    checked={autoRotate}
                                    onChange={(e) => setAutoRotate(e.target.checked)}
                                    onClick={(e) => e.stopPropagation()}
                                />
                                <div className={styles.customCheckbox} />
                                <label htmlFor="autoRotate">Auto-rotate view</label>
                            </div>
                        </div>

                        <div className={styles.controlGroup}>
                            <div className={styles.checkboxWrapper} onClick={() => setShowAxes(!showAxes)}>
                                <input
                                    type="checkbox"
                                    id="showAxes"
                                    checked={showAxes}
                                    onChange={(e) => setShowAxes(e.target.checked)}
                                    onClick={(e) => e.stopPropagation()}
                                />
                                <div className={styles.customCheckbox} />
                                <label htmlFor="showAxes">Show 3D axes</label>
                            </div>
                        </div>

                        {crossSection && (
                            <div className={styles.controlGroup}>
                                <label>Cut axis</label>
                                <div style={{ display: 'flex', gap: '8px', marginBottom: '12px' }}>
                                    {(['x', 'y', 'z'] as const).map(axis => (
                                        <button
                                            key={axis}
                                            type="button"
                                            onClick={() => setCrossSectionAxis(axis)}
                                            style={{
                                                flex: 1, padding: '4px 0', fontSize: '0.8rem', textTransform: 'uppercase',
                                                background: crossSectionAxis === axis ? 'var(--primary-color)' : 'rgba(255,255,255,0.05)',
                                                color: crossSectionAxis === axis ? 'black' : 'white',
                                                border: crossSectionAxis === axis ? '1px solid var(--primary-color)' : '1px solid rgba(255,255,255,0.1)',
                                                borderRadius: '6px', cursor: 'pointer'
                                            }}
                                        >
                                            {axis}
                                        </button>
                                    ))}
                                </div>
                                <label>Slice height ({crossSectionHeight}%)</label>
                                <input
                                    type="range"
                                    min="0"
                                    max="100"
                                    value={crossSectionHeight}
                                    onChange={(e) => setCrossSectionHeight(parseInt(e.target.value))}
                                    className={styles.rangeInput}
                                />
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    )
}

export default function AdminSTLPage() {
    return (
        <Suspense fallback={<Loader text="Loading viewer..." />}>
            <AdminSTLViewer />
        </Suspense>
    )
}

import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@/utils/supabase/server'

export const dynamic = 'force-dynamic';

/**
 * Server-side proxy for downloading files from Supabase Storage.
 * This bypasses CORS restrictions that prevent direct browser fetch.
 * Usage: GET /api/download?url=<encoded-url>&name=<filename>
 */
export async function GET(req: NextRequest) {
    // Auth check
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) {
        return new NextResponse('Unauthorized: Please log in to download models', { status: 401 })
    }

    const url = req.nextUrl.searchParams.get('url')
    const name = req.nextUrl.searchParams.get('name') || 'model.stl'

    if (!url) {
        return new NextResponse('Missing url parameter', { status: 400 })
    }

    // Validate the URL is from our Supabase project (allow trailing slash variations)
    const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL
    if (supabaseUrl) {
        const normalizedSupabase = supabaseUrl.replace(/\/*$/, '')
        const normalizedUrl = url.replace(/\/*$/, '')
        if (!normalizedUrl.startsWith(normalizedSupabase)) {
            return new NextResponse('Forbidden: URL not from allowed origin', { status: 403 })
        }
    }

    try {
        const response = await fetch(url)

        if (!response.ok) {
            return new NextResponse(`Failed to fetch file: ${response.status} ${response.statusText}`, { status: response.status })
        }

        const buffer = await response.arrayBuffer()
        const contentType = response.headers.get('content-type') || 'application/octet-stream'

        return new NextResponse(buffer, {
            status: 200,
            headers: {
                'Content-Type': contentType,
                // Replace both spaces and double quotes with underscores to guarantee the file is downloaded with correct extension and no browser parse issues
                'Content-Disposition': `attachment; filename="${name.replace(/[" ]/g, '_')}"`,
                'Content-Length': buffer.byteLength.toString(),
                'Cache-Control': 'no-cache',
            },
        })
    } catch (err: any) {
        console.error('[/api/download] Error:', err)
        return new NextResponse('Download failed: ' + err.message, { status: 500 })
    }
}

import { NextResponse } from 'next/server'

// Mock slicing endpoint - simulates backend STL analysis and g-code generation
export async function POST(request: Request) {
    try {
        const formData = await request.formData()
        const file = formData.get('file') as File
        const material = formData.get('material') as string
        const layerHeight = parseFloat(formData.get('layerHeight') as string || '0.2')
        const infill = parseInt(formData.get('infill') as string || '20')

        if (!file) {
            return NextResponse.json(
                { success: false, error: 'No file provided' },
                { status: 400 }
            )
        }

        // Simulate processing time
        await new Promise(resolve => setTimeout(resolve, 1000))

        // Mock slice results - in reality this would use a slicer like BambuStudio API
        const fileSize = file.size

        // Rough estimates based on file size (this is very simplified)
        const estimatedVolume = Math.max(10, Math.min(500, fileSize / 10000))
        const estimatedWeight = estimatedVolume * getMaterialDensity(material)
        const estimatedPrintTime = calculatePrintTime(estimatedVolume, layerHeight, infill)
        const estimatedFilamentLength = estimatedWeight / getMaterialDensity(material) * 400 // rough meters
        const estimatedLayers = Math.ceil((estimatedVolume * 10) / Math.pow(layerHeight * 10, 2))

        return NextResponse.json({
            success: true,
            sliceData: {
                fileName: file.name,
                material,
                layerHeight,
                infill,
                volume: Math.round(estimatedVolume * 100) / 100,
                weight: Math.round(estimatedWeight * 100) / 100,
                printTime: estimatedPrintTime, // minutes
                filamentLength: Math.round(estimatedFilamentLength * 100) / 100,
                layers: estimatedLayers,
                estimatedCost: calculateCost(estimatedWeight, material)
            },
            timestamp: new Date().toISOString()
        })

    } catch (error) {
        return NextResponse.json(
            { success: false, error: 'Slicing failed' },
            { status: 500 }
        )
    }
}

function getMaterialDensity(material: string): number {
    const densities: { [key: string]: number } = {
        'PLA': 1.24,
        'ABS': 1.04,
        'PETG': 1.27,
        'TPU': 1.21,
        'Nylon': 1.14
    }
    return densities[material] || 1.24
}

function calculatePrintTime(volume: number, layerHeight: number, infill: number): number {
    // Very simplified calculation - in reality depends on many factors
    const baseTime = volume * 2 // 2 minutes per cm³ base
    const layerFactor = (0.3 - layerHeight) * 50 // finer layers take longer
    const infillFactor = infill * 0.5 // more infill takes longer
    return Math.round(baseTime + layerFactor + infillFactor)
}

function calculateCost(weight: number, material: string): number {
    const pricePerGram: { [key: string]: number } = {
        'PLA': 0.02,
        'ABS': 0.025,
        'PETG': 0.03,
        'TPU': 0.05,
        'Nylon': 0.06
    }
    const materialPrice = (pricePerGram[material] || 0.02) * weight
    return Math.round(materialPrice * 100) / 100
}

'use client'
import Link from 'next/link'
import styles from './AuthError.module.css'
import { AlertTriangle, Home, RotateCcw } from 'lucide-react'
import { useSearchParams } from 'next/navigation'
import { useEffect, useState, Suspense } from 'react'

function AuthErrorContent() {
    const searchParams = useSearchParams()
    const [errorState, setErrorState] = useState<{ error: string | null, description: string | null }>({
        error: searchParams.get('error'),
        description: searchParams.get('error_description')
    })

    useEffect(() => {
        // Also check hash params (Supabase sometimes redirects with #error=...)
        if (!errorState.error && window.location.hash) {
            const hashParams = new URLSearchParams(window.location.hash.substring(1))
            const hashError = hashParams.get('error')
            const hashDesc = hashParams.get('error_description') || hashParams.get('error_code')
            if (hashError) {
                setErrorState({ error: hashError, description: hashDesc })
            }
        }
    }, [searchParams, errorState.error])

    const error = errorState.error
    const errorDescription = errorState.description

    return (
        <div className={styles.container}>
            <div className={styles.card}>
                <div className={styles.iconWrapper}>
                    <AlertTriangle size={48} className={styles.icon} />
                </div>

                <h1 className={styles.title}>Authentication Error</h1>

                <div className={styles.errorBox}>
                    <p className={styles.errorCode}>Error: {error || 'Unknown Error'}</p>
                    <p className={styles.errorMessage}>
                        {errorDescription?.replaceAll('+', ' ') || 'An unexpected error occurred during authentication.'}
                    </p>
                </div>

                <div className={styles.actions}>
                    <Link href="/login" className={styles.retryBtn}>
                        <RotateCcw size={18} />
                        Try Login Again
                    </Link>
                    <Link href="/" className={styles.homeBtn}>
                        <Home size={18} />
                        Go Home
                    </Link>
                </div>
            </div>
        </div>
    )
}

export default function AuthErrorPage() {
