'use client'
import { Canvas, useFrame } from '@react-three/fiber'
import { OrbitControls, PerspectiveCamera } from '@react-three/drei'
import { Suspense, useEffect, useRef, useState } from 'react'
import * as THREE from 'three'
import { STLLoader } from 'three-stdlib'
import styles from './GCodeViewer.module.css'
import { getSignedModelUrl } from '@/app/admin/actions'
import Loader from './Loader'

interface STLViewerProps {
    url: string
    color?: string
    height?: number
    showCrossSection?: boolean
    crossSectionHeight?: number
    crossSectionAxis?: 'x' | 'y' | 'z'
    wireframe?: boolean
    opacity?: number
    autoRotate?: boolean
    showAxes?: boolean
    showLoader?: boolean
    estimatedTime?: string
    geometry?: THREE.BufferGeometry | null
}

function IsaacSimFloor() {
    return (
        <group>
            {/* Reflective Ground Plane (Isaac Sim Style) */}
            <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.2, 0]} receiveShadow>
                <planeGeometry args={[30000, 30000]} />
                <meshStandardMaterial
                    color="#1a2b3c"
                    metalness={0.8}
                    roughness={0.2}
                />
            </mesh>

            {/* Prominent Grid */}
            <gridHelper
                args={[20000, 40, "#ffffff", "#445566"]}
                position={[0, 0, 0]}
                onUpdate={(self) => {
                    if (self.material instanceof THREE.Material) {
                        self.material.transparent = true;
                        self.material.opacity = 0.35;
                    }
                }}
            />
        </group>
    )
}

function Model({ geom, color = '#ffffff', showCrossSection = false, crossSectionHeight = 50, crossSectionAxis = 'y', wireframe = false, opacity = 1, autoRotate = true }: any) {
    const meshRef = useRef<THREE.Mesh>(null)
    const clippingPlane = useRef(new THREE.Plane(new THREE.Vector3(0, -1, 0), 0))

    useEffect(() => {
        if (!geom) return
        if (showCrossSection) {
            geom.computeBoundingBox()
            const size = new THREE.Vector3()
            geom.boundingBox!.getSize(size)

            if (crossSectionAxis === 'x') {
                clippingPlane.current.normal.set(-1, 0, 0)
                clippingPlane.current.constant = (crossSectionHeight / 100) * size.x - (size.x / 2)
            } else if (crossSectionAxis === 'z') {
                clippingPlane.current.normal.set(0, 0, -1)
                clippingPlane.current.constant = (crossSectionHeight / 100) * size.z - (size.z / 2)
            } else {
                clippingPlane.current.normal.set(0, -1, 0)
                clippingPlane.current.constant = (crossSectionHeight / 100) * size.y
            }
        }
    }, [geom, showCrossSection, crossSectionHeight, crossSectionAxis])

    useFrame(() => {
        if (meshRef.current && autoRotate && !showCrossSection) {
            meshRef.current.rotation.y += 0.01
        }
    })

    return (
        <mesh ref={meshRef} geometry={geom} castShadow receiveShadow>
            <meshStandardMaterial
                color={new THREE.Color(color)}
                roughness={0.4}
                metalness={0.6}
                emissive={new THREE.Color(color)}
                emissiveIntensity={0.1}
                clippingPlanes={showCrossSection ? [clippingPlane.current] : []}
                clipShadows={true}
                side={THREE.DoubleSide}
                wireframe={wireframe}
                transparent={opacity < 1}
                opacity={opacity}
            />
        </mesh>
    )
}

export default function STLViewer({ url, color = '#ffffff', height = 400, showCrossSection, crossSectionHeight, crossSectionAxis = 'y', wireframe, opacity, autoRotate = true, showAxes = false, showLoader = false, estimatedTime, geometry }: STLViewerProps) {
    const [loading, setLoading] = useState(true)
    const [processedGeom, setProcessedGeom] = useState<THREE.BufferGeometry | null>(null)
    const [error, setError] = useState<string | null>(null)
    const resolvingRef = useRef(false)

    useEffect(() => {
        if (geometry) {
            setProcessedGeom(geometry)
            setLoading(false)
            return
        }

        if (!url) {
            setLoading(false)
            return
        }

        const loadModel = (actualUrl: string) => {
            const loader = new STLLoader()
            setLoading(true)
            setError(null)

            const startTime = Date.now()

            loader.load(actualUrl, (geom) => {
                geom.computeBoundingBox()
                const size = new THREE.Vector3()
                geom.boundingBox!.getSize(size)
                geom.center()
                // Don't translate up here, we want rotation to be around the geometric center
                // geom.translate(0, size.y / 2, 0)

                const elapsedTime = Date.now() - startTime
                const minLoadTime = showLoader ? 800 : 0

                setTimeout(() => {
                    setProcessedGeom(geom)
                    setLoading(false)
                }, Math.max(0, minLoadTime - elapsedTime))

            }, (xhr) => {
                // Optional progress logging
            }, (err) => {
                setError('Failed to load 3D model: Connection error')
                setLoading(false)
            })
        }

        const resolveAndLoad = async () => {
            if (resolvingRef.current) return
            resolvingRef.current = true

            try {
                let finalUrl = url
                if (url && !url.startsWith('blob:') && !url.startsWith('http')) {
                    const res = await getSignedModelUrl(url)
                    if (res.data) {
                        finalUrl = res.data
                    } else {
                        setError(`Access Denied: ${res.error || 'Private file'}`)
                        setLoading(false)
                        return
                    }
                }

                if (finalUrl) {
                    loadModel(finalUrl)
                } else {
                    setLoading(false)
                }
            } catch (err) {
                setError('Connection error while fetching model')
                setLoading(false)
            } finally {
                resolvingRef.current = false
            }
        }

        resolveAndLoad()
    }, [url, showLoader, geometry])

    return (
        <div style={{
            width: '100%',
            height: `${height}px`,
            background: '#0a111a',
            borderRadius: '12px',
            overflow: 'hidden',
            position: 'relative'
        }}>
            <Canvas
                shadows
                dpr={[1, 2]}
                gl={{ localClippingEnabled: true, antialias: true, logarithmicDepthBuffer: true }}
                onCreated={({ scene, gl }) => {
                    scene.background = new THREE.Color('#0a111a')
                    scene.fog = new THREE.Fog('#0a111a', 5000, 30000)
                    gl.toneMapping = THREE.ACESFilmicToneMapping
                    gl.toneMappingExposure = 1.4 // Slightly higher for better white visibility
                }}
            >
                <Suspense fallback={null}>
                    {processedGeom && processedGeom.boundingBox && (
                        <group position={[0, -processedGeom.boundingBox.getSize(new THREE.Vector3()).y / 2, 0]}>
                            <IsaacSimFloor />
                        </group>
                    )}
                    {!processedGeom && <IsaacSimFloor />}

                    <ambientLight intensity={0.7} />
                    <hemisphereLight args={[0xabcfff, 0x111111, 0.8]} />

                    <directionalLight position={[500, 3000, 1000]} intensity={1.5} castShadow />
                    <directionalLight position={[-500, 3000, -1000]} intensity={0.8} />
                    <pointLight position={[-800, 1000, 800]} intensity={3.5} distance={4000} />

                    {processedGeom && (
                        <Model
                            geom={processedGeom}
                            color={color}
                            showCrossSection={showCrossSection}
                            crossSectionHeight={crossSectionHeight}
                            crossSectionAxis={crossSectionAxis}
                            wireframe={wireframe}
                            opacity={opacity}
                            autoRotate={autoRotate}
                        />
                    )}

                    {showAxes && <axesHelper args={[200]} />}

                    <OrbitControls
                        makeDefault
                        enableDamping
                        minDistance={0.1}
                        maxDistance={3000}
                    />

                    <PerspectiveCamera
                        makeDefault
                        position={[300, 200, 300]}
                        fov={50}
                        near={1}
                        far={100000}
                    />
                </Suspense>
            </Canvas>

            {loading && showLoader && (
                <div className={styles.overlay} style={{ backgroundColor: 'rgba(10, 17, 26, 0.8)' }}>
                    <Loader text="Processing STL file..." fullPage={false} />
                </div>
            )}

            {error && (
                <div className={styles.overlay} style={{ backgroundColor: 'rgba(10, 17, 26, 0.9)' }}>
                    <div style={{ color: '#ff4444', fontSize: '24px', marginBottom: '8px' }}>⚠️</div>
                    <p style={{ color: 'white', fontWeight: '500', textAlign: 'center', padding: '0 20px' }}>{error}</p>
                </div>
            )}
        </div>
    )
}

'use client'
import { useEffect, useState, useRef } from 'react'
import styles from './Testimonials.module.css'
import { Star, MessageSquarePlus, X, Loader2, Send } from 'lucide-react'
import { getApprovedTestimonials, submitUserTestimonial } from '@/app/admin/actions'
import { createClient } from '@/utils/supabase/client'
import { useToastStore } from '@/store/toastStore'

interface Testimonial {
    id?: string
    name: string
    role: string
    quote: string
    initials: string
    rating: number
    admin_reply?: string
}

const DEFAULT_TESTIMONIALS: Testimonial[] = []

function getInitials(name: string) {
    return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2)
}

export default function Testimonials() {
    const [testimonials, setTestimonials] = useState<Testimonial[]>([])
    const [loading, setLoading] = useState(true)
    const [loggedIn, setLoggedIn] = useState(false)
    const [showModal, setShowModal] = useState(false)
    const [submitting, setSubmitting] = useState(false)
    const addToast = useToastStore((state) => state.addToast)
    const trackRef = useRef<HTMLDivElement>(null)

    // Drag-to-scroll
    const drag = useRef({ active: false, startX: 0, scrollLeft: 0 })
    const onMouseDown = (e: React.MouseEvent) => {
        drag.current = { active: true, startX: e.pageX - (trackRef.current?.offsetLeft ?? 0), scrollLeft: trackRef.current?.scrollLeft ?? 0 }
    }
    const onMouseMove = (e: React.MouseEvent) => {
        if (!drag.current.active || !trackRef.current) return
        e.preventDefault()
        const x = e.pageX - (trackRef.current.offsetLeft ?? 0)
        trackRef.current.scrollLeft = drag.current.scrollLeft - (x - drag.current.startX)
    }
    const onMouseUp = () => { drag.current.active = false }

    const [form, setForm] = useState({
        name: '',
        role: '',
        quote: '',
        rating: 5
    })

    useEffect(() => {
        // Load approved testimonials from DB
        getApprovedTestimonials().then(res => {
            if (res.data) {
                setTestimonials(res.data)
            }
            setLoading(false)
        }).catch(() => setLoading(false))

        // Check if user is logged in
        const supabase = createClient()
        supabase.auth.getUser().then(({ data: { user } }) => {
            if (user) {
                setLoggedIn(true)
                const fullName = user.user_metadata?.full_name || user.email?.split('@')[0] || ''
                setForm(f => ({ ...f, name: fullName }))
            }
        })
    }, [])

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()

        if (!loggedIn) {
            addToast('Please sign in to submit a review.', 'error')
            setTimeout(() => { window.location.href = '/login' }, 2000)
            return
        }

        if (!form.quote.trim() || !form.name.trim()) {
            addToast('Please fill in all fields', 'error')
            return
        }

        setSubmitting(true)
        try {
            const newTestimonial: Testimonial = {
                name: form.name.trim(),
                role: form.role.trim() || 'Customer',
                quote: form.quote.trim(),
                initials: getInitials(form.name.trim()),
                rating: form.rating
            }

            const res = await submitUserTestimonial(newTestimonial)

            if (res.error) {
                addToast('Failed to submit review. Please try again.', 'error')
            } else {
                setTestimonials(prev => [...prev, newTestimonial])
                addToast('Thank you for your review! 🎉', 'success')
                setShowModal(false)
                setForm(f => ({ ...f, role: '', quote: '', rating: 5 }))
            }
        } finally {
            setSubmitting(false)
        }
    }

    if (loading && testimonials.length === 0) return null

    return (
        <section className={styles.testimonials}>
            <div className="container">
                <div className={styles.header}>
                    <h2 className="title-gradient">What Our Clients Say</h2>
                    <p>Trusted by engineers, designers, and creators across India.</p>
                    <button
                        className={styles.reviewBtn}
                        onClick={() => {
                            if (!loggedIn) {
                                window.location.href = '/login'
                            } else {
                                setShowModal(true)
                            }
                        }}
                    >
                        <MessageSquarePlus size={18} />
                        Leave a Review
                    </button>
                </div>

                <div className={styles.trackWrapper}>
                    {testimonials.length > 0 ? (
                        <div
                            className={styles.track}
                            ref={trackRef}
                            onMouseDown={onMouseDown}
                            onMouseMove={onMouseMove}
                            onMouseUp={onMouseUp}
                            onMouseLeave={onMouseUp}
                        >
                            {testimonials.slice(-15).map((t, i) => (
                                <div key={t.id || i.toString()} className={`${styles.card} glass`}>
                                    <div className={styles.stars}>
                                        {[...Array(t.rating ?? 5)].map((_, idx) => (
                                            <Star key={idx} size={16} fill="currentColor" />
                                        ))}
                                    </div>
                                    <p className={styles.quote}>"{t.quote}"</p>
                                    {t.admin_reply && (
                                        <div className={styles.adminReply}>
                                            <span className={styles.adminReplyLabel}>Reply from PrintHub</span>
                                            <p>{t.admin_reply}</p>
                                        </div>
                                    )}
                                    <div className={styles.author}>
                                        <div className={styles.avatar}>{t.initials}</div>
                                        <div className={styles.info}>
                                            <h4>{t.name}</h4>
                                            <p>{t.role}</p>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div style={{ textAlign: 'center', padding: '40px 20px', opacity: 0.8, border: '1px dashed rgba(255,255,255,0.2)', borderRadius: '20px', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '15px' }}>
                            <p style={{ margin: 0 }}>No reviews yet. Be the first to share your experience!</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Review Modal */}
            {showModal && (
                <div className={styles.modalOverlay} onClick={() => setShowModal(false)}>
                    <div className={styles.modal} onClick={e => e.stopPropagation()}>
                        <div className={styles.modalHeader}>
                            <div>
                                <h3>Share Your Experience</h3>
                                <p>Your review will be visible to everyone.</p>
                            </div>
                            <button className={styles.closeBtn} onClick={() => setShowModal(false)}>
                                <X size={20} />
                            </button>
                        </div>

                        <form onSubmit={handleSubmit} className={styles.reviewForm}>
                            {/* Star Rating */}
                            <div className={styles.ratingRow}>
                                <label>Rating</label>
                                <div className={styles.starPicker}>
                                    {[1, 2, 3, 4, 5].map(star => (
                                        <button
                                            key={star}
                                            type="button"
                                            onClick={() => setForm(f => ({ ...f, rating: star }))}
                                            className={styles.starBtn}
                                            style={{ color: star <= form.rating ? '#39ff14' : 'rgba(255,255,255,0.2)' }}
                                        >
                                            <Star size={28} fill="currentColor" />
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div className={styles.formRow}>
                                <div className={styles.formGroup}>
                                    <label>Your Name</label>
                                    <input
                                        type="text"
                                        value={form.name}
                                        onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
                                        placeholder="e.g. Rahul S."
                                        required
                                    />
                                </div>
                                <div className={styles.formGroup}>
                                    <label>Your Role / Profession</label>
                                    <input
                                        type="text"
                                        value={form.role}
                                        onChange={e => setForm(f => ({ ...f, role: e.target.value }))}
                                        placeholder="e.g. Robotics Engineer"
                                    />
                                </div>
                            </div>

                            <div className={styles.formGroup}>
                                <label>Your Review</label>
                                <textarea
                                    value={form.quote}
                                    onChange={e => setForm(f => ({ ...f, quote: e.target.value }))}
                                    placeholder="Tell us about your experience..."
                                    rows={4}
                                    required
                                />
                            </div>

                            <button type="submit" className={styles.submitBtn} disabled={submitting}>
                                {submitting ? (
                                    <><Loader2 size={18} className={styles.spin} /> Submitting...</>
                                ) : (
                                    <><Send size={18} /> Submit Review</>
                                )}
                            </button>
                        </form>
                    </div>
                </div>
            )}
        </section>
    )
}

