export const USD_TO_INR = 83.5 // Update this rate as needed

import { analyzeFile } from '@polar3d/file-analyzer'

export interface ColorInfo {
    colors: string[] // Hex color codes
    isMultiColor: boolean
    amsCompatible: boolean // Can be printed with 4-color AMS
}

export interface FileAnalysisResult {
    fileName: string
    fileType: string
    colors: ColorInfo
    layerCount?: number
}

/**
 * Analyze STL/3MF file for colors and metadata
 * Uses @polar3d/file-analyzer
 */
export async function analyzeFileColors(file: File): Promise<FileAnalysisResult> {
    try {
        const result = await analyzeFile(file)

        const colors = result.filamentInfo?.colors || []
        const isMultiColor = result.filamentInfo?.isMultiColor || false

        return {
            fileName: file.name,
            fileType: result.fileType || 'unknown',
            colors: {
                colors: colors.map((c: any) => c.hex || c),
                isMultiColor,
                amsCompatible: colors.length > 0 && colors.length <= 4
            },
            layerCount: result.layerCount
        }
    } catch (error) {
        console.error('Error analyzing file:', error)
        // Return default single-color result
        return {
            fileName: file.name,
            fileType: 'stl',
            colors: {
                colors: ['#ffffff'],
                isMultiColor: false,
                amsCompatible: true
            }
        }
    }
}

/**
 * Extract just the colors from a file
 * Returns array of hex colors, limited to 4 for AMS
 */
export async function extractColors(file: File): Promise<string[]> {
    const analysis = await analyzeFileColors(file)
    const colors = analysis.colors.colors.slice(0, 4) // Limit to 4 for AMS

    // If no colors detected, return default white
    return colors.length > 0 ? colors : ['#ffffff']
}

import { create } from 'zustand'
import { persist } from 'zustand/middleware'
import { FilamentKey } from '@/utils/pricingEngine'

export interface Printer {
    id: string
    name: string
    type: string // e.g., 'FDM', 'SLA'
    status: 'available' | 'busy' | 'maintenance'
}

export interface MaterialTypeConfig {
    name: string
    density: number
    properties: {
        strength: number
        flexibility: number
        heatRes: number
        durability: number
    }
}

export interface Filament {
    key: FilamentKey
    pricePerGram: number // base price
    availableColors: string[]
    density: number // g/cm3
    brand: string
    type: string
    colorPricing?: Record<string, number> // color hex -> price per gram (optional override)
    properties?: {
        strength: number
        flexibility: number
        heatRes: number
        durability: number
    }
}

interface AdminState {
    filaments: Record<FilamentKey, Filament>
    printers: Printer[]
    electricityRate: number // INR per hour
    miscellaneousFee: number // INR per model
    supportMaterialPrice: number // INR per gram
    hasHydrated: boolean
    materialTypes: MaterialTypeConfig[]
    supportTypes: string[]
    setHasHydrated: (val: boolean) => void
    setMaterialTypes: (types: MaterialTypeConfig[]) => void
    addMaterialType: (config: MaterialTypeConfig) => Promise<void>
    removeMaterialType: (type: string) => Promise<void>
    setSupportTypes: (types: string[]) => void
    addSupportType: (type: string) => Promise<void>
    removeSupportType: (type: string) => Promise<void>
    updateGlobalSettings: (settings: { electricityRate?: number, miscellaneousFee?: number, supportMaterialPrice?: number }) => Promise<void>
    updateFilamentPrice: (key: FilamentKey, price: number) => Promise<void>
    updateFilamentColors: (key: FilamentKey, colors: string[]) => Promise<void>
    updateColorPricing: (key: FilamentKey, color: string, price: number) => Promise<void>
    addColorWithPricing: (key: FilamentKey, color: string, price: number) => Promise<void>
    updateColorHex: (key: FilamentKey, oldHex: string, newHex: string) => Promise<void>
    updatePrinterStatus: (id: string, status: Printer['status']) => Promise<void>
    addPrinter: (printer: Printer) => Promise<void>
    updatePrinter: (id: string, updates: Partial<Printer>) => Promise<void>
    removePrinter: (id: string) => Promise<void>
    addFilament: (filament: Filament) => Promise<void>
    updateFilament: (key: FilamentKey, updates: Partial<Filament>) => Promise<void>
    renameFilament: (oldKey: FilamentKey, newKey: FilamentKey) => Promise<void>
    removeFilament: (key: FilamentKey) => Promise<void>
    fetchSettings: () => Promise<void>
}

export const useAdminStore = create<AdminState>()(
    persist(
        (set, get) => ({
            filaments: {},
            printers: [],
            electricityRate: 15,
            miscellaneousFee: 50,
            supportMaterialPrice: 1.5,
            hasHydrated: false,
            materialTypes: [],
            supportTypes: [],
            setHasHydrated: (hasHydrated: boolean) => set({ hasHydrated }),
            setMaterialTypes: (materialTypes: MaterialTypeConfig[]) => set({ materialTypes }),
            addMaterialType: async (config: MaterialTypeConfig) => {
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const { error } = await supabase.from('material_types').insert({
                    name: config.name,
                    density: config.density,
                    properties: config.properties
                })
                if (error) {
                    console.error('Failed to insert material type:', error)
                    throw new Error(error.message || 'Database operation failed')
                }
                set((state: AdminState) => ({ materialTypes: [...state.materialTypes, config] }))
            },
            removeMaterialType: async (type: string) => {
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const { error } = await supabase.from('material_types').delete().eq('name', type)
                if (error) {
                    console.error('Failed to remove material type:', error)
                    throw new Error(error.message || 'Database operation failed')
                }
                set((state: AdminState) => ({ materialTypes: state.materialTypes.filter((t: MaterialTypeConfig) => t.name !== type) }))
            },
            setSupportTypes: (supportTypes: string[]) => set({ supportTypes }),
            addSupportType: async (type: string) => {
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const { error } = await supabase.from('support_types').insert({ name: type })
                if (error) {
                    console.error('Failed to insert support type:', error)
                    throw new Error(error.message || 'Database operation failed')
                }
                set((state: AdminState) => ({ supportTypes: [...state.supportTypes, type] }))
            },
            removeSupportType: async (type: string) => {
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const { error } = await supabase.from('support_types').delete().eq('name', type)
                if (error) {
                    console.error('Failed to remove support type:', error)
                    throw new Error(error.message || 'Database operation failed')
                }
                set((state: AdminState) => ({ supportTypes: state.supportTypes.filter((t: string) => t !== type) }))
            },

            updateGlobalSettings: async (settings: { electricityRate?: number, miscellaneousFee?: number, supportMaterialPrice?: number }) => {
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const promises = []
                if (settings.electricityRate !== undefined) promises.push(supabase.from('site_config').upsert({ key: 'electricity_rate', value: settings.electricityRate.toString() }))
                if (settings.miscellaneousFee !== undefined) promises.push(supabase.from('site_config').upsert({ key: 'miscellaneous_fee', value: settings.miscellaneousFee.toString() }))
                if (settings.supportMaterialPrice !== undefined) promises.push(supabase.from('site_config').upsert({ key: 'support_material_price', value: settings.supportMaterialPrice.toString() }))

                const results = await Promise.all(promises)
                if (results.some(r => r.error)) {
                    console.error('Failed to update some settings')
                    throw new Error('Failed to update global settings')
                }
                set((state: AdminState) => ({ ...state, ...settings }))
            },

            updateFilamentPrice: async (key: FilamentKey, price: number) => {
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const { error } = await supabase.from('materials').update({ price_per_gram: price }).eq('key', key)
                if (error) {
                    console.error('Failed to update filament price:', error)
                    throw new Error(error.message || 'Database operation failed')
                }
                set((state: AdminState) => ({
                    filaments: {
                        ...state.filaments,
                        [key]: { ...state.filaments[key], pricePerGram: price }
                    }
                }))
            },
            updateFilamentColors: async (key: FilamentKey, colors: string[]) => {
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const { error } = await supabase.from('materials').update({ available_colors: colors }).eq('key', key)
                if (error) {
                    console.error('Failed to update filament colors:', error)
                    throw new Error(error.message || 'Database operation failed')
                }
                set((state: AdminState) => ({
                    filaments: {
                        ...state.filaments,
                        [key]: { ...state.filaments[key], availableColors: colors }
                    }
                }))
            },
            updateColorPricing: async (key: FilamentKey, color: string, price: number) => {
                const current = get().filaments[key]
                if (!current) return
                const updatedPricing = { ...(current.colorPricing || {}), [color]: price }
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const { error } = await supabase.from('materials').update({ color_pricing: updatedPricing }).eq('key', key)
                if (error) {
                    console.error('Failed to update color pricing:', error)
                    throw new Error(error.message || 'Database operation failed')
                }
                set((state: AdminState) => ({
                    filaments: {
                        ...state.filaments,
                        [key]: { ...state.filaments[key], colorPricing: updatedPricing }
                    }
                }))
            },
            addColorWithPricing: async (key: FilamentKey, color: string, price: number) => {
                const filament = get().filaments[key]
                if (!filament) return
                const updatedColors = filament.availableColors.includes(color) ? filament.availableColors : [...filament.availableColors, color]
                const updatedPricing = price > 0 ? { ...(filament.colorPricing || {}), [color]: price } : filament.colorPricing
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const { error } = await supabase.from('materials').update({ available_colors: updatedColors, color_pricing: updatedPricing }).eq('key', key)
                if (error) {
                    console.error('Failed to add color with pricing:', error)
                    throw new Error(error.message || 'Database operation failed')
                }
                set((state: AdminState) => ({
                    filaments: {
                        ...state.filaments,
                        [key]: { ...state.filaments[key], availableColors: updatedColors, colorPricing: updatedPricing }
                    }
                }))
            },
            updateColorHex: async (key: FilamentKey, oldHex: string, newHex: string) => {
                const filament = get().filaments[key]
                if (!filament) return
                const availableColors = filament.availableColors.map((c: string) => c === oldHex ? newHex : c)
                const colorPricing = { ...(filament.colorPricing || {}) }
                if (colorPricing[oldHex] !== undefined) {
                    colorPricing[newHex] = colorPricing[oldHex]
                    delete colorPricing[oldHex]
                }
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const { error } = await supabase.from('materials').update({ available_colors: availableColors, color_pricing: colorPricing }).eq('key', key)
                if (error) {
                    console.error('Failed to update color hex:', error)
                    throw new Error(error.message || 'Database operation failed')
                }
                set((state: AdminState) => ({
                    filaments: {
                        ...state.filaments,
                        [key]: { ...state.filaments[key], availableColors, colorPricing }
                    }
                }))
            },
            updatePrinterStatus: async (id: string, status: Printer['status']) => {
                const { updatePrinterAdmin } = require('@/app/admin/actions')
                const { success, error } = await updatePrinterAdmin(id, { status })
                if (!success) {
                    console.error('Failed to update printer status:', error)
                    throw new Error(error || 'Database operation failed')
                }
                set((state: AdminState) => ({
                    printers: state.printers.map((p: Printer) => p.id === id ? { ...p, status } : p)
                }))
            },
            addPrinter: async (printer: Printer) => {
                const { addPrinterAdmin } = require('@/app/admin/actions')
                const { success, error } = await addPrinterAdmin(printer)
                if (!success) {
                    console.error('Failed to add printer:', error)
                    throw new Error(error || 'Database operation failed')
                }
                set((state: AdminState) => ({ printers: [...state.printers, printer] }))
            },
            updatePrinter: async (id: string, updates: Partial<Printer>) => {
                const { updatePrinterAdmin } = require('@/app/admin/actions')
                const { success, error } = await updatePrinterAdmin(id, updates)
                if (!success) {
                    console.error('Failed to update printer:', error)
                    throw new Error(error || 'Database operation failed')
                }
                set((state: AdminState) => ({
                    printers: state.printers.map((p: Printer) => p.id === id ? { ...p, ...updates } : p)
                }))
            },
            removePrinter: async (id: string) => {
                const { deletePrinterAdmin } = require('@/app/admin/actions')
                const { success, error } = await deletePrinterAdmin(id)
                if (!success) {
                    console.error('Failed to remove printer:', error)
                    throw new Error(error || 'Database operation failed')
                }
                set((state: AdminState) => ({ printers: state.printers.filter((p: Printer) => p.id !== id) }))
            },
            addFilament: async (filament: Filament) => {
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const { error } = await supabase.from('materials').insert({
                    key: filament.key,
                    brand: filament.brand,
                    type: filament.type,
                    price_per_gram: filament.pricePerGram,
                    density: filament.density,
                    available_colors: filament.availableColors,
                    color_pricing: filament.colorPricing,
                    properties: filament.properties
                })
                if (error) {
                    console.error('Failed to add filament:', error)
                    throw new Error(error.message || 'Database operation failed')
                }
                set((state: AdminState) => ({ filaments: { ...state.filaments, [filament.key]: filament } }))
            },
            updateFilament: async (key: FilamentKey, updates: Partial<Filament>) => {
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const dbUpdates: any = {}
                if (updates.pricePerGram !== undefined) dbUpdates.price_per_gram = updates.pricePerGram
                if (updates.density !== undefined) dbUpdates.density = updates.density
                if (updates.brand !== undefined) dbUpdates.brand = updates.brand
                if (updates.type !== undefined) dbUpdates.type = updates.type
                if (updates.properties !== undefined) dbUpdates.properties = updates.properties

                if (Object.keys(dbUpdates).length > 0) {
                    const { error } = await supabase.from('materials').update(dbUpdates).eq('key', key)
                    if (error) {
                        console.error('Failed to update filament:', error)
                        throw new Error(error.message || 'Database operation failed')
                    }
                }
                set((state: AdminState) => ({
                    filaments: {
                        ...state.filaments,
                        [key]: { ...state.filaments[key], ...updates }
                    }
                }))
            },
            renameFilament: async (oldKey: FilamentKey, newKey: FilamentKey) => {
                const filament = get().filaments[oldKey]
                if (!filament) return
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const { error } = await supabase.from('materials').update({ key: newKey }).eq('key', oldKey)
                if (error) {
                    console.error('Failed to rename filament:', error)
                    throw new Error(error.message || 'Database operation failed')
                }
                set((state: AdminState) => {
                    const filaments = { ...state.filaments }
                    const data = { ...filaments[oldKey], key: newKey }
                    filaments[newKey] = data
                    delete filaments[oldKey]
                    return { filaments }
                })
            },
            removeFilament: async (key: FilamentKey) => {
                const { createClient } = require('@/utils/supabase/client')
                const supabase = createClient()
                const { error } = await supabase.from('materials').delete().eq('key', key)
                if (error) {
                    console.error('Failed to remove filament:', error)
                    throw new Error(error.message || 'Database operation failed')
                }
                set((state: AdminState) => {
                    const filaments = { ...state.filaments }
                    delete filaments[key]
                    return { filaments }
                })
            },
            fetchSettings: async () => {
                try {
                    const { createClient } = await import('@/utils/supabase/client')
                    const supabase = createClient()
                    const [mRes, pRes, mtRes, stRes, cRes] = await Promise.all([
                        supabase.from('materials').select('*'),
                        supabase.from('printers').select('*'),
                        supabase.from('material_types').select('*'),
                        supabase.from('support_types').select('name'),
                        supabase.from('site_config').select('key, value')
                    ])

                    const filamentMap: Record<FilamentKey, Filament> = {}
                    if (mRes.data) {
                        mRes.data.forEach((m: any) => {
                            // Find the corresponding material type to get density and properties
                            const matType = mtRes.data?.find((t: any) => t.name === m.type)
                            filamentMap[m.key as FilamentKey] = {
                                key: m.key as FilamentKey,
                                brand: m.brand,
                                type: m.type,
                                pricePerGram: m.price_per_gram != null ? (Number(m.price_per_gram) || 0) : 0,
                                availableColors: Array.isArray(m.available_colors) ? m.available_colors : ['#ffffff'],
                                colorPricing: typeof m.color_pricing === 'object' ? m.color_pricing : {},
                                // Provide sensible fallbacks if matType isn't found
                                density: matType && matType.density != null ? (Number(matType.density) || 1.240) : 1.240,
                                properties: matType && typeof matType.properties === 'object'
                                    ? matType.properties
                                    : { strength: 5, flexibility: 5, heatRes: 5, durability: 5 }
                            }
                        })
                    }

                    const updates: any = {
                        filaments: filamentMap,
                        printers: (pRes.data || []).map((p: any) => ({
                            id: p.id,
                            name: p.name,
                            type: p.type,
                            status: p.status
                        })),
                        materialTypes: (mtRes.data && mtRes.data.length > 0) ? mtRes.data.map((t: any) => ({
                            name: t.name,
                            density: t.density != null ? (Number(t.density) || 1.240) : 1.240,
                            properties: typeof t.properties === 'object' ? t.properties : { strength: 5, flexibility: 5, heatRes: 5, durability: 5 }
                        })) : [],
                        supportTypes: (stRes.data && stRes.data.length > 0) ? stRes.data.map((t: any) => t.name) : ['None', 'Standard', 'Tree'],
                        hasHydrated: true
                    }

                    if (cRes.data) {
                        cRes.data.forEach((c: any) => {
                            if (c.key === 'electricity_rate') updates.electricityRate = c.value != null ? (Number(c.value) || 0) : 0
                            if (c.key === 'miscellaneous_fee') updates.miscellaneousFee = c.value != null ? (Number(c.value) || 0) : 0
                            if (c.key === 'support_material_price') updates.supportMaterialPrice = c.value != null ? (Number(c.value) || 0) : 0
                        })
                    }
                    set(updates)
                } catch (err) {
                    console.error('CRITICAL: Fetch failed', err)
                    set({ hasHydrated: true })
                }
            }
        }),
        {
            name: 'admin-storage',
            onRehydrateStorage: () => (state) => {
                state?.setHasHydrated(true)
            },
            partialize: (state: any) => {
                const { materialTypes, supportTypes, filaments, printers, hasHydrated, ...rest } = state
                return rest
            }
        }
    )
)

import { create } from 'zustand'
import { persist, createJSONStorage } from 'zustand/middleware'
import { createClient } from '@/utils/supabase/client'
import { uploadModelToStorage } from '@/utils/uploadModel'
import { getFileFromDB, deleteFileFromDB } from '@/utils/db'

function generateUUID() {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
        return crypto.randomUUID()
    }
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
        var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8)
        return v.toString(16)
    })
}

export interface CartItem {
    id: string
    fileName: string
    fileUrl: string
    material: string
    color: string
    quantity: number
    price: number
    volume: number
    weight: number
    dimensions: { x: number; y: number; z: number }
    layerHeight: number
    infill: number
    supportType: string
    supportMaterial?: string
    brim?: boolean
    brand?: string
    infillPattern?: string
    amsColors?: string[]
    amsBrands?: string[]
    file?: File
}

interface CartState {
    items: CartItem[]
    addItem: (item: CartItem) => Promise<void>
    removeItem: (id: string) => Promise<void>
    updateQuantity: (id: string, quantity: number) => Promise<void>
    updateItem: (id: string, updates: Partial<CartItem>) => Promise<void>
    clearCart: () => Promise<void>
    getTotal: () => number
    lastInteraction: number
    syncToSupabase: (userId?: string) => Promise<void>
    loadFromSupabase: (userId?: string) => Promise<void>
    clearCartFromSupabase: () => Promise<void>
    purge: () => void
    updateInteraction: () => void
}

export const useCartStore = create<CartState>()(
    persist(
        (set, get) => ({
            items: [],
            lastInteraction: Date.now(),

            updateInteraction: () => set({ lastInteraction: Date.now() }),

            addItem: async (item) => {
                get().updateInteraction()
                set((state) => ({ items: [...state.items, item] }))
                await get().syncToSupabase()
            },

            removeItem: async (id) => {
                get().updateInteraction()
                set((state) => ({ items: state.items.filter((i) => i.id !== id) }))
                await get().syncToSupabase()
            },

            updateQuantity: async (id, quantity) => {
                get().updateInteraction()
                set((state) => ({
                    items: state.items.map((i) => (i.id === id ? { ...i, quantity } : i)),
                }))
                await get().syncToSupabase()
            },

            updateItem: async (id, updates) => {
                get().updateInteraction()
                set((state) => ({
                    items: state.items.map((i) => (i.id === id ? { ...i, ...updates } : i)),
                }))
                await get().syncToSupabase()
            },

            clearCart: async () => {
                get().updateInteraction()
                set({ items: [] })
                await get().syncToSupabase()
            },

            getTotal: () => {
                const { items } = get()
                return items.reduce((total, item) => total + item.price, 0)
            },

            syncToSupabase: async (userId?: string) => {
                try {
                    const supabase = createClient()
                    let targetUserId = userId

                    if (!targetUserId) {
                        const { data: { user } } = await supabase.auth.getUser()
                        targetUserId = user?.id
                    }

                    if (!targetUserId) {
                        return // Not logged in, skip sync
                    }

                    let { items } = get()

                    // Ensure all existing items have proper UUIDs, otherwise Supabase insert will fail
                    let hasMigrations = false
                    const uuidPattern = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i

                    const migratedItems = items.map(item => {
                        if (!uuidPattern.test(item.id)) {
                            hasMigrations = true
                            return { ...item, id: generateUUID() }
                        }
                        return item
                    })

                    if (hasMigrations) {
                        set({ items: migratedItems })
                        items = migratedItems
                    }

                    let hasUploads = false
                    const updatedItems = await Promise.all(items.map(async (item) => {
                        if (item.fileUrl.startsWith('blob:')) {
                            const fileToUpload = item.file || await getFileFromDB(item.id);

                            if (fileToUpload) {
                                try {
                                    const res = await uploadModelToStorage(fileToUpload)
                                    if (res !== 'unauthenticated') {
                                        hasUploads = true
                                        // Once uploaded to secure storage, we can remove the local IndexedDB copy
                                        await deleteFileFromDB(item.id);
                                        return { ...item, fileUrl: res, file: undefined }
                                    }
                                } catch (e) {
                                    // Ignore upload sync failures
                                }
                            }
                        }
                        return item
                    }))

                    if (hasUploads) {
                        set({ items: updatedItems })
                        items = updatedItems
                    }

                    // Delete all existing cart items for this user
                    const { error: deleteError } = await supabase
                        .from('cart_items')
                        .delete()
                        .eq('user_id', targetUserId)

                    if (deleteError) {
                        throw deleteError
                    }

                    // Insert current cart items
                    if (items.length > 0) {
                        const cartItemsToInsert = items.map(item => ({
                            id: item.id, // CRITICAL: maintain same ID as in the app!
                            user_id: targetUserId,
                            file_name: item.fileName,
                            file_url: item.fileUrl,
                            material: item.material,
                            color: item.color,
                            quantity: item.quantity,
                            price: item.price,
                            volume: item.volume,
                            weight: item.weight,
                            dimensions: item.dimensions,
                            layer_height: item.layerHeight,
                            infill: item.infill,
                            support_type: item.supportType,
                            support_material: item.supportMaterial || null,
                            brim: item.brim || false,
                            brand: item.brand || null,
                            infill_pattern: item.infillPattern || 'grid',
                            ams_colors: item.amsColors || [],
                            ams_brands: item.amsBrands || []
                        }))

                        const { error: insertError } = await supabase
                            .from('cart_items')
                            .insert(cartItemsToInsert)

                        if (insertError) throw insertError
                    }
                } catch (error: any) {
                    // Sync failed silently
                }



            },

            loadFromSupabase: async (userId?: string) => {
                try {
                    const supabase = createClient()
                    let targetUserId = userId

                    if (!targetUserId) {
                        const { data: { user } } = await supabase.auth.getUser()
                        targetUserId = user?.id
                    }

                    if (!targetUserId) return

                    const { data: cartItems, error } = await supabase
                        .from('cart_items')
                        .select('*')
                        .eq('user_id', targetUserId)

                    if (error) throw error

                    const localItems = get().items

                    if (cartItems && cartItems.length > 0) {
                        const dbItems: CartItem[] = cartItems.map(item => ({
                            id: item.id,
                            fileName: item.file_name,
                            fileUrl: item.file_url,
                            material: item.material,
                            color: item.color,
                            quantity: item.quantity,
                            price: parseFloat(item.price),
                            volume: parseFloat(item.volume),
                            weight: parseFloat(item.weight),
                            dimensions: item.dimensions,
                            layerHeight: parseFloat(item.layer_height) || 0.2,
                            infill: item.infill || 20,
                            supportType: item.support_type || 'none',
                            supportMaterial: item.support_material || undefined,
                            brim: typeof item.brim === 'boolean' ? item.brim : false,
                            brand: item.brand || '',
                            infillPattern: item.infill_pattern || 'grid',
                            amsColors: item.ams_colors || [],
                            amsBrands: item.ams_brands || [],
                        }))

                        let mergedItems = [...dbItems]
                        let hasNewLocal = false

                        for (const local of localItems) {
                            const isDuplicate = dbItems.some(db =>
                                (db.fileUrl === local.fileUrl && db.price === local.price) ||
                                db.id === local.id
                            )
                            if (!isDuplicate) {
                                mergedItems.push(local)
                                hasNewLocal = true
                            }
                        }


                        if (hasNewLocal) {
                            set({ items: mergedItems })
                            await get().syncToSupabase(targetUserId)
                        } else {
                            set({ items: dbItems })
                        }
                    } else if (localItems.length > 0) {
                        // DB is empty, but local has anonymous items -> sync up to newly logged in account!
                        await get().syncToSupabase(targetUserId)
                    } else {
                        set({ items: [] })
                    }
                } catch (error) {
                    // Fallback
                }
            },

            clearCartFromSupabase: async () => {
                try {
                    const supabase = createClient()
                    const { data: { user } } = await supabase.auth.getUser()

                    if (!user) return

                    // Delete all cart items for this user
                    await supabase
                        .from('cart_items')
                        .delete()
                        .eq('user_id', user.id)
                } catch (error) {
                    // Fail silently
                }
            },

            purge: () => {
                set({ items: [], lastInteraction: Date.now() });
                // The middleware will handle clearing the storage automatically 
                // because items is now empty. To be safe, we can also manually remove:
                localStorage.removeItem('cart-storage');
                sessionStorage.removeItem('cart-storage');
            },
        }),
        {
            name: 'cart-storage',
            onRehydrateStorage: () => (state) => {
                if (state) {
                    const GUEST_EXPIRY_MS = 30 * 60 * 1000; // 30 minutes
                    const now = Date.now();

                    // Check if current data belongs to a guest (no auth user in other store)
                    const authData = localStorage.getItem('auth-storage');
                    const user = authData ? JSON.parse(authData).state?.user : null;

                    if (!user && state.items.length > 0) {
                        const timeSinceInteraction = now - state.lastInteraction;
                        if (timeSinceInteraction > GUEST_EXPIRY_MS) {
                            state.purge();
                        }
                    }
                }
            },
            // Universal localStorage ensures survival across OAuth redirects.
            // Cleanup of guest data is handled by purge() on logout.
        }
    )
)

import { create } from 'zustand'
import { persist, createJSONStorage } from 'zustand/middleware'

export interface QueueItem {
    id: string
    file: File
    fileName: string
    fileUrl: string
    size: number
    uploadProgress: number
    status: 'uploading' | 'pending' | 'configured'
    configuredId?: string // Link to cart item if configured
}

interface QueueState {
    items: QueueItem[]
    addToQueue: (item: QueueItem) => void
    removeFromQueue: (id: string) => void
    updateQueueItem: (id: string, updates: Partial<QueueItem>) => void
    clearQueue: () => void
    getPendingCount: () => number
    purge: () => void
    lastInteraction: number
    updateInteraction: () => void
}

export const useQueueStore = create<QueueState>()(
    persist(
        (set, get) => ({
            items: [],
            lastInteraction: Date.now(),
            updateInteraction: () => set({ lastInteraction: Date.now() }),

            addToQueue: (item) => {
                get().updateInteraction()
                set((state) => ({ items: [...state.items, item] }))
            },
            removeFromQueue: (id) => {
                get().updateInteraction()
                set((state) => ({ items: state.items.filter((i) => i.id !== id) }))
            },
            updateQueueItem: (id, updates) => {
                get().updateInteraction()
                set((state) => ({
                    items: state.items.map((i) => (i.id === id ? { ...i, ...updates } : i)),
                }))
            },
            clearQueue: () => set({ items: [] }),
            getPendingCount: () => {
                const { items } = get()
                return items.filter(i => i.status === 'pending').length
            },
            purge: () => {
                set({ items: [], lastInteraction: Date.now() });
                localStorage.removeItem('queue-storage');
                sessionStorage.removeItem('queue-storage');
            }
        }),
        {
            name: 'queue-storage',
            storage: createJSONStorage(() => sessionStorage),
            onRehydrateStorage: () => (state) => {
                if (state) {
                    const GUEST_EXPIRY_MS = 30 * 60 * 1000;
                    const now = Date.now();
                    const authData = localStorage.getItem('auth-storage');
                    const user = authData ? JSON.parse(authData).state?.user : null;

                    if (!user && state.items.length > 0) {
                        const timeSinceInteraction = now - state.lastInteraction;
                        if (timeSinceInteraction > GUEST_EXPIRY_MS) {
                            state.purge();
                        }
                    }
                }
            },
            // File objects and Blob URLs don't survive refresh well in localStorage/sessionStorage
            partialize: (state) => ({
                items: state.items.map(({ file, ...rest }) => ({ ...rest }))
            }) as any,
        }
    )
)

/**
 * ========================================
 * PRICING CONFIGURATION (ADMIN EDITABLE)
 * ========================================
 * 
 * To update filament prices:
 * 1. Modify them in the Admin Panel
 * 2. pricePerGram = Price per gram in INR
 * 3. density = Material density in g/cm³
 * 
 * Current Currency: INR (₹)
 */

export type FilamentKey = string

// Infill Patterns affecting print time/density
export const INFILL_PATTERNS = {
    grid: { name: 'Grid', densityMultiplier: 1.0, timeMultiplier: 1.0 },
    gyroid: { name: 'Gyroid', densityMultiplier: 1.05, timeMultiplier: 1.15 },
    cubic: { name: 'Cubic', densityMultiplier: 1.02, timeMultiplier: 1.05 },
    lines: { name: 'Lines', densityMultiplier: 0.95, timeMultiplier: 0.9 },
}

// Breakdown of accurate pricing
export interface PriceBreakdown {
    mainMaterialCost: number
    supportMaterialCost: number
    materialCost: number
    printCost: number
    setupCost: number // setup + misc (one-time)
    unitCost: number // material + print (per item)
    totalCost: number
    mainWeightGrams: number
    supportWeightGrams: number
    printTimeMinutes: number
}

// Params needed for calculation
export interface PricingParams {
    volumeCm3: number
    material: FilamentKey
    quantity?: number
    layerHeight?: number
    infill?: number
    infillPattern?: string
    brim?: boolean

    // Configurable Rates
    pricePerGram?: number
    electricityRate?: number // INR per hour
    miscFee?: number // One-time fee

    // Support
    supportVolumeCm3?: number
    supportMaterial?: FilamentKey
    supportPricePerGram?: number

    // Dynamic Overrides (from Admin Store)
    mainDensity?: number
    supportDensity?: number
}

export const calculateDetailedPrice = ({
    volumeCm3,
    material,
    quantity = 1,
    layerHeight = 0.2,
    infill = 20,
    infillPattern,
    brim,
    pricePerGram,
    electricityRate = 0,
    miscFee = 0,
    supportVolumeCm3 = 0,
    supportMaterial,
    supportPricePerGram,
    mainDensity,
    supportDensity
}: PricingParams): PriceBreakdown => {
    // 0. Parameter adjusting (Infill Density, Pattern, Brim)
    // Base heuristic: solid object = 100% infill. A 20% infill object isn't actually 20% of the volume, walls take up material.
    // Let's assume bounding volume is reduced. The provided volumeCm3 is usually bounding. 
    // We'll scale volume based on infill deviation from 20% (assuming 20% is baseline 1.0)
    let volumeMultiplier = 1.0 + ((infill - 20) / 100) * 0.8 // Scaling material logic

    // Apply pattern modifiers
    const pattern = INFILL_PATTERNS[infillPattern as keyof typeof INFILL_PATTERNS] || INFILL_PATTERNS.grid
    volumeMultiplier *= pattern.densityMultiplier

    const adjustedMainVolumeCm3 = volumeCm3 * volumeMultiplier

    // 1. Calculate Weights
    // We expect density to be passed in from the DB, otherwise use PLA default
    const actualMainDensity = mainDensity || 1.24
    const actualSupportDensity = supportDensity || actualMainDensity

    // Calculate Brim (1% extra of base volume using main material density)
    const brimGrams = brim ? (volumeCm3 * 0.01) * actualMainDensity : 0

    const mainWeightGrams = adjustedMainVolumeCm3 * actualMainDensity
    const supportWeightGrams = (supportVolumeCm3 * actualSupportDensity) + brimGrams

    // 2. Determine Prices
    const actualMainPricePerGram = pricePerGram || 0
    const actualSupportPricePerGram = supportPricePerGram || 0

    // 3. Material Cost (Per Unit)
    const mainMaterialCost = mainWeightGrams * actualMainPricePerGram
    const supportModelCost = (supportVolumeCm3 * actualSupportDensity) * actualSupportPricePerGram
    const brimCost = brimGrams * actualMainPricePerGram
    const supportMaterialCost = supportModelCost + brimCost
    const totalMaterialCostPerUnit = mainMaterialCost + supportMaterialCost

    // 4. Print Cost (Per Unit) - Electricity
    // Total volume for print time calculation
    const totalVolume = adjustedMainVolumeCm3 + supportVolumeCm3

    // Time scaling matching pattern
    const printTimeMinutes = calculatePrintTime(totalVolume, layerHeight, infill) * pattern.timeMultiplier
    // Add realistic time penalty for brim (approx 1.5 mins)
    const adjustedPrintTimeMinutes = brim ? printTimeMinutes + 1.5 : printTimeMinutes

    const printTimeHours = adjustedPrintTimeMinutes / 60
    const printCostPerUnit = printTimeHours * (electricityRate || 0)

    // 5. Setup Cost (One Time per line item) -> Now requested as Per Item setup
    // Based purely on Global Misc Fee
    const setupCostPerUnit = miscFee || 0

    // Totals
    const unitCost = totalMaterialCostPerUnit + printCostPerUnit + setupCostPerUnit
    const totalCost = unitCost * (quantity || 1)

    return {
        mainMaterialCost: Math.ceil(mainMaterialCost),
        supportMaterialCost: Math.ceil(supportMaterialCost),
        materialCost: Math.ceil(totalMaterialCostPerUnit),
        printCost: Math.ceil(printCostPerUnit),
        setupCost: Math.ceil(setupCostPerUnit),
        unitCost: Math.ceil(unitCost),
        totalCost: Math.ceil(totalCost),
        mainWeightGrams: Number(mainWeightGrams.toFixed(2)),
        supportWeightGrams: Number(supportWeightGrams.toFixed(2)),
        printTimeMinutes: Math.round(adjustedPrintTimeMinutes)
    }
}


export const calculatePrintTime = (
    volumeCm3: number,
    layerHeight: number = 0.2,
    infill: number = 20
) => {
    // Basic heuristic: 1cm3 at 0.2mm takes ~15 mins
    // Adjust by layer height (thinner = slower)
    // Adjust by infill (more = slower)
    const baseMinutesPerCm3 = 15
    const layerFactor = 0.2 / layerHeight
    const infillFactor = (infill / 20) * 0.5 + 0.5

    const minutes = volumeCm3 * baseMinutesPerCm3 * layerFactor * infillFactor
    return Math.round(minutes)
}

export const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-IN', {
        style: 'currency',
        currency: 'INR',
        maximumFractionDigits: 0,
        minimumFractionDigits: 0
    }).format(Math.ceil(amount))
}

export const calculateWeight = (volumeCm3: number, density: number = 1.24): number => {
    return Math.round(volumeCm3 * density * 100) / 100
}

import { createClient } from '@/utils/supabase/client'

export const uploadModelToStorage = async (file: File) => {
    const supabase = createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) {
        return 'unauthenticated'
    }

    const timestamp = Date.now()
    const randomString = Math.random().toString(36).substring(7)
    // Clean filename
    const cleanName = file.name.replace(/[^a-zA-Z0-9.-]/g, '_')
    // Organize by user ID for security segregation
    const filePath = `${user.id}/${timestamp}_${randomString}_${cleanName}`

    const { data, error } = await supabase
        .storage
        .from('prints') // Switched to specific user bucket
        .upload(filePath, file, {
            cacheControl: '3600',
            upsert: false
        })

    if (error) throw error

    // We don't use public URLs for models anymore for 200% security.
    // We return the path, and the application will fetch signed URLs or use the path with the user session.
    // However, for immediate display in the current app architecture, we'll return the path.
    return filePath
}
